/* ============ Global error surfacing (no more silent failures) ============ */
(function () {
  function frLogErr(kind, detail) { try { console.warn("[fairway:" + kind + "]", detail); } catch (e) {} 
    try { window.__frErrors = window.__frErrors || []; window.__frErrors.push({ kind: kind, detail: String(detail), t: Date.now() }); if (window.__frErrors.length > 50) window.__frErrors.shift(); } catch (e) {}
  }
  try { window.__frErrors = window.__frErrors || []; } catch (e) {}  // eager so it's always inspectable
  window.addEventListener("error", function (e) { frLogErr("error", (e && e.message) + " @ " + (e && e.filename) + ":" + (e && e.lineno)); });
  window.addEventListener("unhandledrejection", function (e) { var r = e && e.reason; frLogErr("rejection", (r && r.message) || r); });
})();


