const SUPPORTED_LANGS = ['en', 'no', 'sv', 'da', 'de', 'es', 'fr'];
let currentLang = 'en'; /* forced English until multi-language is ready */

function t(key, params) {
  let str = TRANSLATIONS[key]?.[currentLang] ?? TRANSLATIONS[key]?.en ?? key;
  if (params) {
    Object.entries(params).forEach(([k, v]) => { str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), v); });
  }
  return str;
}

function applyTranslations() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    const txt = t(key);
    if (txt.includes('<')) el.innerHTML = txt;
    else el.textContent = txt;
  });
  document.documentElement.lang = currentLang;
}

function setLanguage(lang) {
  if (!SUPPORTED_LANGS.includes(lang)) lang = 'en';
  currentLang = lang;
  localStorage.setItem('fairway_lang', lang);
  // Sync both pickers
  const hp = document.getElementById('lang-picker');
  const sp = document.getElementById('s-lang-picker');
  if (hp) hp.value = lang;
  if (sp) sp.value = lang;
  applyTranslations();
  // Re-render visible tab content so JS-generated strings update
  const activeTab = document.querySelector('#tabs button.active')?.dataset.tab;
  if (activeTab) activateTab(activeTab);
  showToast(lang === 'en' ? "Language set to English" : lang === 'no' ? "Språk satt til norsk" : "Language: " + lang.toUpperCase());
}

