/* ---------- State ---------- */
function defaultProfile(name = "Profile") {
  return {
    id: uid(),
    name,
    avatar: "⛳",
    homeClub: "",
    startedYear: null,
    targetHcp: null,
    bio: "",
    settings: { manualHcp: null, displayName: name },
    friends: [],
    rounds: [],
    rivalries: [],
    achievementsSeen: [],
    createdAt: new Date().toISOString(),
  };
}

let state = {
  version: STATE_VERSION,
  activeProfileId: null,
  profiles: {},
  courses: [],
  globalSettings: { apiKey: "", apiAuth: "Key", apiBase: "https://api.golfcourseapi.com" },
};

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    const oldRaw = localStorage.getItem('golfDashboard_v1');
    if (raw) {
      const s = JSON.parse(raw);
      state = { ...state, ...s };
    } else if (oldRaw) {
      // Migrate v1 → v2
      const old = JSON.parse(oldRaw);
      const p = defaultProfile(old.settings?.name || "Profile");
      p.friends = old.friends || [];
      p.rounds = old.rounds || [];
      p.settings.manualHcp = old.settings?.manualHcp || null;
      state.profiles[p.id] = p;
      state.activeProfileId = p.id;
      state.courses = old.courses || [];
      state.globalSettings.apiKey = old.settings?.apiKey || "";
      state.globalSettings.apiAuth = old.settings?.apiAuth || "Key";
      state.globalSettings.apiBase = old.settings?.apiBase || "https://api.golfcourseapi.com";
      saveState();
    }
    // First-time setup: create default profile
    if (!state.activeProfileId || Object.keys(state.profiles).length === 0) {
      const p = defaultProfile();
      state.profiles[p.id] = p;
      state.activeProfileId = p.id;
    }
    // Seed courses on first run
    if (!state.courses || state.courses.length === 0) {
      state.courses = SEED_COURSES.map((c, i) => ({ id: `c${Date.now()}_${i}`, ...c }));
    } else {
      // Merge in any new seed courses the user doesn't have yet (by name match)
      const existingNames = new Set(state.courses.map(c => c.name.toLowerCase()));
      SEED_COURSES.forEach((c, i) => {
        if (!existingNames.has(c.name.toLowerCase())) {
          state.courses.push({ id: `c${Date.now()}_${i}_new`, ...c });
        }
      });
    }
    // One-time cleanup: if cloud courses got dumped here previously, trim them out.
    // Keep only seed courses + user-contributed + courses referenced by rounds.
    const seedNames = new Set(SEED_COURSES.map(c => c.name.toLowerCase()));
    const usedIds = new Set();
    Object.values(state.profiles || {}).forEach(p => {
      (p.rounds || []).forEach(r => { if (r.courseId) usedIds.add(r.courseId); });
    });
    const before = state.courses.length;
    state.courses = state.courses.filter(c => {
      const isSeed = seedNames.has((c.name || "").toLowerCase());
      const isUsed = usedIds.has(c.id);
      const isFromCloud = c._fromCloud || (c.id && String(c.id).startsWith('gca_'));
      return isSeed || isUsed || (!isFromCloud);
    });
    if (state.courses.length < before) {
      console.log(`Trimmed ${before - state.courses.length} cloud courses from local storage`);
    }
    // Ensure all courses have holesData (auto-generate if missing)
    state.courses.forEach(c => {
      if (!c.holesData || c.holesData.length !== c.holes) {
        c.holesData = generateDefaultHolesData(c.holes, c.par);
      }
    });
    // Migrate Norwegian country names → English
    const countryMap = { 'Norge': 'Norway', 'Sverige': 'Sweden', 'Danmark': 'Denmark', 'Spania': 'Spain', 'Skottland': 'Scotland', 'Tyskland': 'Germany', 'Storbritannia': 'United Kingdom' };
    state.courses.forEach(c => {
      if (c.country && countryMap[c.country]) c.country = countryMap[c.country];
    });
    saveState();
  } catch (e) { console.error("Load failed", e); }
}

function saveState() {
  // Strip profile aliases before saving to avoid duplicating data
  const { rounds, friends, settings, rivalries, ...toSave } = state;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(toSave));
}

/* Generate sensible default per-hole data for a standard layout.
   Par 72 / 18 holes: 4 par-3, 4 par-5, 10 par-4. */
function generateDefaultHolesData(holes, par) {
  holes = holes || 18;
  par = par || 72;
  const data = Array.from({length: holes}, () => ({ par: 4, si: 1, distance: null, name: "", notes: "" }));
  if (holes === 18) {
    // Classic par 72 layout - adjust if par differs
    const par3Positions = [3, 7, 11, 16];  // 0-indexed: holes 4, 8, 12, 17
    const par5Positions = [1, 6, 12, 17];  // holes 2, 7, 13, 18
    if (par === 72) {
      par3Positions.forEach(i => data[i].par = 3);
      par5Positions.forEach(i => data[i].par = 5);
    } else if (par === 71) {
      par3Positions.forEach(i => data[i].par = 3);
      par5Positions.slice(0, 3).forEach(i => data[i].par = 5);
    } else if (par === 73) {
      [3, 7, 11].forEach(i => data[i].par = 3);
      [1, 6, 12, 14, 17].forEach(i => data[i].par = 5);
    } else if (par === 70) {
      par3Positions.forEach(i => data[i].par = 3);
      [6, 17].forEach(i => data[i].par = 5);
    } else if (par === 68) {
      [3, 6, 9, 11, 14, 16].forEach(i => data[i].par = 3);
      [1, 17].forEach(i => data[i].par = 5);
    }
    // Standard SI distribution alternates between front and back 9
    const siOrder = [7, 13, 1, 11, 5, 15, 3, 17, 9, 8, 14, 2, 12, 6, 16, 4, 18, 10];
    data.forEach((h, i) => h.si = siOrder[i] || (i+1));
  } else {
    // 9-hole or other: just par 4 with SI 1-N
    data.forEach((h, i) => h.si = i+1);
  }
  // Verify par matches
  const computedPar = data.reduce((s, h) => s + h.par, 0);
  if (computedPar !== par && holes === 18) {
    const diff = par - computedPar;
    // Adjust one par-4 to par-5 (or vice versa) to match
    for (let i = 0; i < data.length && data.reduce((s,h)=>s+h.par,0) !== par; i++) {
      if (diff > 0 && data[i].par === 4) data[i].par = 5;
      else if (diff < 0 && data[i].par === 5) data[i].par = 4;
    }
  }
  return data;
}

