/* ---------- WHS calculations ---------- */
function calcDifferential(score, cr, slope) {
  if (!score || !cr || !slope) return null;
  return (113 / slope) * (score - cr);
}

function calcHcpIndex(rounds, courseMap) {
  // Use only valid rounds (with score & rating)
  const diffs = rounds
    .filter(r => r.differential != null && !isNaN(r.differential))
    .sort((a,b) => new Date(b.date) - new Date(a.date))
    .slice(0, 20)
    .map(r => r.differential);

  if (diffs.length === 0) return null;

  // WHS table for handicap calculation
  const sorted = [...diffs].sort((a,b) => a-b);
  const n = sorted.length;
  let best, adjustment = 0;
  if (n === 1) { best = sorted.slice(0,1); adjustment = -2; }
  else if (n === 2) { best = sorted.slice(0,1); adjustment = -2; }
  else if (n === 3) { best = sorted.slice(0,1); adjustment = -2; }
  else if (n === 4) { best = sorted.slice(0,1); adjustment = -1; }
  else if (n === 5) { best = sorted.slice(0,1); adjustment = 0; }
  else if (n === 6) { best = sorted.slice(0,2); adjustment = -1; }
  else if (n <= 8) { best = sorted.slice(0,2); adjustment = 0; }
  else if (n <= 11) { best = sorted.slice(0,3); adjustment = 0; }
  else if (n <= 14) { best = sorted.slice(0,4); adjustment = 0; }
  else if (n <= 16) { best = sorted.slice(0,5); adjustment = 0; }
  else if (n <= 18) { best = sorted.slice(0,6); adjustment = 0; }
  else if (n === 19) { best = sorted.slice(0,7); adjustment = 0; }
  else { best = sorted.slice(0,8); adjustment = 0; }

  const avg = best.reduce((s,x)=>s+x,0) / best.length;
  return Math.round((avg + adjustment) * 10) / 10;
}

function calcCourseHandicap(hcpIndex, slope, cr, par) {
  if (hcpIndex == null) return null;
  return Math.round(hcpIndex * (slope / 113) + (cr - par));
}

function stablefordPoints(score, par, strokesReceived=0) {
  const net = score - strokesReceived;
  const diff = net - par;
  return Math.max(0, 2 - diff);
}

function calcStableford(holes, courseHandicap=0, holeHandicaps=null) {
  let total = 0;
  for (let i=0; i<holes.length; i++) {
    const h = holes[i];
    if (!h.score) continue;
    const hcpRank = holeHandicaps ? holeHandicaps[i] : (i+1);
    let strokes = 0;
    if (courseHandicap > 0) {
      strokes = Math.floor(courseHandicap / 18);
      if (hcpRank <= (courseHandicap % 18)) strokes += 1;
    }
    total += stablefordPoints(h.score, h.par || 4, strokes);
  }
  return total;
}

function netDoubleBogeyAdjust(holes, courseHandicap=0, holeHandicaps=null) {
  let total = 0;
  for (let i=0; i<holes.length; i++) {
    const h = holes[i];
    if (!h.score) continue;
    const hcpRank = holeHandicaps ? holeHandicaps[i] : (i+1);
    let strokes = 0;
    if (courseHandicap > 0) {
      strokes = Math.floor(courseHandicap / 18);
      if (hcpRank <= (courseHandicap % 18)) strokes += 1;
    }
    const maxScore = (h.par || 4) + 2 + strokes;
    total += Math.min(h.score, maxScore);
  }
  return total;
}

/* ---------- Round building ---------- */
function getCourse(id) { return state.courses.find(c => c.id === id); }
function getTee(course, teeName) { return course?.tees.find(t => t.name === teeName); }

function buildRoundComputed(round) {
  const c = getCourse(round.courseId);
  const tee = c ? getTee(c, round.teeName) : null;
  if (!c || !tee) return { ...round, differential: null };
  // Raw gross + my per-hole scores (handles both stroke 'hbh' and match 'winner' shapes)
  let score = round.total;
  let myHoles = null;
  if (round.holes && round.holes.length) {
    myHoles = round.holes.map((h, i) => {
      const sc = (h && h.score != null) ? h.score : (h && h.scores ? h.scores['__me__'] : null);
      const hd = (c.holesData && c.holesData[i]) || {};
      return { score: sc, par: (h && h.par != null) ? h.par : (hd.par || 4), si: (hd.si != null ? hd.si : (i + 1)) };
    }).filter(h => h.score != null);
    if (myHoles.length) score = myHoles.reduce((sum, h) => sum + h.score, 0);
  }
  // WHS Adjusted Gross Score: cap each hole at net double bogey (par + 2 + strokes received)
  let adjGross = score;
  if (myHoles && myHoles.length && tee.slope && tee.cr) {
    const _pp = (typeof activeProfile === 'function') ? activeProfile() : null;
    const _hi = (_pp && _pp.settings && _pp.settings.manualHcp != null)
      ? _pp.settings.manualHcp
      : calcHcpIndex((state.rounds || []).filter(r => r.differential != null));
    const _ch = (_hi != null) ? calcCourseHandicap(_hi, tee.slope, tee.cr, (tee.par || 72)) : 0;
    adjGross = netDoubleBogeyAdjust(myHoles.map(h => ({ score: h.score, par: h.par })), _ch > 0 ? _ch : 0, myHoles.map(h => h.si));
  }
  // Differential — scale partial rounds (9-hole / Front / Back / custom) to an 18-hole equivalent.
  // CR is apportioned by the par actually played; (18 / holesPlayed) extrapolates to a full round.
  // For a full 18-hole round this reduces exactly to (113/slope) x (AGS - CR).
  let differential = null;
  if (tee.cr && tee.slope) {
    const holesPlayed = (myHoles && myHoles.length) ? myHoles.length : 18;
    const parTot = tee.par || 72;
    const parPlayed = (myHoles && myHoles.length) ? myHoles.reduce((sm, h) => sm + (h.par || 4), 0) : parTot;
    const crPlayed = tee.cr * (parPlayed / parTot);
    differential = (113 / tee.slope) * (adjGross - crPlayed) * (18 / (holesPlayed || 18));
    differential = Math.round(differential * 10) / 10;
  }
  return { ...round, total: score, adjustedGross: adjGross, holesPlayed: (myHoles && myHoles.length) ? myHoles.length : null, differential };
}

/* ---------- Tab nav ---------- */
function activateTab(name) {
  // Always ensure aliases are fresh before rendering any tab
  refreshProfileAliases();
  $$("#tabs button").forEach(b => b.classList.toggle("active", b.dataset.tab === name));
  ["dashboard","fgl","feed","profile","round","rounds","insights","rivalry","approvals","trophies","courses","friends","stats","settings"].forEach(t => {
    const el = $("#tab-" + t);
    if (el) el.style.display = t === name ? "" : "none";
  });
  try {
    document.body.setAttribute('data-tab', name);
    // Clubhouse & Tee Off must fit exactly one screen — kill the legacy FAB bottom-padding there.
    var _fit = (name === 'dashboard' || name === 'round');
    document.body.style.paddingBottom = _fit ? '0px' : '';
    var _appEl = document.querySelector('.app');
    if (_appEl) _appEl.style.paddingBottom = _fit ? '0px' : '';
  } catch(e){}
  const _back = document.getElementById('back-clubhouse');
  if (_back) _back.style.display = (name === 'dashboard') ? 'none' : '';
  if (name === "dashboard") renderDashboard();
  if (name === "fgl") renderFGL();
  if (name === "feed") { try { renderFeed(); } catch (e) { console.warn("feed", e); } }
  if (name === "profile") renderProfile();
  if (name === "round") renderRoundForm();
  if (name === "rounds") renderAllRounds();
  if (name === "insights") renderInsights();
  if (name === "rivalry") renderRivalry();
  if (name === "trophies") renderTrophies();
  if (name === "courses") renderCourses();
  if (name === "friends") renderFriends();
  if (name === "stats") renderStats();
  if (name === "settings") renderSettings();
  // Scroll the active tab into view in horizontal tab strip
  const activeBtn = $(`#tabs button[data-tab="${name}"]`);
  if (activeBtn) activeBtn.scrollIntoView({ behavior: "smooth", inline: "center", block: "nearest" });
  // Scroll content area to top so user always sees the tab from the start
  window.scrollTo({ top: 0, behavior: "instant" });
  // Hide the floating CTA on the round tab itself
  const fab = document.getElementById('mobile-fab');
  if (fab) fab.style.display = name === 'round' ? 'none' : '';
  // Close the mobile "More" menu and reflect whether a secondary tab is active
  const moreMenu = document.getElementById('more-menu');
  if (moreMenu) { moreMenu.classList.remove('open'); document.body.style.overflow = ''; }
  const moreBtn = document.getElementById('tabs-more');
  if (moreBtn && activeBtn) moreBtn.classList.toggle('has-active', activeBtn.classList.contains('tab-secondary'));
}

// Mobile overflow menu: surface the secondary tabs behind a "More" button
window.toggleMoreMenu = function (e) {
  if (e) e.stopPropagation();
  const menu = document.getElementById('more-menu');
  if (!menu) return;
  if (menu.classList.contains('open')) { menu.classList.remove('open'); document.body.style.overflow = ''; return; }
  // Only include tabs that are not hidden via inline style
  const secondary = $$('#tabs button.tab-secondary').filter(b => b.style.display !== 'none');
  const itemsHtml = secondary.map(b =>
    `<button data-tab="${b.dataset.tab}" class="${b.classList.contains('active') ? 'active' : ''}">${b.textContent}</button>`
  ).join('');
  menu.innerHTML = `
    <div class="more-menu-head">
      <div class="more-menu-title">MORE</div>
      <button class="more-menu-close" onclick="toggleMoreMenu()" aria-label="Close">✕</button>
    </div>
    <div class="more-items">${itemsHtml}</div>
  `;
  menu.querySelectorAll('.more-items button').forEach(item =>
    item.addEventListener('click', () => { activateTab(item.dataset.tab); })
  );
  menu.classList.add('open');
  document.body.style.overflow = 'hidden';
};
document.addEventListener('click', function (e) {
  const menu = document.getElementById('more-menu');
  const btn = document.getElementById('tabs-more');
  if (menu && menu.classList.contains('open') && !menu.contains(e.target) && e.target !== btn) {
    menu.classList.remove('open');
  }
});

