// Update edge-fade affordance on tab strip
(function setupTabScrollFade() {
  const tabs = $("#tabs");
  const wrap = $("#tabs-wrap");
  if (!tabs || !wrap) return;
  const update = () => {
    const max = tabs.scrollWidth - tabs.clientWidth;
    wrap.classList.toggle("scrolled-left", tabs.scrollLeft > 4);
    wrap.classList.toggle("scrolled-right", tabs.scrollLeft >= max - 4);
  };
  tabs.addEventListener("scroll", update, { passive: true });
  window.addEventListener("resize", update);
  setTimeout(update, 100);
})();

