function computeStakeRecord(friendId) {
  const rounds = (activeProfile()?.rounds || []).filter(r => r.stake && (!friendId || (r.friends || []).includes(friendId)));
  let won = 0, lost = 0, net = 0; const byType = {};
  rounds.forEach(r => {
    let iWon = null;
    if (r.winner) iWon = (r.winner === 'me');
    else if (r.total != null && r.opponentScore != null) iWon = (r.total < r.opponentScore);
    if (iWon === true) won++; else if (iWon === false) lost++;
    const t = r.stake; byType[t] = byType[t] || { w: 0, l: 0, amt: 0 };
    if (iWon === true) byType[t].w++; else if (iWon === false) byType[t].l++;
    const amt = Number(r.stakeAmount) || 0;
    if (t === 'money' && amt) { if (iWon === true) { net += amt; byType[t].amt += amt; } else if (iWon === false) { net -= amt; byType[t].amt -= amt; } }
  });
  return { won, lost, net, byType, count: rounds.length };
}
window.settleStakes = function (id) {
  const rounds = (activeProfile()?.rounds || []).filter(r => r.stake && (r.friends || []).includes(id) && !r.stakeSettled);
  if (!rounds.length) { showToast('Nothing outstanding to settle'); return; }
  if (!confirm('Mark all stakes with this rival as settled (paid / received)?')) return;
  rounds.forEach(r => r.stakeSettled = true);
  try { saveState(); } catch (e) {}
  showToast('Stakes settled \u2713');
  closeModal();
};
window.openProfileMenu = function() {
  const cloudIn = !!window.fairwayCloud?.isLoggedIn?.();
  if (!cloudIn && window.openAuthModal) { return openAuthModal(); }
  const p = activeProfile(); if (!p) return;
  const profiles = Object.values(state.profiles);
  const LANGS = {en:'English'};  // only fully-supported language shown — others were partial/non-working (#94)
  const curLang = (typeof currentLang!=='undefined') ? currentLang : 'en';
  const langOpts = Object.entries(LANGS).map(([k,v])=>`<option value="${k}" ${curLang===k?'selected':''}>${v}</option>`).join('');
  const rounds = (p.rounds || []).map(buildRoundComputed).filter(r => r.differential != null);
  const hcp = p.settings?.manualHcp != null ? p.settings.manualHcp : (rounds.length ? calcHcpIndex(rounds) : null);
  let wins = 0, losses = 0;
  (p.rounds || []).forEach(r => { if (r.opponentScore == null || r.total == null) return; if (r.total < r.opponentScore) wins++; else if (r.total > r.opponentScore) losses++; });
  const diffs = rounds.map(r => r.differential);
  const avg = a => a.length ? a.reduce((s,x)=>s+x,0)/a.length : null;
  const l5 = avg(diffs.slice(-5)), p5 = avg(diffs.slice(-10,-5));
  const formArrow = (l5!=null && p5!=null) ? (l5 < p5-0.2 ? '▲' : (l5 > p5+0.2 ? '▼' : '▬')) : '';
  const formVal = l5!=null ? (formArrow + ' ' + l5.toFixed(1)) : '—';
  const strong = (typeof clubhouseStrongestCourse==='function') ? clubhouseStrongestCourse(rounds) : null;
  const rep = (wins+losses)===0 ? 'Unproven' : (wins>losses ? 'On top' : (wins<losses ? 'Underdog' : 'Even'));
  const stat = (v, l) => `<div class="pc-stat"><div class="pc-stat-v">${v}</div><div class="pc-stat-l">${l}</div></div>`;
  const others = profiles.filter(x => x.id !== state.activeProfileId);
  const ridFmt = '000-' + String(p.rivalryNumber || 1).padStart(3, '0');
  const sr = computeStakeRecord();
  openModal(`
    <div class="player-card">
      <div class="pc-avatar">${avatarMarkup(p.avatar, 96)}</div>
      <div class="pc-name">${p.name || 'Player'}</div>
      <div class="pc-rid">RIVALRY ID&nbsp; <b>${ridFmt}</b></div>
      <div class="pc-club">${p.homeClub || 'No home club yet'}</div>
      <div class="pc-stats">${stat(hcp != null ? Number(hcp).toFixed(1) : '—', 'HCP*')}${stat(wins + '–' + losses, 'Rival record')}${stat(formVal, 'Current form')}</div>
      <div class="pc-traits">
        <span class="pc-trait"><span class="pc-trait-l">Rival reputation</span><span class="pc-trait-v">${rep}</span></span>
        ${strong ? `<span class="pc-trait"><span class="pc-trait-l">Signature course</span><span class="pc-trait-v">${strong}</span></span>` : ''}
        <span class="pc-trait"><span class="pc-trait-l">Rounds played</span><span class="pc-trait-v">${(p.rounds||[]).length}</span></span>
        ${sr.count ? `<span class="pc-trait"><span class="pc-trait-l">Stakes record</span><span class="pc-trait-v">Won ${sr.won} · Lost ${sr.lost}${sr.net ? ` · ${sr.net>0?'+':''}${sr.net}` : ''}</span></span>` : ''}
      </div>
      ${p.bio ? `<p class="pc-bio">${p.bio}</p>` : ''}
      <div class="pc-foot">*Unofficial WHS-style index — not your official federation handicap</div>
      <div class="pc-actions">
        <button class="btn btn-gold" style="flex:1" onclick="closeModal(); activateTab('profile')">Edit profile</button>
        <button class="btn btn-ghost" style="flex:1" onclick="closeModal(); activateTab('settings')">Settings</button>
      </div>
      <div class="pc-lang"><span class="pc-lang-l">Language</span><select class="pc-lang-sel" onchange="setLanguage(this.value)">${langOpts}</select></div>
      <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="if(window.fairwayCloud&&window.fairwayCloud.signOut){window.fairwayCloud.signOut().then(()=>location.reload());}else{location.reload();}">Sign out</button>
      ${others.length ? `<div class="pc-switch">${others.map(x => `<button class="pc-switch-btn" onclick="switchProfile('${x.id}'); closeModal()">${avatarMarkup(x.avatar, 22)} <span>${x.name}</span></button>`).join('')}</div>` : ''}
    </div>
  `);
};
