function hcoChart(rounds, countIds) {
  if (!rounds || rounds.length < 2) return '<div class="hco-chart-empty">Log a few rounds to see your trend.</div>';
  const n = rounds.length;
  const diffs = rounds.map(r => r.differential);
  const min = Math.min(...diffs), max = Math.max(...diffs);
  const span = (max - min) || 1;
  const dx = 46, padX = 28, padTop = 34, plotH = 150, baseY = padTop + plotH; // baseY = date axis
  const W = padX * 2 + (n - 1) * dx;
  const H = baseY + 40;
  const x = i => padX + i * dx;
  const y = d => padTop + (d - min) / span * plotH; // lower diff -> higher
  const pts = rounds.map((r, i) => [x(i), y(r.differential)]);
  // smooth (Catmull-Rom -> cubic bezier) curve through the points
  const sp = (a) => {
    if (a.length < 2) return '';
    let d = 'M' + a[0][0].toFixed(1) + ' ' + a[0][1].toFixed(1);
    for (let i = 0; i < a.length - 1; i++) {
      const p0 = a[i - 1] || a[i], p1 = a[i], p2 = a[i + 1], p3 = a[i + 2] || p2;
      const c1x = p1[0] + (p2[0] - p0[0]) / 6, c1y = p1[1] + (p2[1] - p0[1]) / 6;
      const c2x = p2[0] - (p3[0] - p1[0]) / 6, c2y = p2[1] - (p3[1] - p1[1]) / 6;
      d += ' C' + c1x.toFixed(1) + ' ' + c1y.toFixed(1) + ' ' + c2x.toFixed(1) + ' ' + c2y.toFixed(1) + ' ' + p2[0].toFixed(1) + ' ' + p2[1].toFixed(1);
    }
    return d;
  };
  const line = sp(pts);
  const area = line + ' L' + pts[n-1][0].toFixed(1) + ' ' + baseY + ' L' + pts[0][0].toFixed(1) + ' ' + baseY + ' Z';
  const shortDate = (ds) => { const dt = new Date(ds); if (isNaN(dt)) return ''; return (dt.getDate()) + '/' + (dt.getMonth() + 1); };
  const marks = rounds.map((r, i) => {
    const c = countIds && countIds.has(r.id);
    const px = pts[i][0], py = pts[i][1];
    const val = r.differential != null ? r.differential.toFixed(1) : '';
    return `<g>
      <line x1="${px.toFixed(1)}" y1="${(py+4).toFixed(1)}" x2="${px.toFixed(1)}" y2="${baseY}" stroke="rgba(201,169,97,0.22)" stroke-width="1" stroke-dasharray="2 3"/>
      <circle cx="${px.toFixed(1)}" cy="${py.toFixed(1)}" r="${c ? 3.6 : 2.6}" fill="${c ? 'var(--gold-bright)' : 'rgba(201,169,97,0.55)'}" stroke="${c ? 'var(--gold)' : 'none'}" stroke-width="1"/>
      <text x="${px.toFixed(1)}" y="${(py-9).toFixed(1)}" fill="${c ? 'var(--gold-bright)' : 'var(--muted)'}" font-size="10" font-weight="${c ? '700' : '500'}" text-anchor="middle" font-family="inherit">${val}</text>
      <text x="${px.toFixed(1)}" y="${baseY+15}" fill="var(--muted-2,#9a937f)" font-size="8.5" text-anchor="middle" font-family="inherit">${shortDate(r.date)}</text>
    </g>`;
  }).join('');
  return `<div class="hco-chart">
    <div class="hco-chart-scroll">
      <svg viewBox="0 0 ${W} ${H}" width="${W}" height="${H}" style="height:${H}px;max-width:none">
        <defs><linearGradient id="hcoArea" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="rgba(201,169,97,0.28)"/><stop offset="100%" stop-color="rgba(201,169,97,0)"/></linearGradient></defs>
        <line x1="${padX-6}" y1="${baseY}" x2="${W-padX+6}" y2="${baseY}" stroke="rgba(201,169,97,0.18)" stroke-width="1"/>
        <path d="${area}" fill="url(#hcoArea)"/>
        <path d="${line}" fill="none" stroke="var(--gold)" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round"/>
        ${marks}
      </svg>
    </div>
    <div class="hco-chart-cap">HC played per round · last ${n} · lower is better · gold dots count toward your index · swipe to see all</div>
  </div>`;
}
window.openHcOverview = function () {
  const p = activeProfile() || {};
  const built = (p.rounds || []).map(buildRoundComputed).filter(r => r.differential != null)
    .sort((a, b) => new Date(a.date) - new Date(b.date));
  const idx = p.settings?.manualHcp != null ? p.settings.manualHcp : (built.length ? calcHcpIndex(built) : null);
  const last20 = built.slice(-20);
  const _avg = a => a.length ? a.reduce((s, x) => s + x, 0) / a.length : null;
  const diffs = last20.map(r => r.differential);
  const l5 = _avg(diffs.slice(-5)), pr5 = _avg(diffs.slice(-10, -5));
  const trend = (l5 != null && pr5 != null) ? (l5 < pr5 - 0.2 ? '\u25BC improving' : (l5 > pr5 + 0.2 ? '\u25B2 rising' : '\u25AC steady')) : '';
  const low = built.length ? Math.min(...built.map(r => r.differential)) : null;
  // best 8 of last 20 count toward the index
  const nCount = Math.min(8, last20.length);
  const countIds = new Set([...last20].sort((a, b) => a.differential - b.differential).slice(0, nCount).map(r => r.id));
  const recent = [...last20].reverse();
  const rows = recent.length ? recent.map(r => {
    const c = getCourse(r.courseId);
    const counts = countIds.has(r.id);
    return `<div class="hco-row ${counts ? 'counts' : ''}">
      <span class="hco-row-date">${fmtDate(r.date)}</span>
      <span class="hco-row-course">${c ? c.name : '\u2014'}</span>
      <span class="hco-row-total">${r.total || '\u2014'}</span>
      <span class="hco-row-diff">${r.differential != null ? r.differential.toFixed(1) : '\u2014'}</span>
    </div>`;
  }).join('') : '<p style="color:var(--muted); font-size:13px; padding:10px 0">No rounds logged yet.</p>';
  openModal(`
    <div class="hco">
      <div class="section-eyebrow">YOUR HANDICAP</div>
      <div class="hco-idx">${idx != null ? Number(idx).toFixed(1) : '\u2014'}</div>
      <div class="hco-idx-sub">Unofficial WHS-style index \u00b7 best ${nCount} of last ${last20.length}${trend ? ' \u00b7 ' + trend : ''}</div>
      <button class="hco-edit-link" onclick="closeModal(); activateTab('profile'); try{ document.getElementById('p-manual-hcp')?.focus(); }catch(e){}">Edit handicap in Profile</button>
      ${hcoChart(last20, countIds)}
      <div class="hco-chips">
        <div class="hco-chip"><div class="hco-chip-v">${built.length}</div><div class="hco-chip-l">Rounds</div></div>
        <div class="hco-chip"><div class="hco-chip-v">${low != null ? low.toFixed(1) : '\u2014'}</div><div class="hco-chip-l">Lowest diff</div></div>
        <div class="hco-chip"><div class="hco-chip-v">${l5 != null ? l5.toFixed(1) : '\u2014'}</div><div class="hco-chip-l">Last 5 avg</div></div>
      </div>
      <div class="hco-rounds-h">Recent rounds <span style="color:var(--gold-dim); font-weight:400">\u00b7 gold = counts toward index</span></div>
      <div class="hco-rounds">${rows}</div>
      <button class="btn btn-ghost" style="width:100%; margin-top:14px" onclick="closeModal()">Close</button>
    </div>`);
};
window.openAdvancedInsights = function () {
  const p = activeProfile() || {};
  const rounds = (p.rounds || []).map(buildRoundComputed);
  const holeRecs = [];
  rounds.forEach(r => (r.holes || []).forEach((h, i) => { if (h && h.score != null) holeRecs.push({ i, rel: h.score - (h.par || 4) }); }));
  const N = holeRecs.length;
  const f1 = x => (x > 0 ? '+' : (x < 0 ? '−' : '')) + Math.abs(x).toFixed(2);
  const overall = N ? holeRecs.reduce((s, h) => s + h.rel, 0) / N : null;
  // Scoring mix
  let eagle = 0, birdie = 0, par = 0, bogey = 0, dbl = 0;
  holeRecs.forEach(h => { const d = h.rel; if (d <= -2) eagle++; else if (d === -1) birdie++; else if (d === 0) par++; else if (d === 1) bogey++; else dbl++; });
  const pc = v => N ? Math.round(v / N * 100) : 0;
  // Per hole-number average
  const byHole = {}; holeRecs.forEach(h => { (byHole[h.i] = byHole[h.i] || []).push(h.rel); });
  const avg = a => a && a.length ? a.reduce((x, y) => x + y, 0) / a.length : null;
  // Opening jitters (first hole) & clutch (last 3 holes) computed per round then averaged
  let openRel = [], clutchRel = [];
  rounds.forEach(r => {
    const hs = (r.holes || []).filter(h => h && h.score != null).map(h => h.score - (h.par || 4));
    if (hs.length) { openRel.push(hs[0]); }
    if (hs.length >= 3) { const last3 = hs.slice(-3); clutchRel.push(last3.reduce((a, b) => a + b, 0) / 3); }
  });
  const openAvg = avg(openRel), clutchAvg = avg(clutchRel);
  // Bounce-back: after a double+ , next hole par or better
  let opps = 0, backs = 0;
  rounds.forEach(r => { const hs = (r.holes || []).filter(h => h && h.score != null).map(h => h.score - (h.par || 4)); for (let i = 0; i < hs.length - 1; i++) { if (hs[i] >= 2) { opps++; if (hs[i + 1] <= 0) backs++; } } });
  // Best / worst hole number (>=2 samples)
  let bestH = null, worstH = null;
  Object.entries(byHole).forEach(([i, a]) => { if (a.length < 2) return; const m = avg(a); if (bestH == null || m < bestH.m) bestH = { i: +i + 1, m }; if (worstH == null || m > worstH.m) worstH = { i: +i + 1, m }; });
  // Day of week (always available from date)
  const dows = ['Sundays', 'Mondays', 'Tuesdays', 'Wednesdays', 'Thursdays', 'Fridays', 'Saturdays'];
  const dowBuckets = {};
  rounds.forEach(r => { if (r.differential == null) return; const dt = new Date(r.date); if (isNaN(dt)) return; const k = dt.getDay(); (dowBuckets[k] = dowBuckets[k] || []).push(r.differential); });
  let bestDow = null; Object.entries(dowBuckets).forEach(([k, a]) => { if (a.length < 2) return; const m = avg(a); if (bestDow == null || m < bestDow.m) bestDow = { k: +k, m, n: a.length }; });
  // Time of day (needs hour info)
  const todName = ['Early mornings', 'Mornings', 'Midday', 'Afternoons', 'Evenings'];
  const todBucket = h => h < 8 ? 0 : h < 11 ? 1 : h < 14 ? 2 : h < 18 ? 3 : 4;
  const todB = {}; let anyHour = false;
  rounds.forEach(r => { if (r.differential == null) return; const dt = new Date(r.date); if (isNaN(dt)) return; const h = dt.getHours(); if (h !== 0) anyHour = true; const k = todBucket(h); (todB[k] = todB[k] || []).push(r.differential); });
  let bestTod = null; if (anyHour) Object.entries(todB).forEach(([k, a]) => { if (a.length < 2) return; const m = avg(a); if (bestTod == null || m < bestTod.m) bestTod = { k: +k, m }; });

  const row = (label, value, explain) => `<div class="adv-row"><div class="adv-row-top"><span class="adv-label">${label}</span><span class="adv-val">${value}</span></div><div class="adv-explain">${explain}</div></div>`;
  const dash = '—';
  const todVal = bestTod ? `${todName[bestTod.k]}` : dash;
  const todExp = bestTod ? `Your scoring differential is lowest then (avg ${bestTod.m.toFixed(1)}). Lower is better.` : 'Log rounds with a tee time to unlock when you play your best.';
  const dowVal = bestDow ? dows[bestDow.k] : dash;
  const dowExp = bestDow ? `Best average differential by weekday (${bestDow.m.toFixed(1)} over ${bestDow.n} rounds). Lower is better.` : 'Play a few more rounds to reveal your strongest day.';
  const mixVal = N ? `${pc(par)}% par` : dash;
  const mixExp = N ? `How your holes break down: eagles ${pc(eagle)}% · birdies ${pc(birdie)}% · pars ${pc(par)}% · bogeys ${pc(bogey)}% · doubles or worse ${pc(dbl)}%.` : 'No hole-by-hole rounds logged yet.';
  const bbVal = opps ? `${Math.round(backs / opps * 100)}%` : dash;
  const bbExp = opps ? `After a double bogey or worse, you answer with par or better ${Math.round(backs / opps * 100)}% of the time (${backs} of ${opps}). Higher is better — it means mistakes don't snowball.` : 'No double bogeys to bounce back from yet — nice.';
  const clVal = clutchAvg != null ? `${f1(clutchAvg)} /hole` : dash;
  const clExp = clutchAvg != null ? `Your average score vs par over the final 3 holes. ${f1(clutchAvg)} means ${Math.abs(clutchAvg).toFixed(2)} strokes ${clutchAvg <= 0 ? 'under' : 'over'} par per hole — ${clutchAvg <= 0 ? 'you finish strong' : 'you tend to leak shots late'}.` : 'Log full rounds to measure your finish.';
  const opVal = openAvg != null ? `${f1(openAvg)} /hole` : dash;
  const opExp = openAvg != null ? `Your average score vs par on the 1st hole. ${f1(openAvg)} means ${Math.abs(openAvg).toFixed(2)} strokes ${openAvg <= 0 ? 'under' : 'over'} par — ${openAvg <= 0 ? 'you start calm' : 'a slow first-tee start'}.` : 'Log full rounds to measure your start.';
  const bestVal = bestH ? `Hole ${bestH.i} (${f1(bestH.m)})` : dash;
  const worstVal = worstH ? `Hole ${worstH.i} (${f1(worstH.m)})` : dash;
  const bwExp = (bestH || worstH) ? `Average score vs par by hole number across all your courses. A minus is under par (your friend), a plus is over par (your trouble spot).` : 'Play more hole-by-hole rounds to map your holes.';

  openModal(`
    <div class="adv-ins">
      <div class="section-eyebrow">PLAYER INSIGHTS</div>
      <h2 style="margin:2px 0 2px">Your edge, in the detail</h2>
      <p style="color:var(--muted); font-size:12.5px; line-height:1.5; margin:0 0 12px">The patterns behind your scores. Numbers shown as <b>per-hole strokes vs par</b> — a <b>minus (−)</b> is under par (better), a <b>plus (+)</b> is over par. So −0.67 means two-thirds of a shot better than par each hole.</p>
      ${row('Time of day', todVal, todExp)}
      ${row('Day of week', dowVal, dowExp)}
      ${row('Scoring mix', mixVal, mixExp)}
      ${row('Bounce-back rate', bbVal, bbExp)}
      ${row('Clutch factor (last 3 holes)', clVal, clExp)}
      ${row('Opening jitters (hole 1)', opVal, opExp)}
      ${row('Best hole', bestVal, bwExp)}
      ${row('Worst hole', worstVal, 'Your toughest hole number on average — a plus means you play it over par. Target it in practice.')}
      <button class="btn btn-ghost" style="width:100%; margin-top:14px" onclick="closeModal()">Close</button>
    </div>`);
};
window.openHcImport = function () {
  const rows = Array.from({length:20}, (_,i)=>`<div class="hci-row"><span class="hci-n">${i+1}</span><input type="number" step="0.1" inputmode="decimal" class="hci-in" placeholder="—"></div>`).join('');
  openModal(`
    <div class="hci">
      <div class="section-eyebrow" style="margin-bottom:4px">QUICK-SET HANDICAP</div>
      <h2 style="margin:0 0 6px">Your last 20 rounds</h2>
      <p style="color:var(--muted); font-size:13px; line-height:1.5; margin:0 0 12px">Enter the handicap you played to in each of your last 20 rounds — <b>round 20 is your most recent</b>. We work out your index from your best 8.</p>
      <div class="hci-grid">${rows}</div>
      <div class="hci-result" id="hci-result" style="display:none"></div>
      <button class="btn btn-gold" style="width:100%; margin-top:14px" onclick="calcHcImport()">Calculate my handicap</button>
      <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="closeModal()">Close</button>
    </div>`);
};
window.calcHcImport = function () {
  const vals = [...document.querySelectorAll('.hci-in')].map(i=>parseFloat(i.value)).filter(v=>!isNaN(v));
  if (vals.length < 3) { showToast('Enter at least 3 rounds', true); return; }
  const table = {3:1,4:1,5:1,6:2,7:2,8:2,9:3,10:3,11:3,12:4,13:4,14:4,15:5,16:5,17:6,18:6,19:7,20:8};
  const n = Math.min(vals.length, 20);
  const use = table[n] || Math.max(1, Math.round(n*0.4));
  const idx = vals.slice().sort((a,b)=>a-b).slice(0,use).reduce((s,x)=>s+x,0) / use;
  const p = activeProfile();
  if (p) { p.settings = p.settings || {}; p.settings.manualHcp = Number(idx.toFixed(1)); try { saveState(); } catch(e) {} }
  const res = document.getElementById('hci-result');
  if (res) { res.style.display=''; res.innerHTML = `<div class="hci-idx">${idx.toFixed(1)}</div><div class="hci-idx-l">WHS-style index from your best ${use} of ${n}. Saved to your profile.</div>`; }
  if (typeof renderHeader === 'function') renderHeader();
};
window.createNewProfile = function() {
  const name = prompt("Name for the new profile:");
  if (!name) return;
  const p = defaultProfile(name);
  state.profiles[p.id] = p;
  state.activeProfileId = p.id;
  refreshProfileAliases();
  saveState();
  renderHeader();
  activateTab('profile');
};

window.deleteCurrentProfile = function() {
  if (Object.keys(state.profiles).length <= 1) { showToast("Can't delete your last profile", true); return; }
  if (!confirm(`Delete the profile "${activeProfile().name}" and all its data?`)) return;
  delete state.profiles[state.activeProfileId];
  state.activeProfileId = Object.keys(state.profiles)[0];
  refreshProfileAliases();
  saveState();
  renderHeader();
  activateTab('dashboard');
};

function checkOnboarding() {
  if (window._frInRecovery) return;
  const p = activeProfile();
  if (!p) return;
  // Skip welcome if user already has email, name set, or has skipped/registered before
  const alreadyRegistered = !!(p.email || (p.name && p.name !== "Profile" && p.name !== "Min profil" && p.name !== "Player") || p.skippedOnboarding);
  if (alreadyRegistered) return;
  const hasAnyData = (p.rounds && p.rounds.length > 0) || (p.friends && p.friends.length > 0);
  if (hasAnyData) return;
  // Only show welcome on truly fresh first run
  setTimeout(() => _showWelcomeWizard(), 200);
}

