window.skipOnboarding = function() {
  const overlay = document.getElementById('wl-overlay');
  if (overlay) overlay.remove();
  document.body.classList.remove('wl-showing');
  const p = activeProfile();
  if (p) { p.skippedOnboarding = true; saveState(); }
};
window.frCheckOutSite = function() {
  window._frCheckedOut = true;
  const overlay = document.getElementById('wl-overlay');
  if (overlay) overlay.remove();
  document.body.classList.remove('wl-showing');
  try { activateTab('dashboard'); } catch (e) {}
};

window.finishWelcomeAndCreate = async function() {
  const p = activeProfile();
  const name = (document.getElementById('wz-name')?.value || '').trim();
  const email = (document.getElementById('wz-email')?.value || '').trim();
  const password = document.getElementById('wz-password')?.value || '';
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!name) { showToast('Enter your name', true); document.getElementById('wz-name')?.focus(); return; }
  if (!re.test(email)) { showToast("That email doesn't look right", true); document.getElementById('wz-email')?.focus(); return; }
  if (password.length < 6) { showToast('Password must be at least 6 characters', true); document.getElementById('wz-password')?.focus(); return; }
  if (p) { p.name = name; p.email = email; p.skippedOnboarding = true; saveState(); }
  const btn = document.querySelector('.wl-cta-primary');
  if (btn) { btn.disabled = true; btn.textContent = "Creating account…"; }
  let signedIn = false, needConfirm = false, errMsg = null;
  if (window.fairwayCloud && window.fairwayCloud.signUp) {
    try {
      const { data, error } = await window.fairwayCloud.signUp(email, password, name);
      if (error) errMsg = error.message || 'Could not create account';
      else if (data && data.session) signedIn = true;
      else needConfirm = true;
    } catch (e) { errMsg = (e && e.message) || 'Cloud unreachable'; }
  } else { errMsg = 'Cloud not loaded'; }
  if (signedIn) {
    window._frCheckedOut = true;
    const o = document.getElementById('wl-overlay'); if (o) o.remove();
    document.body.classList.remove('wl-showing');
    showToast('Welcome, ' + name + '!');
    setTimeout(() => { try { if (typeof openAddRival === 'function') return openAddRival(); } catch (e) {} try { activateTab('rivalry'); } catch (e) {} }, 350);
    return;
  }
  const overlay = document.getElementById('wl-overlay');
  if (overlay) {
    overlay.innerHTML = `
      <div class="wl-content wl-sent">
        <div class="wl-sent-icon">\ud83d\udce7</div>
        <h1 class="wl-sent-h">${needConfirm ? 'Confirm your email' : 'Almost there'}</h1>
        ${needConfirm ? `<p class="wl-sent-p">We sent a confirmation link to <strong>${email}</strong>.<br>Tap it to finish creating your account, then sign in.</p>` : `<p class="wl-sent-p" style="color:#c97a7a">${errMsg}.</p>`}
        <p class="wl-sent-sub">No email after a minute? Check spam.</p>
        <button class="wl-cta-primary" onclick="frCheckOutSite(); setTimeout(openAuthModal, 100);">Go to sign in →</button>
        <button class="wl-cta-tertiary" onclick="frCheckOutSite();">Take a look first</button>
      </div>`;
    if (btn) { btn.disabled = false; btn.textContent = "Create my account →"; }
  }
};

window.finishWelcome = function(withDemo) {
  const p = activeProfile();
  p.name = ($("#wz-name").value || "Mathias").trim();
  p.homeClub = $("#wz-club").value || "";
  const target = $("#wz-target").value;
  if (target) p.targetHcp = parseFloat(target);
  if (withDemo) {
    loadDemoData();
  }
  saveState();
  closeModal();
  renderHeader();
  showToast(`Welcome, ${p.name}! ${withDemo ? 'Demo data loaded.' : 'Ready for your first round.'}`);
  activateTab('dashboard');
};

/* =====================================================
   DEMO DATA - så nye brukere ser appen med innhold
   ===================================================== */
function loadDemoData() {
  const p = activeProfile();
  // Demo friends
  const friends = [
    { id: uid(), name: "Petter", hcp: 12.4 },
    { id: uid(), name: "Lars", hcp: 8.1 },
    { id: uid(), name: "Anna", hcp: 18.5 },
  ];
  p.friends.push(...friends);

  // Pick 3 popular courses from seed
  const courses = state.courses.filter(c => ["Oslo Golfklubb (Bogstad)", "Miklagard GK", "Soon Golfklubb"].includes(c.name)).slice(0, 3);
  if (courses.length < 3) courses.push(...state.courses.slice(0, 3 - courses.length));

  // Generate ~18 demo rounds over last 6 months
  const today = new Date();
  const startScore = 95, endScore = 84; // improvement curve
  const weatherOpts = ['sun', 'sun', 'cloud', 'cloud', 'rain', 'wind'];
  const times = ['07:30', '09:15', '11:00', '13:30', '15:45', '17:30'];

  for (let i = 0; i < 18; i++) {
    const date = new Date(today);
    date.setDate(date.getDate() - (180 - i * 10) - Math.floor(Math.random() * 3));
    const progress = i / 17;
    const c = courses[i % courses.length];
    const tee = c.tees[0];
    const baseScore = startScore + (endScore - startScore) * progress;
    const noise = (Math.random() - 0.5) * 6;
    const score = Math.round(baseScore + noise);
    const mood = Math.random() > 0.3 ? Math.floor(Math.random() * 3) + 3 : Math.floor(Math.random() * 2) + 1;
    const energy = Math.floor(Math.random() * 3) + 2;
    const friendId = friends[i % 3].id;
    const opponentScore = score + Math.round((Math.random() - 0.4) * 8);

    p.rounds.push({
      id: uid(),
      date: date.toISOString().slice(0, 10),
      teeTime: times[i % times.length],
      courseId: c.id,
      teeName: tee.name,
      scoreType: 'total',
      total: score,
      friends: [friendId],
      notes: "",
      weather: weatherOpts[i % weatherOpts.length],
      temp: 12 + Math.floor(Math.random() * 15),
      windSpeed: Math.floor(Math.random() * 7),
      mood, energy,
      focus: Math.floor(Math.random() * 3) + 2,
      opponentScore: i >= 12 ? opponentScore : null,  // recent rounds have opponent data for rivalry
    });
  }

  // Demo rivalry
  if (!p.rivalries) p.rivalries = [];
  const startD = new Date(today); startD.setDate(startD.getDate() - 60);
  const endD = new Date(today); endD.setDate(endD.getDate() + 30);
  p.rivalries.push({
    id: uid(),
    name: "Sommerligaen 2026",
    friendId: friends[0].id,
    startDate: startD.toISOString().slice(0,10),
    endDate: endD.toISOString().slice(0,10),
    format: 'stroke_play',
    status: 'active',
    createdAt: new Date().toISOString(),
  });

  refreshProfileAliases();
}

window.clearDemoData = function() {
  if (!confirm("Delete demo rounds, demo friends and demo rivalry?")) return;
  const p = activeProfile();
  // Heuristic: rounds with notes === "" and recent demo dates - safer to ask user to reset
  // Easier: keep a marker. For now, just remove everything from this profile.
  p.rounds = [];
  p.friends = [];
  p.rivalries = [];
  p.achievementsSeen = [];
  refreshProfileAliases();
  saveState();
  renderHeader();
  showToast("Demo data cleared ✓");
  activateTab('dashboard');
};

