function frCourseLogo(name){ if(!name) return 'course-logos/default.png'; const slug=String(name).toLowerCase().normalize('NFD').replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,''); return 'course-logos/'+slug+'.png'; }
function frFindFriend(fid){ var _fr = (typeof state!=='undefined' && state && state.friends) ? state.friends : []; return _fr.find(f=>f&&(f.id===fid||f.cloudId===fid||f._cloudUserId===fid)); }
function frFriendIdSet(fid){ const out=new Set([fid]); const f=frFindFriend(fid); if(f){ if(f.id)out.add(f.id); if(f.cloudId)out.add(f.cloudId); if(f._cloudUserId)out.add(f._cloudUserId);} return out; }
function frListHasFriend(list, fid){ const sset=frFriendIdSet(fid); return (list||[]).some(x=>sset.has(x)); }
function frRoundHasFriend(round, fid){ return frListHasFriend(round&&round.friends, fid); }
