function initCropper() {
  const stage = document.getElementById('pc-crop-stage'), img = document.getElementById('pc-crop-img'), zoom = document.getElementById('pc-crop-zoom');
  if (!stage || !img) return;
  const c = window.__crop;
  const apply = () => { img.style.transform = 'translate(-50%,-50%) translate(' + c.x + 'px,' + c.y + 'px) scale(' + c.scale + ')'; };
  const setup = () => {
    const S = stage.clientWidth || 240;
    c.k = S / Math.min(img.naturalWidth || 1, img.naturalHeight || 1);
    img.style.width = (img.naturalWidth * c.k) + 'px';
    img.style.height = (img.naturalHeight * c.k) + 'px';
    apply();
  };
  if (img.complete && img.naturalWidth) setup(); else img.onload = setup;
  zoom.oninput = () => { c.scale = parseFloat(zoom.value); apply(); };
  const start = (x, y) => { c.drag = { x: x, y: y, ox: c.x, oy: c.y }; };
  const move = (x, y) => { if (!c.drag) return; c.x = c.drag.ox + (x - c.drag.x); c.y = c.drag.oy + (y - c.drag.y); apply(); };
  const endD = () => { c.drag = null; };
  stage.addEventListener('mousedown', e => start(e.clientX, e.clientY));
  window.addEventListener('mousemove', e => move(e.clientX, e.clientY));
  window.addEventListener('mouseup', endD);
  stage.addEventListener('touchstart', e => { const t = e.touches[0]; start(t.clientX, t.clientY); }, { passive: true });
  stage.addEventListener('touchmove', e => { const t = e.touches[0]; move(t.clientX, t.clientY); e.preventDefault(); }, { passive: false });
  stage.addEventListener('touchend', endD);
}
window.savePhotoCrop = function () {
  const c = window.__crop; const stage = document.getElementById('pc-crop-stage'), img = document.getElementById('pc-crop-img');
  if (!c || !stage || !img) { closeModal(); return; }
  const S = stage.clientWidth || 240; const out = 256; const r = out / S;
  const canvas = document.createElement('canvas'); canvas.width = out; canvas.height = out;
  const ctx = canvas.getContext('2d');
  ctx.beginPath(); ctx.arc(out / 2, out / 2, out / 2, 0, Math.PI * 2); ctx.clip();
  ctx.fillStyle = '#0d1c15'; ctx.fillRect(0, 0, out, out);
  const dw = img.naturalWidth * c.k * c.scale * r;
  const dh = img.naturalHeight * c.k * c.scale * r;
  const dx = out / 2 + c.x * r - dw / 2;
  const dy = out / 2 + c.y * r - dh / 2;
  try { ctx.drawImage(img, dx, dy, dw, dh); } catch (e) {}
  let data; try { data = canvas.toDataURL('image/jpeg', 0.85); } catch (e) { closeModal(); return; }
  const p = activeProfile(); if (p) { p.avatar = data; try { saveState(); } catch (e) {} }
  try { if (window.fairwayCloud && window.fairwayCloud.isLoggedIn && window.fairwayCloud.isLoggedIn() && window.fairwayCloud.pushProfile) window.fairwayCloud.pushProfile(activeProfile()); } catch (e) {}
  closeModal();
  try { renderHeader(); } catch (e) {}
  try { renderProfile(); } catch (e) {}
  try { showToast('Profile photo updated'); } catch (e) {}
};
