/* ---------- Render: Dashboard ---------- */
function renderRivalryHero() {
  const hero = $("#rivalry-hero");
  if (!hero) return;
  const active = (state.rivalries || []).filter(rv => {
    const now = new Date(), end = new Date(rv.endDate);
    return now <= end;
  });

  if (active.length === 0) {
    // Editorial empty state - no panels, just typography and intent
    hero.innerHTML = `
      <div class="hero-empty">
        <div class="hero-empty-label">NO RIVALRY ACTIVE</div>
        <h1 class="hero-empty-title">A season is waiting<br>to be played.</h1>
        <p class="hero-empty-body">
          Pick a friend. Pick a period. Pick a format.<br>
          Fairway Rivalry turns every round into history.
        </p>
        <button class="hero-cta" onclick="activateTab('rivalry'); setTimeout(()=>$('#rv-new').click(), 300)">
          <span>Begin the season</span>
          <span class="arrow">→</span>
        </button>
      </div>
    `;
    return;
  }

  // Show top active rivalry as the cinematic fight card
  const rv = active[0];
  const stats = computeRivalryStats(rv);
  const friend = state.friends.find(f => f.id === rv.friendId);
  const me = (activeProfile()?.name || "YOU").toUpperCase();
  const fname = (friend?.name || "RIVAL").toUpperCase();
  const myLeading = stats.myScore > stats.theirScore;
  const tie = stats.myScore === stats.theirScore;
  const margin = Math.abs(stats.myScore - stats.theirScore);
  const daysLeft = Math.max(0, Math.ceil((new Date(rv.endDate) - new Date()) / 86400000));

  // Compute current streak (last consecutive results)
  const recentMatches = stats.matches.sort((a,b) => new Date(b.round.date) - new Date(a.round.date));
  let streakType = null, streakCount = 0;
  for (const m of recentMatches) {
    if (m.tie) { if (streakCount === 0) { streakType = 'T'; streakCount = 1; } break; }
    const t = m.won ? 'W' : 'L';
    if (streakType === null) { streakType = t; streakCount = 1; }
    else if (streakType === t) streakCount++;
    else break;
  }
  const streakLabel = streakType && streakCount > 0 ? `${streakType}${streakCount}` : '—';
  const streakColor = streakType === 'W' ? 'var(--accent-bright)' : streakType === 'L' ? 'var(--tension)' : 'var(--muted)';

  hero.innerHTML = `
    <div class="hero-fight-card" onclick="activateTab('rivalry'); setTimeout(()=>showRivalryDetail('${rv.id}'), 200)">
      <div class="hero-meta-top">
        <span class="hero-tag">SEASON IN PROGRESS</span>
        <span class="hero-meta-dot">·</span>
        <span class="hero-tag-light">${daysLeft} DAYS REMAINING</span>
      </div>

      <h1 class="hero-matchup">
        <span class="${myLeading ? 'leading' : ''}">${me}</span>
        <span class="versus">—</span>
        <span class="${!myLeading && !tie ? 'leading' : ''}">${fname}</span>
      </h1>

      <div class="hero-score">
        <div class="score-num ${myLeading ? 'win' : tie ? 'tie' : 'loss'}">${stats.myScore}</div>
        <div class="score-separator"></div>
        <div class="score-num ${!myLeading && !tie ? 'win' : tie ? 'tie' : 'loss'}">${stats.theirScore}</div>
      </div>

      <div class="hero-meta-bottom">
        <div class="hero-meta-item">
          <span class="meta-label">SEASON</span>
          <span class="meta-value">${rv.name}</span>
        </div>
        <div class="hero-meta-item">
          <span class="meta-label">ROUNDS</span>
          <span class="meta-value">${stats.rounds} played</span>
        </div>
        <div class="hero-meta-item">
          <span class="meta-label">STREAK</span>
          <span class="meta-value" style="color: ${streakColor}">${streakLabel}</span>
        </div>
        <div class="hero-meta-item">
          <span class="meta-label">FORMAT</span>
          <span class="meta-value">${RIVALRY_FORMATS[rv.format]?.label || rv.format}</span>
        </div>
      </div>

      <button class="hero-cta" onclick="event.stopPropagation(); activateTab('round')">
        <span>Play next round</span>
        <span class="arrow">→</span>
      </button>
    </div>
  `;

  // Update brand sub
  const brandSub = $("#brand-sub");
  if (brandSub) brandSub.textContent = `${rv.name} · ${stats.rounds} rounds played`;
}

window.rwzSaveActive = function () {
  try {
    const rfs = window.roundFormState; if (!rfs) return;
    const holes = rfs.holes || [];
    const totals = [...document.querySelectorAll('.rwz-total-input')].some(i => i.value);
    const hasData = holes.some(h => h && (h.score || (h.scores && Object.keys(h.scores).length) || h.result)) || totals;
    if (!hasData) return;
    const cid = document.getElementById('r-course')?.value;
    localStorage.setItem('fgl_active_round', JSON.stringify({ rfs, courseId: cid, courseName: cid ? (getCourse(cid)?.name || '') : '', tee: document.getElementById('r-tee')?.value || '', scoreType: window._rwzCardMode || rfs.scoreType, ts: Date.now() }));
  } catch (e) {}
};
window.rwzClearActive = function () { try { localStorage.removeItem('fgl_active_round'); } catch (e) {} };
window.resumeActiveRound = function () {
  let d = null; try { d = JSON.parse(localStorage.getItem('fgl_active_round')); } catch (e) {}
  if (!d) return;
  window.roundFormState = d.rfs || { holes: [], selectedFriends: [] };
  roundFormState = window.roundFormState;
  activateTab('round'); showRoundForm('golf');
  const cs = document.getElementById('r-course');
  if (cs && d.courseId) { cs.value = d.courseId; cs.dispatchEvent(new Event('change', { bubbles: true })); }
  setTimeout(() => {
    const ts = document.getElementById('r-tee'); if (ts && d.tee) ts.value = d.tee;
    if (d.scoreType && typeof rndSetScoreType === 'function') rndSetScoreType(d.scoreType);
    // A round is in progress — jump straight to the scorecard, not the setup picker.
    try {
      if (typeof rwzNext === 'function') { rwzNext(3); if (typeof rwzBuildScorecard === 'function') rwzBuildScorecard(window._rwzCardMode || d.scoreType || 'hbh'); }
    } catch (e) {}
  }, 220);
};
function renderResumeBox() {
  // Top "Resume your round" box removed — active-round info now lives in the Today's Challenge box.
  let host = document.getElementById('ch-resume-round'); if (host) host.remove();
  try { document.body.classList.remove('ch-has-resume'); } catch (e) {}
  try { if (window.frRefreshTodayChallenge) window.frRefreshTodayChallenge(); } catch (e) {}
}
if (!window.__rwzActiveListener) { window.__rwzActiveListener = true; document.addEventListener('input', e => { try { if (e.target && e.target.closest && e.target.closest('#r-form-golf')) rwzSaveActive(); } catch (x) {} }); }
async function renderActiveRoundsBox() {
  try {
    const strip = document.getElementById('dash-quick-strip');
    if (!window.fairwayCloud || !window.fairwayCloud.isLoggedIn || !window.fairwayCloud.isLoggedIn() || !window.fairwayCloud.listFriendsLiveRounds) return;
    let resp;
    try { resp = await window.fairwayCloud.listFriendsLiveRounds(); } catch (e) { return; }
    const all = (resp && resp.data) ? resp.data : (Array.isArray(resp) ? resp : []);
    const myId = (window.fairwayCloud.getUser && window.fairwayCloud.getUser()) ? window.fairwayCloud.getUser().id : null;
    const live = all.filter(r => r.status === 'playing' && r.user_id !== myId && (state.friends || []).some(f => f._cloudUserId === r.user_id));
    window.__liveRounds = live;
    let host = document.getElementById('ch-active-rounds'); if (host) host.remove();
    try { if (window.frRefreshTodayChallenge) window.frRefreshTodayChallenge(); } catch (e) {}
  } catch (e) {}
}
window.openLiveSpectator = function (id) {
  const row = ((window.__liveRounds || []).concat(window._feedLiveRounds || [])).find(r => r.id === id) || null;
  const fn = (state.friends || []).find(f => f._cloudUserId === row?.user_id)?.name || 'Your rival';
  // Build both-players scorecard from the live holes if present
  let sc = '';
  try {
    const players = (row && row.players) || [];
    const holes = (row && row.holes) || [];
    if (holes.length && players.length) {
      const id1 = players[0]?.id || '__me__', id2 = players[1]?.id;
      const n1 = players[0]?.name || fn, n2 = players[1]?.name || null;
      const p1 = holes.map(h => ({ par: h.par || 4, score: (h.scores && h.scores[id1] != null) ? h.scores[id1] : null }));
      const p2 = id2 ? holes.map(h => ({ par: h.par || 4, score: (h.scores && h.scores[id2] != null) ? h.scores[id2] : null })) : null;
      const f1 = p1.filter(x => x.score != null), f2 = p2 ? p2.filter(x => x.score != null) : null;
      if (f1.length && typeof feedScorecard === 'function') sc = feedScorecard({ p1: f1, p2: (f2 && f2.length ? f2 : null), n1, n2 }, true);
    }
  } catch (e) {}
  openModal(`
    <div style="text-align:center">
      <div class="section-eyebrow" style="margin-bottom:4px; color:#7ec8e3">● LIVE ROUND</div>
      <h2 style="margin:4px 0 2px">${fn}</h2>
      <p style="color:var(--muted); font-size:13px; margin:0">${row?.course_name || 'Casual round'}</p>
      ${(function(){ const rel = row && row.rel_to_par != null ? (row.rel_to_par>0?'+'+row.rel_to_par:(row.rel_to_par===0?'E':String(row.rel_to_par))) : null; const bits=[]; if(row&&row.thru) bits.push('Thru '+row.thru); else if(row&&row.current_hole) bits.push('Hole '+row.current_hole); if(rel) bits.push(rel); return bits.length?`<div style="font-family:Georgia,serif;font-size:20px;color:#7ec8e3;margin-top:8px">${bits.join(' · ')}</div>`:''; })()}
      ${sc ? `<div style="margin-top:14px;text-align:left">${sc}</div>` : `<p style="color:var(--muted-2); font-size:12px; line-height:1.55; max-width:320px; margin:12px auto 0">Live scorecard appears here as ${fn} enters scores.</p>`}
      <button class="btn btn-ghost" style="width:100%; margin-top:16px" onclick="closeModal()">Close</button>
    </div>`);
};
function renderDashboard() {
  try {
    const strip = document.getElementById('dash-quick-strip');
    if (strip) strip.innerHTML = '';
    const tail = document.getElementById('dash-clubhouse-tail');
    if (tail) tail.innerHTML = renderClubhouseInsightsPreview() + renderClubhouseTrophiesPreview();
    try { renderResumeBox(); } catch (e) {}
    try { renderActiveRoundsBox(); } catch (e) {}
    try { renderDashApprovals(); } catch (e) {}
    return;  // Skip the legacy identity hero / wfb / demo sections below
  } catch (e) { console.warn('quick-strip', e); }
  // First-time welcome — fires once per profile
  try { maybeShowClubhouseWelcome(); } catch (e) { console.warn('welcome', e); }
  renderIdentityHero();
  const rounds = state.rounds.map(buildRoundComputed);
  const golfRounds = rounds.filter(r => !r.gameKind || r.gameKind === 'golf');
  const hasRounds = golfRounds.length > 0;
  const hcp = state.settings.manualHcp != null ? state.settings.manualHcp : calcHcpIndex(rounds);

  // Toggle visibility based on whether user has rounds
  const showWhenHasData = ['dash-recent-moments','dash-stakes','dash-your-game','dash-trophy-section','dash-rivalries-panel','dash-advanced'];
  showWhenHasData.forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = hasRounds ? '' : 'none';
  });

  // Render new adaptive sections (only when relevant)
  if (hasRounds) {
    try { renderRecentMoments(golfRounds); } catch(e) { console.warn('moments', e); }
    try { renderWhatsAtStake(golfRounds); } catch(e) { console.warn('stakes', e); }
    try { renderYourGame(golfRounds); } catch(e) { console.warn('your game', e); }
  }

  // Header sub-line shows the most current rivalry context, otherwise quiet
  const activeRivalries = (state.rivalries || []).filter(rv => new Date() <= new Date(rv.endDate));
  const brandSub = $("#brand-sub");
  if (brandSub) {
    if (activeRivalries.length > 0) {
      brandSub.textContent = `${activeRivalries.length} ACTIVE ${activeRivalries.length === 1 ? 'RIVALRY' : 'RIVALRIES'}`;
    } else {
      brandSub.textContent = rounds.length > 0 ? `${rounds.length} ROUNDS PLAYED` : '';
    }
  }

  // recent table
  const tbody = $("#recent-rounds tbody");
  tbody.innerHTML = "";
  const recent = [...rounds].sort((a,b) => new Date(b.date)-new Date(a.date)).slice(0, 10);
  if (recent.length === 0) {
    tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; color:var(--muted); padding: 32px">
      <div style="width:40px;height:40px;margin:0 auto 10px;color:var(--gold)"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="11" height="17" rx="1"/><line x1="6" y1="8" x2="11" y2="8"/><line x1="6" y1="11" x2="11" y2="11"/><line x1="6" y1="14" x2="11" y2="14"/><line x1="6" y1="17" x2="9" y2="17"/><line x1="19" y1="3" x2="19" y2="21"/><path d="M 19 5 L 22 6.5 L 19 8 Z" fill="currentColor"/></svg></div>
      <div style="font-weight: 500; color: var(--text); margin-bottom: 4px">Log your first round</div>
      <div style="font-size: 12px">Every round you play with a friend can count in a rivalry season.</div>
      <button class="btn" style="margin-top: 14px" onclick="activateTab('round')">Log round</button>
    </td></tr>`;
  } else {
    recent.forEach(r => {
      // Minigame / other game row
      if (r.gameKind && r.gameKind !== 'golf') {
        const friendNames = (r.friends||[]).map(fid => frFindFriend(fid)?.name).filter(Boolean).join(", ");
        const winnerLabel = r.winner === 'me' ? '🟢' : r.winner === 'opp' ? '🔴' : r.winner === 'tie' ? '½' : '';
        tbody.innerHTML += `<tr class="row-clickable" onclick="viewRound('${r.id}')" style="cursor: pointer">
          <td>${fmtDate(r.date)}</td>
          <td colspan="3">${r.gameIcon || '🎲'} <strong>${r.gameLabel || 'Minigame'}</strong>${friendNames ? ` <span style="color: var(--muted); font-size: 11px">vs ${friendNames}</span>` : ''}</td>
          <td class="num">${winnerLabel}</td>
        </tr>`;
        return;
      }
      const c = getCourse(r.courseId);
      tbody.innerHTML += `<tr class="row-clickable" onclick="viewRound('${r.id}')" style="cursor: pointer">
        <td>${fmtDate(r.date)}</td>
        <td>${c ? c.name : "—"}</td>
        <td>${r.teeName ? `<span class="badge tee-${getTee(c,r.teeName)?.color || 'white'}">${r.teeName}</span>` : ''}</td>
        <td class="num">${r.total || "—"}</td>
        <td class="num">${r.holePoints ? ((r.winner==='me'?'W':r.winner==='opp'?'L':'½')+' '+(r.myPoints||0)+'–'+(r.oppPoints||0)) : fmt(r.differential, 1)}</td>
      </tr>`;
    });
  }

  // chart
  renderHcpChart("chart-hcp", rounds);

  // Mini active rivalries panel
  renderDashRivalriesMini();
  // Latest trophies
  renderDashTrophiesMini();
  // Memories
  renderDashMemories(rounds);
}


/* ============================================================
   RECENT MOMENTS — story feed, not a table
   ============================================================ */
function renderRecentMoments(rounds) {
  const el = document.getElementById('dash-recent-moments');
  if (!el) return;
  const moments = [];

  // Build moments from data
  const sorted = [...rounds].sort((a,b) => new Date(b.date) - new Date(a.date));
  const earned = (typeof evaluateAchievements === 'function') ? evaluateAchievements().filter(a => a.earned && a.earnedAt) : [];
  // Recent trophies (last 7)
  earned.sort((a,b) => new Date(b.earnedAt) - new Date(a.earnedAt)).slice(0, 3).forEach(a => {
    const isLegend = a.isLegend;
    moments.push({
      icon: fgIcon('trophy'),
      label: isLegend ? `${a.tierLabel} unlocked: ${a.title}` : `Trophy unlocked: ${a.title}`,
      date: a.earnedAt,
      color: a.tierColor || 'var(--gold)',
    });
  });
  // Best round of recent activity
  if (sorted.length) {
    const bestRecent = [...sorted.slice(0, 10)].sort((a,b) => (a.total||999) - (b.total||999))[0];
    const allTimeBest = Math.min(...rounds.filter(r => r.total).map(r => r.total).concat([999]));
    if (bestRecent && bestRecent.total && bestRecent.total === allTimeBest) {
      moments.push({ icon: fgIcon('streak'), label: `Best round ever: ${bestRecent.total} at ${getCourse(bestRecent.courseId)?.name || 'the course'}`, date: bestRecent.date, color: 'var(--gold)' });
    }
  }
  // New course played (most recent unique)
  const seenCourses = new Set();
  for (const r of [...rounds].sort((a,b) => new Date(a.date) - new Date(b.date))) {
    if (r.courseId && !seenCourses.has(r.courseId)) {
      seenCourses.add(r.courseId);
    }
  }
  const lastRound = sorted[0];
  if (lastRound && lastRound.courseId) {
    const playedTimes = rounds.filter(r => r.courseId === lastRound.courseId).length;
    if (playedTimes === 1) {
      moments.push({ icon: fgIcon('course'), label: `New course played: ${getCourse(lastRound.courseId)?.name || 'New course'}`, date: lastRound.date, color: 'var(--accent-bright)' });
    }
  }
  // Streak detection
  let winStreak = 0;
  for (const r of sorted) {
    if (typeof _didIWin === 'function') {
      const w = _didIWin(r);
      if (w === true) winStreak++;
      else if (w === false) break;
    }
  }
  if (winStreak >= 3) {
    moments.push({ icon: fgIcon('battle'), label: `Win streak: ${winStreak} in a row`, date: sorted[0].date, color: 'var(--tension-bright)' });
  }
  // Score trend
  if (sorted.length >= 5) {
    const recent3 = sorted.slice(0, 3).filter(r => r.differential != null);
    const prior3 = sorted.slice(3, 6).filter(r => r.differential != null);
    if (recent3.length >= 2 && prior3.length >= 2) {
      const r3 = recent3.reduce((s,r) => s + r.differential, 0) / recent3.length;
      const p3 = prior3.reduce((s,r) => s + r.differential, 0) / prior3.length;
      const delta = p3 - r3;
      if (delta > 2) {
        moments.push({ icon: fgIcon('form'), label: `Score trend improving — down ${delta.toFixed(1)} differential`, date: sorted[0].date, color: 'var(--accent-bright)' });
      }
    }
  }
  // Sort and take top 5
  moments.sort((a,b) => new Date(b.date) - new Date(a.date));
  const top = moments.slice(0, 5);

  if (!top.length) { el.innerHTML = ''; el.style.display = 'none'; return; }

  el.innerHTML = `
    <div class="dash-section-header">
      <h3>Recent Moments</h3>
      <a href="#" onclick="activateTab('rounds'); return false;" class="dash-section-link">All rounds →</a>
    </div>
    <div class="moments-feed">
      ${top.map(m => `
        <div class="moment-card">
          <div class="moment-icon" style="color:${m.color}">${m.icon}</div>
          <div class="moment-text">${m.label}</div>
          <div class="moment-date">${fmtDate(m.date)}</div>
        </div>
      `).join('')}
    </div>`;
}

/* ============================================================
   WHAT'S AT STAKE — why next round matters
   ============================================================ */
function renderWhatsAtStake(rounds) {
  const el = document.getElementById('dash-stakes');
  if (!el) return;
  const stakes = [];
  const p = activeProfile();
  const activeRivalries = (state.rivalries || []).filter(rv => new Date() <= new Date(rv.endDate));
  const rv = activeRivalries[0];

  if (rv) {
    // Rivalry-specific stakes
    const friend = (state.friends || []).find(f => f.id === rv.friendId);
    const stats = (typeof computeRivalryStats === 'function') ? computeRivalryStats(rv) : { myScore: 0, theirScore: 0 };
    const fname = friend?.name || 'your rival';
    const myLeading = stats.myScore > stats.theirScore;
    const tie = stats.myScore === stats.theirScore;
    let winStreak = 0, lossStreak = 0;
    const rvRounds = rounds.filter(r => frRoundHasFriend(r, rv.friendId)).sort((a,b) => new Date(b.date) - new Date(a.date));
    for (const r of rvRounds) {
      const w = (typeof _didIWin === 'function') ? _didIWin(r) : null;
      if (w === null) break;
      if (w === true && lossStreak === 0) winStreak++;
      else if (w === false && winStreak === 0) lossStreak++;
      else break;
    }
    if (winStreak >= 2) stakes.push({ icon: fgIcon('streak'), text: `Extend your ${winStreak}-round win streak to ${winStreak + 1}` });
    if (lossStreak >= 2) stakes.push({ icon: fgIcon('battle'), text: `Stop ${fname}'s ${lossStreak}-round streak` });
    if (myLeading) stakes.push({ icon: fgIcon('crown'), text: `Extend your season lead — currently ${stats.myScore}–${stats.theirScore}` });
    else if (tie) stakes.push({ icon: fgIcon('milestone'), text: `Break the deadlock — currently ${stats.myScore} all` });
    else stakes.push({ icon: fgIcon('form'), text: `Cut the gap — currently down ${stats.theirScore}–${stats.myScore}` });
  } else {
    // Solo stakes
    const scores = rounds.filter(r => r.total).map(r => r.total);
    if (scores.length) {
      const best = Math.min(...scores);
      const ladder = [100, 95, 90, 85, 80, 75];
      for (const target of ladder) {
        if (best >= target) {
          stakes.push({ icon: fgIcon('milestone'), text: `Get ${best - target + 1} stroke${best - target + 1 === 1 ? '' : 's'} closer to breaking ${target}` });
          break;
        }
      }
    }
    const identity = (typeof computePlayerIdentity === 'function') ? computePlayerIdentity() : null;
    if (identity && !identity.archetype && identity.roundsNeeded > 0) {
      stakes.push({ icon: fgIcon('identity'), text: `Reveal your player identity — ${identity.roundsNeeded} round${identity.roundsNeeded === 1 ? '' : 's'} away` });
    }
    if (rounds.length >= 1) {
      stakes.push({ icon: fgIcon('form'), text: `Build your form trend — log another round to extend it` });
    }
    stakes.push({ icon: fgIcon('trophy'), text: `Unlock new trophies — every round can move your legacy forward` });
  }

  if (!stakes.length) { el.innerHTML = ''; el.style.display = 'none'; return; }

  el.innerHTML = `
    <div class="stakes-card">
      <div class="stakes-tag">WHAT'S AT STAKE</div>
      <div class="stakes-title">${rv ? "Why next round matters" : "Your next round can"}</div>
      <ul class="stakes-list">
        ${stakes.slice(0, 4).map(s => `<li>${s.icon}<span>${s.text}</span></li>`).join('')}
      </ul>
    </div>`;
}

/* ============================================================
   YOUR GAME — simple stats cards
   ============================================================ */
function renderYourGame(rounds) {
  const el = document.getElementById('dash-your-game');
  if (!el) return;
  const p = activeProfile();
  const scores = rounds.filter(r => r.total).map(r => r.total);
  const bestRound = scores.length ? Math.min(...scores) : null;
  const courseRoundCounts = {};
  rounds.forEach(r => { if (r.courseId) courseRoundCounts[r.courseId] = (courseRoundCounts[r.courseId]||0) + 1; });
  const bestCourseId = Object.entries(courseRoundCounts).sort((a,b) => b[1]-a[1])[0]?.[0];
  const bestCourseName = bestCourseId ? (getCourse(bestCourseId)?.name || '—') : '—';
  // Form
  const sorted = [...rounds].filter(r => r.differential != null).sort((a,b) => new Date(b.date) - new Date(a.date));
  let formLabel = '—';
  if (sorted.length >= 4) {
    const r3 = sorted.slice(0, 3).reduce((s,r) => s + r.differential, 0) / Math.min(3, sorted.length);
    const p3 = sorted.slice(3, 6).reduce((s,r) => s + r.differential, 0) / Math.min(3, sorted.length - 3 || 1);
    if (p3 - r3 > 1.5) formLabel = 'Improving';
    else if (r3 - p3 > 1.5) formLabel = 'Fading';
    else formLabel = 'Steady';
  } else if (rounds.length > 0) formLabel = 'Building';
  // Next goal
  let nextGoal = '—';
  if (bestRound) {
    const ladder = [100, 95, 90, 85, 80, 75];
    for (const t of ladder) { if (bestRound >= t) { nextGoal = `Break ${t}`; break; } }
  }
  const achievements = (typeof evaluateAchievements === 'function') ? evaluateAchievements() : [];
  const trophiesEarned = achievements.filter(a => a.earned).length;
  const trophiesTotal = achievements.length || 1;

  el.innerHTML = `
    <div class="dash-section-header">
      <h3>Your Game</h3>
      <a href="#" onclick="activateTab('stats'); return false;" class="dash-section-link">Full stats →</a>
    </div>
    <div class="your-game-grid">
      <div class="yg-card"><div class="yg-label">BEST ROUND</div><div class="yg-value">${bestRound ?? '—'}</div></div>
      <div class="yg-card"><div class="yg-label">BEST COURSE</div><div class="yg-value-text">${bestCourseName}</div></div>
      <div class="yg-card"><div class="yg-label">CURRENT FORM</div><div class="yg-value-text">${formLabel}</div></div>
      <div class="yg-card"><div class="yg-label">NEXT GOAL</div><div class="yg-value-text">${nextGoal}</div></div>
      <div class="yg-card"><div class="yg-label">ROUNDS LOGGED</div><div class="yg-value">${rounds.length}</div></div>
      <div class="yg-card"><div class="yg-label">TROPHIES</div><div class="yg-value">${trophiesEarned} <span class="yg-value-suffix">/ ${trophiesTotal}</span></div></div>
    </div>`;
}

function renderDashMemories(rounds) {
  const panel = $("#dash-memories-panel");
  const el = $("#dash-memories");
  if (!panel || !el) return;

  const today = new Date();
  const memories = [];

  // "X years ago today"
  rounds.forEach(r => {
    const d = new Date(r.date);
    if (d.toString() === 'Invalid Date') return;
    const yearsAgo = today.getFullYear() - d.getFullYear();
    if (yearsAgo >= 1 && d.getMonth() === today.getMonth() && d.getDate() === today.getDate()) {
      const c = getCourse(r.courseId);
      memories.push({
        type: 'years_ago',
        icon: '📅',
        title: `${yearsAgo} ${yearsAgo === 1 ? 'år' : 'år'} siden i dag`,
        body: `Du spilte ${c?.name || 'en runde'}${r.total ? ` med score ${r.total}` : ''}`,
        date: r.date,
        importance: 80 + yearsAgo,
      });
    }
  });

  // First time you played a course
  const courseFirstPlay = {};
  rounds.forEach(r => {
    if (!courseFirstPlay[r.courseId] || new Date(r.date) < new Date(courseFirstPlay[r.courseId].date)) {
      courseFirstPlay[r.courseId] = r;
    }
  });
  Object.values(courseFirstPlay).forEach(r => {
    const d = new Date(r.date);
    if (d.toString() === 'Invalid Date') return;
    if (d.getMonth() === today.getMonth() && d.getDate() === today.getDate() && today.getFullYear() - d.getFullYear() >= 1) {
      const c = getCourse(r.courseId);
      memories.push({
        type: 'first_play',
        icon: '🆕',
        title: `Første runde på ${c?.name || 'denne banen'}`,
        body: `${fmtDate(r.date)}`,
        date: r.date,
        importance: 75,
      });
    }
  });

  // Personal best - lowest score
  const scoredRounds = rounds.filter(r => r.total);
  if (scoredRounds.length >= 5) {
    const sortedByScore = [...scoredRounds].sort((a,b) => a.total - b.total);
    const best = sortedByScore[0];
    const d = new Date(best.date);
    if (d.toString() !== 'Invalid Date' && d.getMonth() === today.getMonth() && d.getDate() === today.getDate()) {
      const c = getCourse(best.courseId);
      memories.push({
        type: 'pb',
        icon: '🏆',
        title: 'Personlig rekord på denne datoen',
        body: `${best.total} på ${c?.name || 'ukjent bane'}`,
        date: best.date,
        importance: 90,
      });
    }
  }

  // First-ever round
  if (rounds.length >= 5) {
    const sorted = [...rounds].sort((a,b) => new Date(a.date) - new Date(b.date));
    const first = sorted[0];
    const d = new Date(first.date);
    if (d.toString() !== 'Invalid Date' && d.getMonth() === today.getMonth() && d.getDate() === today.getDate()) {
      memories.push({
        type: 'first_ever',
        icon: '🌅',
        title: 'Din aller første runde',
        body: `Logget ${fmtDate(first.date)} - der det hele begynte`,
        date: first.date,
        importance: 95,
      });
    }
  }

  // First win against any friend
  // (Best looking back over rivalry data)

  if (memories.length === 0) {
    panel.style.display = 'none';
    return;
  }
  panel.style.display = '';
  memories.sort((a,b) => b.importance - a.importance);
  el.innerHTML = memories.slice(0, 5).map(m => `
    <div class="memory-card">
      <div class="memory-icon">${m.icon}</div>
      <div class="memory-text">
        <div class="memory-title">${m.title}</div>
        <div class="memory-body">${m.body}</div>
      </div>
    </div>
  `).join('');
}

function renderIdentityHero() {
  const hero = document.getElementById("identity-hero");
  if (!hero) return;
  const p = activeProfile();
  if (!p) return;

  const golfRounds = (p.rounds || []).filter(r => !r.gameKind || r.gameKind === 'golf');
  const activeRivalries = (p.rivalries || []).filter(rv => new Date() <= new Date(rv.endDate));
  const hasRounds = golfRounds.length > 0;
  const hasActiveRivalry = activeRivalries.length > 0;

  if (!hasRounds) { renderHeroModeA(hero, p); return; }
  if (hasActiveRivalry) { renderHeroModeC(hero, p, golfRounds, activeRivalries[0]); return; }
  renderHeroModeB(hero, p, golfRounds);
}

function renderBreakscore(rounds) {
  const totals = (rounds || []).map(r => r && r.total).filter(t => t != null && t > 40);
  const n = totals.length;
  const thresholds = [100, 90, 80, 70];
  const rows = thresholds.map(T => {
    const cnt = totals.filter(t => t < T).length;
    const pct = n ? Math.round((cnt / n) * 100) : 0;
    return `<div class="bs-row"><span class="bs-lbl">Under ${T}</span><span class="bs-bar"><span class="bs-fill" style="width:${Math.max(cnt>0?6:0,pct)}%"></span></span><span class="bs-cnt">${cnt}</span></div>`;
  }).join('');
  return `<div class="breakscore"><div class="bs-title">BREAKSCORE</div>${rows}${n ? '' : '<div class="bs-empty">Log 18-hole rounds to build your breakscore.</div>'}</div>`;
}
