function renderHeroModeB(hero, p, rounds) {
  const identity = (typeof computePlayerIdentity === 'function') ? computePlayerIdentity() : null;
  const achievements = (typeof evaluateAchievements === 'function') ? evaluateAchievements() : [];
  const trophiesEarned = achievements.filter(a => a.earned).length;
  const trophiesTotal = achievements.length || 1;
  const milestone = computeNextMilestone(p, rounds, identity, achievements);

  const sorted = [...rounds].map(buildRoundComputed).filter(r => r.differential != null).sort((a,b) => new Date(b.date) - new Date(a.date));
  const recent5 = sorted.slice(0,5), prior5 = sorted.slice(5,10);
  let formLabel = '—', formDesc = '', formIcon = '📈';
  if (recent5.length >= 3 && prior5.length >= 3) {
    const ra = recent5.reduce((s,r) => s + r.differential, 0) / recent5.length;
    const pa = prior5.reduce((s,r) => s + r.differential, 0) / prior5.length;
    const delta = pa - ra;
    if (delta > 1.5) { formLabel='Improving'; formIcon='🔥'; formDesc=`Down ${delta.toFixed(1)} differential over last 5 rounds.`; }
    else if (delta < -1.5) { formLabel='Fading'; formIcon='📉'; formDesc=`Up ${Math.abs(delta).toFixed(1)} differential vs prior 5.`; }
    else { formLabel='Steady'; formIcon='🎚'; formDesc='Form is holding round to round.'; }
  } else if (rounds.length > 0) {
    formLabel='Just getting started'; formIcon='🌱';
    formDesc=`${rounds.length} round${rounds.length === 1 ? '' : 's'} logged — log a few more to see trends.`;
  }

  let storyHeadline;
  if (rounds.length === 1) storyHeadline = "Your first round is on the board.";
  else if (rounds.length < 5) storyHeadline = `You're building form. ${rounds.length} rounds logged.`;
  else if (identity?.archetype) storyHeadline = `${identity.archetype.title}. ${trophiesEarned} of ${trophiesTotal} trophies earned.`;
  else storyHeadline = `${rounds.length} rounds in. Player identity coming soon.`;

  hero.innerHTML = `
    <div class="story-hero modeB">
      <div class="story-tag">CURRENT STORY</div>
      <h1 class="story-title">${storyHeadline}</h1>
      ${milestone ? `<div class="story-milestone"><strong>${milestone.title}:</strong> ${milestone.desc}</div>` : ''}
      <div class="story-cta-row">
        <button class="story-cta primary" onclick="activateTab('round')">Log a round →</button>
        <button class="story-cta ghost" onclick="editFriend()">Invite a rival</button>
      </div>
      <div class="story-grid-3">
        <div class="story-card bs-card">${renderBreakscore(rounds)}</div>
        <div class="story-card">
          <div class="sc-label">PLAYER IDENTITY</div>
          ${identity?.archetype ? `<div class="sc-value-row"><span class="sc-icon-inline">${identity.archetype.icon}</span><span class="sc-value">${identity.archetype.title}</span></div><div class="sc-desc">${identity.archetype.tagline}</div>` : `<div class="sc-value-row">${fgIcon("identity", {silver: true})}<span class="sc-value muted">In progress</span></div><div class="sc-desc">${identity?.roundsNeeded ? `Log ${identity.roundsNeeded} more round${identity.roundsNeeded===1?'':'s'} to discover your type.` : 'Log a few more rounds to lock in your archetype.'}</div>`}
        </div>
        <div class="story-card">
          <div class="sc-label">TROPHY PROGRESS</div>
          <div class="sc-value-row">${fgIcon("trophy")}<span class="sc-value">${trophiesEarned} <span class="sc-value-suffix">/ ${trophiesTotal}</span></span></div>
          <div class="sc-progress-bar"><div style="width: ${Math.round((trophiesEarned/trophiesTotal)*100)}%"></div></div>
        </div>
      </div>
    </div>`;
}

function renderHeroModeC(hero, p, rounds, rv) {
  const me = p.name || 'You';
  const friend = (state.friends || []).find(f => f.id === rv.friendId);
  const fname = friend?.name || 'Rival';
  const stats = computeRivalryStats(rv);
  const daysLeft = Math.max(0, Math.ceil((new Date(rv.endDate) - new Date()) / 86400000));
  const myLeading = stats.myScore > stats.theirScore;
  const tie = stats.myScore === stats.theirScore;

  const rvRounds = rounds.filter(r => frRoundHasFriend(r, rv.friendId)).sort((a,b) => new Date(b.date) - new Date(a.date));
  const last5 = rvRounds.slice(0,5).reverse().map(r => _didIWin(r) === true ? 'W' : _didIWin(r) === false ? 'L' : '—');
  let streakCount = 0; let streakType = null;
  for (const r of rvRounds) {
    const w = _didIWin(r);
    if (w === null) break;
    const t = w ? 'W' : 'L';
    if (streakType === null) { streakType = t; streakCount = 1; }
    else if (t === streakType) streakCount++;
    else break;
  }

  let storyLine;
  if (stats.rounds === 0) storyLine = 'Season has started. First round counts.';
  else if (tie) storyLine = `Locked in at ${stats.myScore}-all. ${daysLeft} days to break the deadlock.`;
  else if (myLeading) storyLine = streakType==='W' && streakCount>=3 ? `You've won ${streakCount} in a row against ${fname}.` : `You lead ${fname} ${stats.myScore}–${stats.theirScore}. ${daysLeft} days left.`;
  else storyLine = streakType==='L' && streakCount>=3 ? `${fname} has won ${streakCount} straight. Time to flip it.` : `Down ${stats.theirScore}–${stats.myScore} to ${fname}. ${daysLeft} days to turn it.`;

  hero.innerHTML = `
    <div class="story-hero modeC">
      <div class="story-tag">CURRENT RIVALRY · ${daysLeft} DAYS LEFT</div>
      <h1 class="story-title rivalry-title">
        <span class="${myLeading ? 'leading' : ''}">${me}</span>
        <span class="versus">vs</span>
        <span class="${!myLeading && !tie ? 'leading' : ''}">${fname}</span>
      </h1>
      <div class="rivalry-score-row">
        <div class="rivalry-score ${myLeading ? 'win' : tie ? 'tie' : 'loss'}">${stats.myScore}</div>
        <div class="rivalry-score-sep">—</div>
        <div class="rivalry-score ${!myLeading && !tie ? 'win' : tie ? 'tie' : 'loss'}">${stats.theirScore}</div>
      </div>
      <p class="story-body">${storyLine}</p>
      <div class="story-cta-row">
        <button class="story-cta primary" onclick="activateTab('round')">Log next round →</button>
        <button class="story-cta ghost" onclick="activateTab('rivalry'); setTimeout(()=>showRivalryDetail('${rv.id}'), 100)">View rivalry</button>
      </div>
      <div class="story-grid-2">
        <div class="story-card">
          <div class="sc-label">CURRENT FORM</div>
          <div class="form-streak-row">${last5.length ? last5.map(t => `<span class="form-pill ${t==='W'?'win':t==='L'?'loss':''}">${t}</span>`).join('') : '<span style="color:var(--muted-2)">No rounds yet</span>'}</div>
          <div class="sc-desc">${streakType && streakCount>=2 ? `${streakCount} ${streakType==='W'?'win':'loss'} streak${streakCount>=3?' 🔥':''}` : 'Last 5 rounds shown.'}</div>
        </div>
        <div class="story-card">
          <div class="sc-label">WHAT'S AT STAKE</div>
          <div class="sc-desc" style="margin-top:8px">${myLeading ? `Win and extend your lead.<br>Lose and ${fname} cuts the gap to ${stats.theirScore + 1}–${stats.myScore}.` : tie ? `Winner takes control of the season.` : `Win and cut the gap to ${stats.theirScore}–${stats.myScore + 1}.<br>Lose and ${fname} pulls further away.`}</div>
        </div>
      </div>
    </div>`;
}

function computeNextMilestone(profile, rounds, identity, achievements) {
  if (identity && !identity.archetype && identity.roundsNeeded > 0) {
    return { title: `${identity.roundsNeeded} round${identity.roundsNeeded===1?'':'s'} away`, desc: 'until your player identity is revealed.' };
  }
  const scores = rounds.filter(r => r.total).map(r => r.total);
  if (scores.length) {
    const best = Math.min(...scores);
    for (const target of [100, 95, 90, 85, 80, 75, 72]) {
      if (best >= target) return { title: `${best - target + 1} stroke${best - target + 1 === 1 ? '' : 's'} from breaking ${target}`, desc: 'on your best round so far.' };
    }
  }
  if (achievements?.length) {
    const close = achievements.filter(a => !a.earned && a.currentValue != null && a.threshold).map(a => ({ach: a, gap: a.threshold - a.currentValue})).filter(x => x.gap > 0 && x.gap <= 5).sort((x,y) => x.gap - y.gap)[0];
    if (close) return { title: `${close.gap} away from ${close.ach.title}`, desc: close.ach.desc };
  }
  return null;
}

