function renderDashRivalriesMini() {
  const el = $("#dash-rivalries-mini");
  if (!el) return;
  const active = (state.rivalries || []).filter(rv => new Date() <= new Date(rv.endDate));
  if (active.length === 0) {
    el.innerHTML = `
      <div style="padding: 20px 0; color: var(--muted); font-size: 13px; line-height: 1.6; text-align: center">
        <div style="margin-bottom: 12px">No active rivalries</div>
        <button class="btn btn-ghost btn-small" onclick="activateTab('rivalry')">View all</button>
      </div>
    `;
    return;
  }
  const me = activeProfile()?.name || "You";
  el.innerHTML = active.map(rv => {
    const stats = computeRivalryStats(rv);
    const friend = state.friends.find(f => f.id === rv.friendId);
    const myLeading = stats.myScore > stats.theirScore;
    const tie = stats.myScore === stats.theirScore;
    const daysLeft = Math.max(0, Math.ceil((new Date(rv.endDate) - new Date()) / 86400000));
    return `
      <div class="rivalry-mini" onclick="activateTab('rivalry'); setTimeout(()=>showRivalryDetail('${rv.id}'), 200)">
        <div>
          <div class="mini-meta">${daysLeft} days left · ${stats.rounds} rounds</div>
          <div class="mini-name">${me} vs ${friend?.name || '—'}</div>
        </div>
        <div class="mini-score">
          <span class="${tie ? '' : (myLeading ? 'lead' : 'lose')}">${stats.myScore}</span>
          <span class="sep">—</span>
          <span class="${tie ? '' : (!myLeading ? 'lead' : 'lose')}">${stats.theirScore}</span>
        </div>
      </div>
    `;
  }).join('');
}

function renderDashTrophiesMini() {
  const el = $("#dash-trophies-mini");
  if (!el) return;
  const achievements = evaluateAchievements()
    .filter(a => a.earned && a.earnedAt)
    .sort((a, b) => new Date(b.earnedAt) - new Date(a.earnedAt))
    .slice(0, 4);
  if (achievements.length === 0) {
    el.innerHTML = `
      <div style="padding: 20px 0; color: var(--muted); font-size: 13px; line-height: 1.6; text-align: center">
        <div style="margin-bottom: 12px">Trophies unlock as you play</div>
        <button class="btn btn-ghost btn-small" onclick="activateTab('trophies')">View all</button>
      </div>
    `;
    return;
  }
  el.innerHTML = achievements.map(a => `
    <div style="display: flex; gap: 14px; align-items: center; padding: 12px 14px; border-bottom: 1px solid var(--border-subtle)">
      <div style="font-size: 18px; color: var(--gold); flex-shrink: 0">◆</div>
      <div style="flex: 1; min-width: 0">
        <div style="font-size: 13px; font-weight: 500; color: var(--text)">${a.title}</div>
        <div style="font-size: 11px; color: var(--muted); margin-top: 2px">${a.desc}</div>
      </div>
      <div style="font-size: 9px; color: var(--gold); letter-spacing: 0.15em; text-transform: uppercase">${fmtDate(a.earnedAt.slice(0,10))}</div>
    </div>
  `).join('');
}

let hcpCharts = {};
function renderHcpChart(canvasId, rounds) {
  const sorted = [...rounds].filter(r => r.differential != null).sort((a,b) => new Date(a.date) - new Date(b.date));
  const labels = sorted.map(r => fmtDate(r.date));
  const diffs = sorted.map(r => r.differential);
  // running HCP after each round
  const runningHcp = [];
  for (let i=0; i<sorted.length; i++) {
    const upTo = sorted.slice(0, i+1);
    runningHcp.push(calcHcpIndex(upTo));
  }
  if (hcpCharts[canvasId]) hcpCharts[canvasId].destroy();
  const ctx = document.getElementById(canvasId);
  if (!ctx) return;
  hcpCharts[canvasId] = new Chart(ctx, {
    type: 'line',
    data: {
      labels,
      datasets: [
        { label: 'Differential', data: diffs, borderColor: '#8fa599', backgroundColor: 'rgba(143,165,153,0.1)', tension: 0.2, pointRadius: 3 },
        { label: 'HCP Index', data: runningHcp, borderColor: '#4ade80', backgroundColor: 'rgba(74,222,128,0.15)', tension: 0.2, pointRadius: 2, borderWidth: 2.5, fill: false },
      ]
    },
    options: {
      maintainAspectRatio: false,
      plugins: { legend: { labels: { color: '#e6f0ea' } } },
      scales: {
        x: { ticks: { color: '#8fa599', maxTicksLimit: 8 }, grid: { color: '#2a3c32' } },
        y: { ticks: { color: '#8fa599' }, grid: { color: '#2a3c32' }, reverse: false }
      }
    }
  });
}

