let roundFormState = { editId: null, holes: [], scoreType: 'total', selectedFriends: [], gameKind: null, gameSubtype: null };
window.roundFormState = roundFormState; // keep module + window as ONE object (save reads module, wizard writes window)

function renderRoundForm() {
  // Reset to game-kind picker when entering tab fresh (unless we're editing)
  if (!roundFormState.editId) {
    showRoundKindPicker();
  }
  if (!$("#r-date").value) $("#r-date").value = todayISO();
  { const _tt = $("#r-time-of-day"); if (_tt && !_tt.value) _tt.value = new Date().toTimeString().slice(0,5); }
  // hidden select kept for state sync
  const csel = $("#r-course");
  if (csel) {
    csel.innerHTML = '<option value="">Velg bane...</option>' + state.courses.map(c =>
      `<option value="${c.id}">${c.name}</option>`).join('');
  }
  renderFriendPills();
  applyScoreType(roundFormState.scoreType);
}

function showRoundKindPicker() {
  ['r-kind-panel','r-form-golf','r-form-golfmini','r-form-minigame','r-form-other'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = id === 'r-kind-panel' ? '' : 'none';
  });
  roundFormState.gameKind = null;
  roundFormState.gameSubtype = null;
  // Reset the Tee Off card selection back to the default (Golf Round)
  try {
    window._teeoffKind = 'golf';
    document.querySelectorAll('.teeoff-card').forEach(c => c.classList.toggle('sel', c.dataset.kind === 'golf'));
  } catch (e) {}
}

window.resetRoundKind = function() {
  roundFormState.gameKind = null;
  roundFormState.gameSubtype = null;
  showRoundKindPicker();
};

function showRoundForm(kind) {
  roundFormState.gameKind = kind;
  ['r-kind-panel','r-form-golf','r-form-golfmini','r-form-minigame','r-form-other'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });
  // 'simulator' uses the same golf form, just with weather hidden
  const targetId = (kind === 'golf' || kind === 'simulator' || kind === 'teamplay') ? 'r-form-golf'
    : kind === 'golfmini' ? 'r-form-golfmini'
    : kind === 'minigame' ? 'r-form-minigame'
    : 'r-form-other';
  const el = document.getElementById(targetId);
  if (el) el.style.display = '';
  // Toggle weather row + heading for simulator
  const golfFormEl = document.getElementById('r-form-golf');
  if (golfFormEl) {
    const isSim = kind === 'simulator';
    const heading = golfFormEl.querySelector('h2');
    if (heading) heading.textContent = isSim ? 'Log simulator round' : 'Log golf round';
    // Hide the weather/temp/wind row when simulator
    const wxRow = document.getElementById('r-weather-row');
    if (wxRow) wxRow.style.display = isSim ? 'none' : '';
    const wxBtn = document.getElementById('r-weather-autofill');
    if (wxBtn) wxBtn.style.display = isSim ? 'none' : '';
  }
  // Initialize the right sub-form
  if (kind === 'golf' || kind === 'simulator' || kind === 'teamplay') prefillFromLastRound();
  else if (kind === 'golfmini') renderMinigameCatalog('golfmini');
  else if (kind === 'minigame') renderMinigameCatalog('minigame');
  else if (kind === 'other') initOtherForm();
  if (kind === 'teamplay') setupTeamPlayForm(); else teardownTeamPlayForm();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function prefillFromLastRound() {
  if (roundFormState.editId) return; // editing an existing round, don't pre-fill
  const sorted = [...(state.rounds || [])]
    .filter(r => (!r.gameKind || r.gameKind === 'golf') && r.courseId && r.teeName)
    .sort((a, b) => new Date(b.date) - new Date(a.date));
  if (sorted.length === 0) return;
  const last = sorted[0];
  const c = getCourse(last.courseId);
  if (!c) return;
  // Only pre-fill if user hasn't typed anything yet
  const courseSearch = $("#r-course-search");
  if (false && courseSearch && !courseSearch.value) {
    courseSearch.value = c.name;
    const csel = $("#r-course");
    if (csel) {
      if (!csel.querySelector(`option[value="${c.id}"]`)) {
        csel.innerHTML += `<option value="${c.id}">${c.name}</option>`;
      }
      csel.value = c.id;
      csel.dispatchEvent(new Event('change'));
      // After the tee dropdown is populated, restore the last tee
      setTimeout(() => {
        const teeSel = $("#r-tee");
        if (teeSel && teeSel.querySelector(`option[value="${last.teeName}"]`)) {
          teeSel.value = last.teeName;
        }
      }, 0);
    }
  }
  // Pre-fill friends if same set on last 3+ rounds
  if (!roundFormState.selectedFriends?.length && last.friends?.length) {
    const recentFriendSets = sorted.slice(0, 3).map(r => (r.friends || []).slice().sort().join(','));
    if (recentFriendSets.length >= 2 && recentFriendSets[0] === recentFriendSets[1]) {
      // (#69) No auto pre-selecting a rival — user adds rival explicitly via Add Rival.
      /* roundFormState.selectedFriends = [...last.friends]; renderFriendPills(); */
    }
  }
}

// Wire up the game-kind picker cards
document.querySelectorAll('.gk-card').forEach(card => {
  card.addEventListener('click', () => showRoundForm(card.dataset.kind));
});

