$("#r-date")?.addEventListener('change', updateRivalrySection);

/* Course typeahead - searches local first, then cloud (if logged in).
   Never overwrites or locks the input. */
let _courseSearchTimer = null;
function getRecentCourseIds(limit = 3) {
  const ids = [];
  const seen = new Set();
  const sorted = [...(state.rounds || [])]
    .filter(r => r.courseId)
    .sort((a, b) => new Date(b.date) - new Date(a.date));
  for (const r of sorted) {
    if (seen.has(r.courseId)) continue;
    seen.add(r.courseId);
    ids.push(r.courseId);
    if (ids.length >= limit) break;
  }
  return ids;
}

async function renderCourseSuggestions(query) {
  const box = $("#r-course-suggestions");
  if (!box) return;
  // Empty query: show recent courses (if any)
  if (!query || query.length < 1) {
    const recentIds = getRecentCourseIds(3);
    if (recentIds.length === 0) {
      box.classList.remove("open"); box.innerHTML = ""; return;
    }
    const recent = recentIds.map(id => getCourse(id)).filter(Boolean).map(c => ({ course: c, fromCloud: false }));
    renderSuggestionList(box, recent, '', false, /*recentLabel*/ true);
    return;
  }
  const q = query.toLowerCase();
  const norm = sx => (sx || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]+/g, " ").replace(/\b(golf|club|klubb|gk|gc|cc|the|course|banen?)\b/g, "").replace(/\s+/g, " ").trim();
  const dkey = c => norm(c.name) + "|" + (c.city || "").toLowerCase();

  // 1. Local matches (instant feedback)
  const localMatches = state.courses.filter(c => {
    const name = (c.name || "").toLowerCase();
    return name.includes(q) || (c.country || "").toLowerCase().includes(q) || (c.city || "").toLowerCase().includes(q);
  }).sort((a, b) => {
    const aStart = a.name.toLowerCase().startsWith(q) ? 0 : 1;
    const bStart = b.name.toLowerCase().startsWith(q) ? 0 : 1;
    if (aStart !== bStart) return aStart - bStart;
    return a.name.localeCompare(b.name);
  }).slice(0, 6);

  renderSuggestionList(box, localMatches.map(c => ({ course: c, fromCloud: false })), query, /*searching*/ false);

  // 2. Cloud search (Supabase — now the full catalogue). Cloud is preferred; on
  //    duplicates the cloud course wins. No "cloud" label — they look like any course.
  if (window.fairwayCloud?.isLoggedIn() && query.length >= 2) {
    if (_courseSearchTimer) clearTimeout(_courseSearchTimer);
    _courseSearchTimer = setTimeout(async () => {
      renderSuggestionList(box, localMatches.map(c => ({ course: c, fromCloud: false })), query, /*searching*/ true);
      const cloudResults = await searchCloudCourses(query, 12);
      const seen = new Set();
      const merged = [];
      for (const c of cloudResults) {       // cloud first = preferred
        const k = dkey(c);
        if (seen.has(k) || seen.has(c.id)) continue;
        seen.add(k); seen.add(c.id);
        merged.push({ course: c, fromCloud: true });
      }
      for (const c of localMatches) {        // local only if not a cloud duplicate
        const k = dkey(c);
        if (seen.has(k) || seen.has(c.id)) continue;
        seen.add(k); seen.add(c.id);
        merged.push({ course: c, fromCloud: false });
      }
      renderSuggestionList(box, merged.slice(0, 12), query, /*searching*/ false);
    }, 300);
  }
}

function renderSuggestionList(box, items, query, searching, recentLabel = false) {
  if (items.length === 0 && !searching) {
    box.innerHTML = `<div class="course-suggestion-item" style="cursor:default; color:var(--muted)">No matches. <a class="small-link" onclick="quickAddCourse()">+ Add new course</a></div>`;
  } else {
    box.innerHTML = (recentLabel ? `<div style="padding: 6px 14px; font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase; color: var(--gold); border-bottom: 1px solid var(--border)">Recently played</div>` : '') +
      items.map(it => suggestionRow(it.course, it.fromCloud)).join('') +
      (searching ? `<div style="padding: 8px 14px; font-size: 11px; color: var(--muted); font-style: italic">Searching\u2026</div>` : '');
    const cloudMap = {};
    items.forEach(it => { if (it.fromCloud && it.course && it.course.id) cloudMap[it.course.id] = it.course; });
    box.querySelectorAll('.course-suggestion-item[data-id]').forEach(item => {
      item.addEventListener('mousedown', e => {
        e.preventDefault();
        const id = item.dataset.id;
        let c = getCourse(id);
        if (!c && cloudMap[id]) c = adoptCloudCourse(cloudMap[id]);
        if (!c) return;
        $("#r-course-search").value = c.name;
        $("#r-course").value = c.id;
        const csel = $("#r-course");
        if (csel && !csel.querySelector(`option[value="${c.id}"]`)) {
          csel.innerHTML += `<option value="${c.id}">${c.name}</option>`;
        }
        $("#r-course").dispatchEvent(new Event('change'));
        box.classList.remove("open");
      });
    });
  }
  box.classList.add("open");
}

function suggestionRow(c, isCloud) {
  return `
    <div class="course-suggestion-item" data-id="${c.id}" data-cloud="${isCloud?'1':'0'}">
      <span class="csi-name">${c.name}</span>
      <span class="csi-meta">${[c.city, c.country].filter(Boolean).join(', ') || ''}</span>
    </div>
  `;
}

$("#r-course-search")?.addEventListener("input", e => {
  renderCourseSuggestions(e.target.value);
});
$("#r-course-search")?.addEventListener("focus", e => {
  // Always trigger — empty value shows recent courses
  renderCourseSuggestions(e.target.value);
});
$("#r-course-search")?.addEventListener("blur", () => {
  // Delay so click on suggestion lands first
  setTimeout(() => $("#r-course-suggestions")?.classList.remove("open"), 150);
});

$("#r-course").addEventListener("change", e => {
  const c = getCourse(e.target.value);
  const tsel = $("#r-tee");
  if (c) {
    if ($("#r-course-search") && !$("#r-course-search").value) {
      $("#r-course-search").value = c.name;
    }
    const realTees = (c.tees || []).filter(t => Number(t.cr) > 0 && Number(t.slope) > 0);
    if (realTees.length) {
      tsel.innerHTML = '<option value="">Select tee...</option>' + realTees.map(t => `<option value="${t.name}">${t.name} (CR ${t.cr} / Slope ${t.slope})</option>`).join('');
    } else {
      tsel.innerHTML = '<option value="">No tee \u00b7 play without handicap</option>';
    }
    buildHolesGrid(c);
    if (roundFormState.scoreType === 'hbh') startHbhWizard(c);
    updateCourseDataNote(c);
  } else {
    tsel.innerHTML = '<option value="">Select tee...</option>';
    updateCourseDataNote(null);
  }
});

/* ---- Course-data completeness: surface missing CR / par; allow manual entry or play-without-HC ---- */
function courseBestTee(course) { return (course && Array.isArray(course.tees) ? course.tees : []).find(t => Number(t.cr) > 0 && Number(t.slope) > 0) || null; }
function courseHasCR(course) { return !!courseBestTee(course); }
function coursePar(course) {
  if (!course) return null;
  if (course.par) return course.par;
  if (Array.isArray(course.holesData) && course.holesData.length) { const s = course.holesData.reduce((a, h) => a + (h && h.par ? h.par : 0), 0); if (s > 0) return s; }
  const t = (course.tees || []).find(t => t.par); return t ? t.par : null;
}
function updateCourseDataNote(course) {
  const note = document.getElementById('r-course-data-note');
  if (!note) return;
  if (!course) { note.style.display = 'none'; note.innerHTML = ''; return; }
  const hasCR = courseHasCR(course);
  const par = coursePar(course);
  let html = '';
  if (!par) {
    html += '<div class="cdn-row"><span class="cdn-warn">No par for this course.</span>' +
      '<span class="cdn-hint">Set par for each hole on the scorecard below &mdash; it is saved for this course.</span></div>';
  }
  if (!hasCR) {
    html += '<div class="cdn-row"><span class="cdn-warn">No course rating &mdash; needed to play with handicap.</span>' +
      '<span class="cdn-controls">CR <input type="number" id="cdn-cr" step="0.1" placeholder="70.5"> Slope <input type="number" id="cdn-slope" min="55" max="155" placeholder="130"> <button type="button" class="btn btn-ghost btn-small" onclick="applyManualTee()">Use</button></span>' +
      '<span class="cdn-hint">&hellip;or leave it and play without handicap.</span></div>';
  }
  note.innerHTML = html;
  note.style.display = html ? 'block' : 'none';
}
window.applyManualPar = function () {
  const c = getCourse($("#r-course").value); if (!c) return;
  const el = document.getElementById('cdn-par'); const total = parseInt(el && el.value) || 0;
  if (!total || total < 27 || total > 80) { showToast('Enter a valid total par', true); return; }
  const holes = c.holes || 18;
  c.par = total;
  let base = Math.floor(total / holes), rem = total - base * holes;
  c.holesData = Array.from({ length: holes }, (_, i) => { let pp = base; if (rem > 0) { pp += 1; rem--; } return Object.assign({}, (c.holesData && c.holesData[i]) || {}, { par: pp }); });
  try { saveState(); } catch (e) {}
  buildHolesGrid(c);
  if (roundFormState.scoreType === 'hbh') startHbhWizard(c);
  try { if (typeof rwzBuildScorecard === 'function' && (roundFormState.scoreType === 'winner' || roundFormState.scoreType === 'hbh' || roundFormState.scoreType === 'nassau')) rwzBuildScorecard(roundFormState.scoreType); } catch (e) {}
  updateCourseDataNote(c);
  showToast('Par set to ' + total);
};
window.applyManualTee = function () {
  const c = getCourse($("#r-course").value); if (!c) return;
  const cr = parseFloat((document.getElementById('cdn-cr') || {}).value);
  const slope = parseInt((document.getElementById('cdn-slope') || {}).value);
  if (!cr || !slope) { showToast('Enter both CR and Slope', true); return; }
  if (!Array.isArray(c.tees)) c.tees = [];
  const par = coursePar(c) || c.par || 72;
  c.tees = c.tees.filter(t => t.name !== 'Manual');
  c.tees.push({ name: 'Manual', color: 'white', cr: cr, slope: slope, par: par });
  try { saveState(); } catch (e) {}
  const tsel = $("#r-tee"); tsel.innerHTML = '<option value="">Select tee...</option>';
  (c.tees || []).forEach(t => { tsel.innerHTML += `<option value="${t.name}">${t.name} (CR ${t.cr} / Slope ${t.slope})</option>`; });
  tsel.value = 'Manual';
  updateCourseDataNote(c);
  showToast('Course rating added');
};

/* =====================================================
   HOLE-BY-HOLE WIZARD
   ===================================================== */
let hbhWizardState = { holeIndex: 0, mode: 'wizard' };

function startHbhWizard(course) {
  const holes = course.holes || 18;
  if (!roundFormState.holes || roundFormState.holes.length !== holes) {
    roundFormState.holes = [];
    for (let i=0; i<holes; i++) {
      const defaultPar = (course.holesData && course.holesData[i]?.par) || 4;
      roundFormState.holes.push({ par: defaultPar, score: defaultPar });
    }
  } else if (course.holesData) {
    course.holesData.forEach((h, i) => {
      if (roundFormState.holes[i] && !roundFormState.holes[i].score) {
        roundFormState.holes[i].par = h.par;
        roundFormState.holes[i].score = h.par;
      }
    });
  }
  hbhWizardState.holeIndex = 0;
  renderHbhWizard(course);
}

function renderHbhWizard(course) {
  if (!course) {
    $("#hbh-hole-info").textContent = "Select course first";
    $("#hbh-hole-name").textContent = "";
    $("#hbh-score").textContent = "—";
    $("#hbh-score-label").textContent = "";
    return;
  }
  const holes = course.holes || 18;
  const idx = hbhWizardState.holeIndex;
  if (idx < 0 || idx >= holes) return;
  if (!roundFormState.holes || !roundFormState.holes[idx]) {
    startHbhWizard(course);
    return;
  }
  const hole = roundFormState.holes[idx];
  const info = course.holesData?.[idx] || {};
  const par = info.par || hole.par || 4;
  hole.par = par;
  if (hole.score == null) hole.score = par;

  $("#hbh-current").textContent = idx + 1;
  $("#hbh-total").textContent = holes;
  $("#hbh-progress-fill").style.width = `${((idx + 1) / holes) * 100}%`;
  $("#hbh-hole-number").textContent = idx + 1;
  $("#hbh-hole-info").innerHTML = `Par ${par}${info.distance ? ` · ${info.distance}m` : ''}${info.si ? ` · SI ${info.si}` : ''}`;
  $("#hbh-hole-name").textContent = info.name || '';
  $("#hbh-score").textContent = hole.score;
  const rel = hole.score - par;
  const label = rel <= -2 ? 'Eagle' : rel === -1 ? 'Birdie' : rel === 0 ? 'Par' : rel === 1 ? 'Bogey' : rel === 2 ? 'Double bogey' : rel === 3 ? 'Triple bogey' : `+${rel}`;
  const labelClass = rel <= -2 ? 'eagle' : rel === -1 ? 'birdie' : rel === 0 ? 'par' : rel === 1 ? 'bogey' : 'double';
  const labelEl = $("#hbh-score-label");
  labelEl.textContent = label;
  labelEl.className = 'hbh-score-label ' + labelClass;
  $("#hbh-prev").disabled = idx === 0;
  $("#hbh-prev").style.opacity = idx === 0 ? 0.4 : 1;
  $("#hbh-next").textContent = idx === holes - 1 ? 'Finish ✓' : 'Next →';
  $("#hbh-next").classList.toggle('done', idx === holes - 1);
  updateHbhSum();
}

function ensureHbhInit() {
  const c = getCourse($("#r-course").value);
  if (!c) { showToast("Select course first", true); return null; }
  if (!roundFormState.holes || roundFormState.holes.length === 0) {
    startHbhWizard(c);
  }
  if (!roundFormState.holes[hbhWizardState.holeIndex]) {
    hbhWizardState.holeIndex = 0;
  }
  return c;
}

function bindHbhWizard() {
  $("#hbh-minus")?.addEventListener('click', () => {
    const course = ensureHbhInit(); if (!course) return;
    const h = roundFormState.holes[hbhWizardState.holeIndex];
    if (h.score > 1) h.score--;
    renderHbhWizard(course);
  });
  $("#hbh-plus")?.addEventListener('click', () => {
    const course = ensureHbhInit(); if (!course) return;
    const h = roundFormState.holes[hbhWizardState.holeIndex];
    if (h.score < 15) h.score++;
    renderHbhWizard(course);
  });
  $("#hbh-prev")?.addEventListener('click', () => {
    const course = ensureHbhInit(); if (!course) return;
    if (hbhWizardState.holeIndex > 0) {
      hbhWizardState.holeIndex--;
      renderHbhWizard(course);
    }
  });
  $("#hbh-next")?.addEventListener('click', () => {
    const course = ensureHbhInit(); if (!course) return;
    const totalHoles = course.holes || 18;
    if (hbhWizardState.holeIndex < totalHoles - 1) {
      hbhWizardState.holeIndex++;
      renderHbhWizard(course);
    } else {
      $("#r-save")?.scrollIntoView({ behavior: 'smooth' });
      showToast("Ready to save round ✓");
    }
  });
  document.querySelectorAll('.hbh-quick').forEach(btn => {
    btn.addEventListener('click', () => {
      const course = ensureHbhInit(); if (!course) return;
      const rel = parseInt(btn.dataset.rel);
      const h = roundFormState.holes[hbhWizardState.holeIndex];
      h.score = Math.max(1, h.par + rel);
      renderHbhWizard(course);
      setTimeout(() => {
        const totalHoles = course.holes || 18;
        if (hbhWizardState.holeIndex < totalHoles - 1) {
          hbhWizardState.holeIndex++;
          renderHbhWizard(course);
        }
      }, 250);
    });
  });
}

window.toggleHbhMode = function() {
  const grid = $("#r-holes-container");
  const wizard = $("#r-hbh-wizard");
  if (grid.style.display === 'none') {
    grid.style.display = '';
    const course = getCourse($("#r-course").value);
    if (course) buildHolesGrid(course);
  } else {
    grid.style.display = 'none';
  }
};

// Bind wizard once on script load
setTimeout(bindHbhWizard, 0);

function buildHolesGrid(course) {
  const container = $("#r-holes-container");
  const holes = course.holes || 18;
  // initialize hole pars from per-hole default if any
  if (!roundFormState.holes || roundFormState.holes.length !== holes) {
    roundFormState.holes = [];
    for (let i=0; i<holes; i++) {
      const defaultPar = (course.holesData && course.holesData[i]?.par) || 4;
      roundFormState.holes.push({ par: defaultPar, score: null, gir: false, fairway: false, putts: null });
    }
  } else if (course.holesData) {
    // sync pars from course data if available
    course.holesData.forEach((h, i) => {
      if (roundFormState.holes[i] && !roundFormState.holes[i].score) {
        roundFormState.holes[i].par = h.par;
      }
    });
  }
  // render two rows of 9
  const front = roundFormState.holes.slice(0, 9);
  const back = roundFormState.holes.slice(9, 18);
  function row(holes, offset, title) {
    const courseHoles = course.holesData || [];
    return `<h3 style="margin-top: 10px">${title}</h3>
      <div class="holes-grid">
        ${holes.map((h,i) => {
          const idx = offset + i;
          const info = courseHoles[idx] || {};
          const ctx = [];
          if (info.distance) ctx.push(`${info.distance}m`);
          if (info.si) ctx.push(`SI ${info.si}`);
          const ctxLine = ctx.length ? `<div class="hole-context">${ctx.join(' · ')}</div>` : '';
          const nameLine = info.name ? `<div class="hole-context"><span class="name">${info.name}</span></div>` : '';
          const notesLine = info.notes ? `<div class="hole-context"><span class="notes" title="${info.notes}">${info.notes.slice(0, 30)}${info.notes.length > 30 ? '…' : ''}</span></div>` : '';
          return `<div class="hole-input">
            <div class="hole-num">Hull ${idx+1}</div>
            ${nameLine}
            <input type="number" placeholder="Par" min="3" max="6" value="${h.par||''}" data-i="${idx}" data-field="par" style="font-size:11px">
            <input type="number" placeholder="Score" min="1" max="15" value="${h.score||''}" data-i="${idx}" data-field="score">
            ${ctxLine}
            ${notesLine}
          </div>`;
        }).join('')}
      </div>`;
  }
  container.innerHTML = row(front, 0, "Hull 1-9") + (holes >= 18 ? row(back, 9, "Hull 10-18") : "");
  container.querySelectorAll('input').forEach(input => {
    input.addEventListener('input', e => {
      const i = parseInt(e.target.dataset.i);
      const f = e.target.dataset.field;
      const v = e.target.value ? parseInt(e.target.value) : null;
      roundFormState.holes[i][f] = v;
      updateHbhSum();
    });
  });
  updateHbhSum();
}

function updateHbhSum() {
  const sum = roundFormState.holes.reduce((s,h) => s + (h.score || 0), 0);
  $("#r-hbh-sum").textContent = sum;
  // approximate stableford without HCP adjustment
  let stbl = 0;
  roundFormState.holes.forEach(h => {
    if (h.score && h.par) stbl += stablefordPoints(h.score, h.par);
  });
  $("#r-hbh-stbl").textContent = stbl;
}

function applyScoreType(type) {
  roundFormState.scoreType = type;
  $$('#r-type label').forEach(l => l.classList.toggle('selected', l.querySelector('input').value === type));
  $("#r-input-total").style.display = type === 'total' ? '' : 'none';
  $("#r-input-hbh").style.display = type === 'hbh' ? '' : 'none';
  $("#r-input-stbl").style.display = type === 'stableford' ? '' : 'none';
  updateRivalrySection();
  if (type === 'hbh') {
    const course = getCourse($("#r-course").value);
    if (course) startHbhWizard(course);
  }
}
$$('#r-type input').forEach(inp => inp.addEventListener('change', e => applyScoreType(e.target.value)));

function renderFriendPills() {
  const container = $("#r-friends");
  if (state.friends.length === 0) {
    container.innerHTML = `<span style="color: var(--muted); font-size: 12px">No friends yet. <span class="small-link" onclick="editFriend()">Add friends</span></span>`;
    return;
  }
  container.innerHTML = state.friends.map(f => {
    const sel = roundFormState.selectedFriends.includes(f.id);
    return `<span class="friend-chip ${sel?'selected':''}" data-fid="${f.id}">${f.name}${f.hcp != null ? ` (${f.hcp})` : ''}</span>`;
  }).join('');
  container.querySelectorAll('.friend-chip').forEach(chip => {
    chip.addEventListener('click', () => {
      const id = chip.dataset.fid;
      const idx = roundFormState.selectedFriends.indexOf(id);
      if (idx >= 0) roundFormState.selectedFriends.splice(idx,1);
      else roundFormState.selectedFriends.push(id);
      chip.classList.toggle('selected');
      updateRivalrySection();
    });
  });
  updateRivalrySection();
}

function updateRivalrySection() {
  const date = $("#r-date").value || todayISO();
  const selectedFriendIds = roundFormState.selectedFriends;
  const active = (state.rivalries || []).filter(rv =>
    rv.status === 'active' &&
    frListHasFriend(selectedFriendIds, rv.friendId) &&
    date >= rv.startDate && date <= rv.endDate
  );
  const sec = $("#r-rivalry-section");
  if (!sec) return;
  // Score now comes from the scorecard \u2014 the old opponent score / differential / Stableford /
  // active-season block below the scorecard is removed. Always keep it hidden.
  sec.style.display = "none";
  const _ohc0 = $("#r-opp-holes-container"); if (_ohc0) _ohc0.style.display = "none";
  return;
  if (active.length === 0) {
    sec.style.display = "none";
    $("#r-opp-holes-container").style.display = "none";
    return;
  }
  sec.style.display = "";
  // Show opponent hole tracking only if scoring hole-by-hole
  if (roundFormState.scoreType === 'hbh') {
    $("#r-opp-holes-container").style.display = "";
  } else {
    $("#r-opp-holes-container").style.display = "none";
    $("#r-matchplay-container").style.display = "none";
  }
  $("#r-active-rivalries").innerHTML = "Active seasons: " + active.map(rv => {
    const f = state.friends.find(x => x.id === rv.friendId);
    return `<span style="color: var(--gold)">${rv.name} (vs ${f?.name})</span>`;
  }).join(", ");
}

$("#r-opp-hbh-toggle")?.addEventListener("change", e => {
  $("#r-opp-holes-grid").style.display = e.target.checked ? "" : "none";
  // Match-play toggle only makes sense when opponent HBH is on
  $("#r-matchplay-container").style.display = e.target.checked ? "" : "none";
  if (!e.target.checked) $("#r-matchplay-toggle").checked = false;
  if (e.target.checked) buildOpponentHolesGrid();
});

function buildOpponentHolesGrid() {
  const n = roundFormState.holes?.length || 18;
  if (!roundFormState.opponentHoles || roundFormState.opponentHoles.length !== n) {
    roundFormState.opponentHoles = Array.from({length: n}, () => ({ score: null }));
  }
  const grid = $("#r-opp-holes-grid");
  if (!grid) return;
  grid.innerHTML = `
    <div style="font-size: 12px; color: var(--muted); margin-bottom: 8px">Motspillerens score per hull:</div>
    <div class="holes-grid">
      ${roundFormState.opponentHoles.map((h, i) => `
        <div class="hole-input">
          <div class="hole-num">Hull ${i+1}</div>
          <input type="number" min="1" max="15" value="${h.score||''}" data-i="${i}" placeholder="—" class="opp-hole-input">
        </div>
      `).join('')}
    </div>
  `;
  grid.querySelectorAll('.opp-hole-input').forEach(inp => {
    inp.addEventListener('input', e => {
      const i = parseInt(e.target.dataset.i);
      roundFormState.opponentHoles[i].score = e.target.value ? parseInt(e.target.value) : null;
    });
  });
}

window.rndSetStake = function (el, val) {
  window.roundFormState = window.roundFormState || {};
  const same = window.roundFormState.stake === val;
  document.querySelectorAll('#r-stake-row .stake-chip').forEach(b => b.classList.remove('on'));
  if (same) { window.roundFormState.stake = null; }
  else { window.roundFormState.stake = val; el.classList.add('on'); }
  const ci = document.getElementById('r-stake-custom');
  if (ci) ci.style.display = (window.roundFormState.stake === 'custom') ? '' : 'none';
  const ai = document.getElementById('r-stake-amount');
  if (ai) ai.style.display = (window.roundFormState.stake && window.roundFormState.stake !== 'custom') ? '' : 'none';
};
$("#r-cancel").addEventListener("click", () => {
    window._rwzPlayout = false; window._rwzPlayoutDecidedHoles = null;
  try { if (window.roundFormState && window.roundFormState._liveRoundId && window.fairwayCloud && window.fairwayCloud.abandonLiveRound) window.fairwayCloud.abandonLiveRound(window.roundFormState._liveRoundId); } catch (e) {}
  try { rwzClearActive(); } catch (e) {}
  roundFormState = { editId: null, holes: [], scoreType: 'total', selectedFriends: [] };
  window.roundFormState = roundFormState;
  activateTab('dashboard');
});

$("#r-save").addEventListener("click", () => {
    window._rwzPlayout = false; window._rwzPlayoutDecidedHoles = null;
  const courseId = $("#r-course").value;
  const teeName = $("#r-tee").value;
  const date = $("#r-date").value;
  if (!courseId || !date) { showToast("Fill in date and course", true); return; }
  // #104 safeguard: if a rival was scored but the selection got dropped, recover it from entered hole scores / totals.
  if ((!roundFormState.selectedFriends || roundFormState.selectedFriends.length === 0) && !roundFormState.solo) {
    const _rec = new Set();
    (roundFormState.holes || []).forEach(h => { if (h && h.scores) Object.keys(h.scores).forEach(pid => { if (pid !== '__me__') _rec.add(pid); }); });
    document.querySelectorAll('.rwz-total-input[data-pid]').forEach(inp => { if (inp.dataset.pid && inp.dataset.pid !== '__me__' && inp.value) _rec.add(inp.dataset.pid); });
    const _valid = [..._rec].filter(pid => (state.friends || []).some(f => f.id === pid));
    if (_valid.length) roundFormState.selectedFriends = _valid;
  }
  if (!roundFormState.selectedFriends || roundFormState.selectedFriends.length === 0) {
    roundFormState.solo = true;  // solo is the default when you played alone — no prompt
  }
  const round = {
    id: roundFormState.editId || uid(),
    date,
    teeTime: $("#r-time").value || null,
    time: $("#r-time-of-day")?.value || null,
    timeOfDay: (function(){ const t=$("#r-time-of-day")?.value; if(!t) return null; const h=parseInt(t.split(":")[0],10); return h<11?"Morning":(h<16?"Midday":"Evening"); })(),
    dayOfWeek: (function(){ try { return ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"][new Date(date).getDay()]; } catch(e){ return null; } })(),
    cart: !!($("#r-cart") && $("#r-cart").checked),
    courseId, teeName,
    scoreType: roundFormState.scoreType,
    holeSet: roundFormState.holeSet || 'all',
    friends: [...roundFormState.selectedFriends],
    notes: $("#r-notes").value || "",
    weather: $("#r-weather")?.value || null,
    tempCat: $("#r-temp-cat")?.value || null,
    windCat: $("#r-wind-cat")?.value || null,
    sleep: $("#r-sleep")?.value || null,
    alcohol: $("#r-alcohol")?.value || null,
    warmup: $("#r-warmup")?.value || null,
    transport: (($("#r-cart") && $("#r-cart").checked) ? "cart" : ($("#r-transport")?.value || null)),
    opponentScore: $("#r-opp-score")?.value ? parseInt($("#r-opp-score").value) : null,
    opponentDifferential: $("#r-opp-diff")?.value ? parseFloat($("#r-opp-diff").value) : null,
    opponentStableford: $("#r-opp-stbl")?.value ? parseInt($("#r-opp-stbl").value) : null,
    opponentHoles: ($("#r-opp-hbh-toggle")?.checked && roundFormState.opponentHoles) ? roundFormState.opponentHoles.map(h => ({...h})) : null,
    matchPlay: !!($("#r-matchplay-toggle")?.checked && $("#r-opp-hbh-toggle")?.checked),
    gameKind: 'golf',
    roundType: ($("#r-round-type")?.value || 'season'),
    stake: window.roundFormState?.stake || null,
    stakeNote: window.roundFormState?.stakeNote || null,
    stakeAmount: window.roundFormState?.stakeAmount || null,
  };
  if (roundFormState.scoreType === 'total') {
    const total = parseInt($("#r-total").value);
    if (!total) { showToast("Enter total score", true); return; }
    round.total = total;
    // Collect opponent totals if any
    const oppInputs = document.querySelectorAll('.rwz-total-input[data-pid]:not([id="r-total"])');
    const opps = {};
    oppInputs.forEach(inp => {
      const v = parseInt(inp.value);
      if (v) opps[inp.dataset.pid] = v;
    });
    if (Object.keys(opps).length) round.opponentTotals = opps;
  } else if (roundFormState.scoreType === 'hbh') {
    round.holes = roundFormState.holes.map(h => ({ ...h }));
    round.total = round.holes.reduce((s,h) => s + (h.score || 0), 0);
    if (round.total === 0) { showToast("Enter score on the holes", true); return; }
  } else if (roundFormState.scoreType === 'stableford') {
    const stbl = parseInt($("#r-stbl-only").value);
    if (!stbl) { showToast("Enter Stableford points", true); return; }
    round.stableford = stbl;
    // estimate total from stableford if course handicap known (skip for now)
  } else if (roundFormState.scoreType === 'winner') {
    round.holes = (roundFormState.holes || []).map(h => ({ ...h }));
    round.holePoints = true;
    const players = rwzPlayers();
    const _c = courseId ? getCourse(courseId) : null;
    const _hd = _c?.holesData || [];
    const _tot = _c?.holes || 18;
    const _wh = !!document.getElementById('r-with-hcp')?.checked;
    const _eff = _wh && (typeof rwzHasAllHcp === 'function' ? rwzHasAllHcp() : false);
    const _ps = {}; players.forEach(p => _ps[p.id] = _eff ? rwzStrokesPerHole(_hd, _tot, rwzPlayerCH(p)) : new Array(_tot).fill(0));
    const pts = {}; players.forEach(p => pts[p.id] = 0);
    const _decidedSet = (window._rwzPlayout && Array.isArray(window._rwzPlayoutDecidedHoles)) ? new Set(window._rwzPlayoutDecidedHoles) : null;
    const bonusPts = {}; if (_decidedSet) players.forEach(p => bonusPts[p.id] = 0);
    (round.holes || []).forEach((h, hi) => {
      const scH = (h && h.scores) || {};
      let best = Infinity, winners = [], scored = 0;
      players.forEach(p => { const g = scH[p.id]; if (g == null || g === '') return; scored++; const st = (_ps[p.id] && _ps[p.id][hi]) || 0; const net = g - st; if (net < best) { best = net; winners = [p.id]; } else if (net === best) winners.push(p.id); });
      const hw = (scored === players.length && winners.length === 1) ? winners[0] : null;
      h.winner = hw || ((scored >= 2) ? 'tie' : null);
      if (hw) { if (_decidedSet && !_decidedSet.has(hi)) bonusPts[hw] = (bonusPts[hw] || 0) + 1; else pts[hw]++; }
    });
    if (_decidedSet) {
      let bb = 0, bw = [];
      players.forEach(p => { const v = bonusPts[p.id] || 0; if (v > bb) { bb = v; bw = [p.id]; } else if (v === bb && v > 0) bw.push(p.id); });
      if (bb > 0 && bw.length === 1) { pts[bw[0]] = (pts[bw[0]] || 0) + 1; round.bonusPoint = true; round.bonusTo = (bw[0] === '__me__') ? 'me' : 'opp'; }
    }
    round.myPoints = pts['__me__'] || 0;
    let oppBest = 0; players.forEach(p => { if (p.id !== '__me__') oppBest = Math.max(oppBest, pts[p.id] || 0); });
    round.oppPoints = oppBest;
    const _anyScores = (round.holes || []).some(h => h && h.scores && Object.keys(h.scores).length);
    if (!_anyScores) { showToast("Enter the hole scores", true); return; }
    round.winner = round.myPoints > oppBest ? 'me' : (round.myPoints < oppBest ? 'opp' : 'tie');
    let myTot = 0; round.holes.forEach(h => { if (h && h.scores && h.scores['__me__']) myTot += h.scores['__me__']; });
    if (myTot) round.total = myTot;
  } else if (roundFormState.scoreType === 'nassau') {
    round.holes = (roundFormState.holes || []).map(h => ({ ...h }));
    round.holePoints = true; round.nassau = true;
    const players = rwzPlayers();
    const _c = courseId ? getCourse(courseId) : null;
    const _hd = _c?.holesData || [];
    const _tot = _c?.holes || 18;
    const _wh = !!document.getElementById('r-with-hcp')?.checked;
    const _eff = _wh && (typeof rwzHasAllHcp === 'function' ? rwzHasAllHcp() : false);
    const _ps = {}; players.forEach(p => _ps[p.id] = _eff ? rwzStrokesPerHole(_hd, _tot, rwzPlayerCH(p)) : new Array(_tot).fill(0));
    const A = players[0], B = players[1] || null;
    const seg = (lo, hi) => {
      let wa = 0, wb = 0;
      (round.holes || []).forEach((h, x) => {
        if (x < lo || x >= hi) return;
        const sH = (h && h.scores) || {};
        const ga = sH[A.id], gb = B ? sH[B.id] : null;
        if (ga == null || ga === '' || gb == null || gb === '') return;
        const sa = (_ps[A.id] && _ps[A.id][x]) || 0, sb = (B && _ps[B.id] && _ps[B.id][x]) || 0;
        const na = ga - sa, nb = gb - sb;
        if (na < nb) wa++; else if (nb < na) wb++;
      });
      return wa > wb ? 'me' : (wb > wa ? 'opp' : 'tie');
    };
    const segs = [seg(0, 9), seg(9, 18), seg(0, 18)];
    let mp = 0, op = 0;
    segs.forEach(r => { if (r === 'me') mp++; else if (r === 'opp') op++; });
    round.nassauSegments = segs;
    round.myPoints = mp; round.oppPoints = op;
    round.winner = mp > op ? 'me' : (mp < op ? 'opp' : 'tie');
    const _anyScores = (round.holes || []).some(h => h && h.scores && Object.keys(h.scores).length);
    if (!_anyScores) { showToast("Enter the hole scores", true); return; }
    let myTot = 0; round.holes.forEach(h => { if (h && h.scores && h.scores['__me__']) myTot += h.scores['__me__']; });
    if (myTot) round.total = myTot;
  } else if (window.roundFormState.teamPlay) {
    round.holes = (roundFormState.holes || []).map(h => ({ ...h }));
    round.holePoints = true; round.teamPlay = true;
    const fmt = roundFormState.teamFormat; round.teamFormat = fmt;
    const t = rwzTeams(); round.teamA = t.A; round.teamB = t.B;
    let aPts = 0, bPts = 0;
    if (TEAM_PERTEAM.indexOf(fmt) !== -1) {
      (round.holes || []).forEach(h => { const sH = (h && h.scores) || {}; const a = sH['__teamA__'], b = sH['__teamB__']; if (a == null || a === '' || b == null || b === '') return; if (a < b) aPts++; else if (b < a) bPts++; });
    } else {
      const seg = (ids, h, agg) => { const sH = (h && h.scores) || {}; const vals = ids.map(id => sH[id]).filter(v => v != null && v !== '').map(Number); if (!vals.length) return null; return agg === 'max' ? Math.max.apply(null, vals) : Math.min.apply(null, vals); };
      (round.holes || []).forEach(h => { const aB = seg(t.A, h, 'min'), bB = seg(t.B, h, 'min'); if (aB != null && bB != null) { if (aB < bB) aPts++; else if (bB < aB) bPts++; } if (fmt === 'team_doubleduel') { const aW = seg(t.A, h, 'max'), bW = seg(t.B, h, 'max'); if (aW != null && bW != null) { if (aW < bW) aPts++; else if (bW < aW) bPts++; } } });
    }
    const _anyScores = (round.holes || []).some(h => h && h.scores && Object.keys(h.scores).length);
    if (!_anyScores) { showToast("Enter the hole scores", true); return; }
    round.myPoints = aPts; round.oppPoints = bPts;
    round.winner = aPts > bPts ? 'me' : (aPts < bPts ? 'opp' : 'tie');
    let myTot = 0; round.holes.forEach(h => { if (h && h.scores) { const v = h.scores['__teamA__'] != null ? h.scores['__teamA__'] : h.scores['__me__']; if (v) myTot += v; } });
    if (myTot) round.total = myTot;
  }
  // Per-player "played to" (net vs par) for the round summary
  if (round.holes && round.holes.some(h => h && h.scores)) {
    const _wh = document.getElementById('r-with-hcp')?.checked;
    round.withHcp = !!_wh;
    const _players = rwzPlayers();
    const _hd = (getCourse(courseId)?.holesData) || [];
    const _tot = getCourse(courseId)?.holes || 18;
    round.playedTo = {}; round.playerNames = {};
    _players.forEach(pl => {
      const str = _wh ? rwzStrokesPerHole(_hd, _tot, rwzPlayerCH(pl)) : null;
      let net = 0, played = 0;
      round.holes.forEach((h, i) => { const g = h && h.scores && h.scores[pl.id]; if (g) { const par = _hd[i]?.par || 4; const sx = str ? (str[i] || 0) : 0; net += (g - par - sx); played++; } });
      if (played) { round.playedTo[pl.id] = net; round.playerNames[pl.id] = pl.disp; }
    });
  }
  // Par of the holes ACTUALLY played (so 9-hole rounds aren't compared to an 18-hole par)
  const _c = getCourse(courseId);
  const _tee = _c ? getTee(_c, teeName) : null;
  let _playedPar = 0;
  (round.holes || []).forEach(h => {
    const hasScore = h && ((h.score != null) || (h.scores && Object.values(h.scores).some(v => v != null)));
    if (hasScore) _playedPar += (h.par || 4);
  });
  const _par = _playedPar > 0 ? _playedPar : (_tee?.par || _c?.par || 72);
  // Validate score is realistic relative to the played par
  if (round.total != null) {
    if (round.total < _par - 9) {
      showToast(`Score ${round.total} is unrealistically low for par ${_par}.`, true);
      return;
    }
    if (round.total > _par + 80) {
      showToast(`Score ${round.total} is unrealistically high. Check your entry.`, true);
      return;
    }
  }
  // Validate opponent score same way
  if (round.opponentScore != null) {
    if (round.opponentScore < _par - 9 || round.opponentScore > _par + 80) {
      showToast(`Opponent's score ${round.opponentScore} is unrealistic for par ${_par}.`, true);
      return;
    }
  }
  // Auto-compute opponent_differential when opponent_score is provided
  if (round.opponentScore != null && round.opponentDifferential == null) {
    const _c = getCourse(courseId);
    const _tee = _c ? getTee(_c, teeName) : null;
    if (_tee?.cr && _tee?.slope) {
      round.opponentDifferential = calcDifferential(round.opponentScore, _tee.cr, _tee.slope);
    }
  }
  // save
  const isNew = !roundFormState.editId;
  // Ensure round ID is UUID-format if we're going to push to cloud
  if (window.fairwayCloud?.isLoggedIn() && !/^[0-9a-f-]{36}$/i.test(round.id)) {
    round.id = window.fairwayCloud.ensureUuid(round.id);
  }
  // Auto-link to an active rivalry if friend matches and date is in range
  if (!round.rivalryId && round.friends?.length) {
    let matchingRivalry = (state.rivalries || []).find(rv =>
      frListHasFriend(round.friends, rv.friendId) &&
      round.date >= rv.startDate && round.date <= rv.endDate
    );
    // Playing a rival goes straight into a rivalry — auto-create one if none exists (1v1).
    if (!matchingRivalry && round.friends.length === 1) {
      const fr = (state.friends || []).find(f => f.id === round.friends[0]);
      if (fr) {
        const yr = new Date(round.date).getFullYear();
        const myName = activeProfile()?.name || 'You';
        matchingRivalry = { id: uid(), name: `${myName} vs ${fr.name} ${yr}`, friendId: fr.id, startDate: `${yr}-01-01`, endDate: `${yr}-12-31`, status: 'active', createdAt: new Date().toISOString(), auto: true };
        state.rivalries = state.rivalries || [];
        state.rivalries.push(matchingRivalry);
      }
    }
    // Team match: generate a rival card against each opponent so a rivalry always exists after a match
    if (round.teamPlay && Array.isArray(round.teamB)) {
      const yr = new Date(round.date).getFullYear();
      const myName = activeProfile()?.name || 'You';
      round.teamB.filter(id => id && id !== '__me__').forEach(oid => {
        const fr = (state.friends || []).find(f => f.id === oid);
        if (!fr) return;
        let rv = (state.rivalries || []).find(r => r.friendId === oid && round.date >= r.startDate && round.date <= r.endDate);
        if (!rv) {
          rv = { id: uid(), name: `${myName} vs ${fr.name} ${yr}`, friendId: fr.id, startDate: `${yr}-01-01`, endDate: `${yr}-12-31`, status: 'active', createdAt: new Date().toISOString(), auto: true, fromTeamMatch: true };
          state.rivalries = state.rivalries || [];
          state.rivalries.push(rv);
        }
        if (!matchingRivalry) matchingRivalry = rv;
      });
    }
    if (matchingRivalry) round.rivalryId = matchingRivalry.id;
  }
  // Compute differential before saving so cloud gets it
  const computedRound = buildRoundComputed(round);
  if (computedRound.differential != null) round.differential = computedRound.differential;
  // Save per-player conditions on the round
  try { rppSaveActive(); round.playerConditions = JSON.parse(JSON.stringify(window._roundPPConditions || {})); } catch (e) {}
  if (roundFormState.editId) {
    const i = state.rounds.findIndex(r => r.id === roundFormState.editId);
    if (i >= 0) state.rounds[i] = round;
  } else {
    state.rounds.push(round);
  }
  saveState();
  // Defensive: ensure state.rounds points to the same array as activeProfile().rounds
  refreshProfileAliases();
  // Carry rival cloud user-ids so the cloud round keeps the rival (local friend ids are not UUIDs).
  round.friendCloudIds = (round.friends || []).map(fid => (frFindFriend(fid) || {}).cloudId).filter(Boolean);
  cloudPushRound(round);
  try { rwzProposeRoundResults(round); } catch (e) {}
  // Auto-rivalry: after 3+ matches with the same opponent, suggest a rivalry
  try { maybeSuggestAutoRivalry(); } catch (e) { console.warn('auto-rivalry', e); }
  try { checkMembershipFromTrophies(); } catch (e) { console.warn('membership check', e); }
  console.log(`[Fairway Rivalry] Round saved. state.rounds.length=${state.rounds.length}, activeProfile rounds=${activeProfile()?.rounds?.length}`);
  try { rwzClearActive(); } catch (e) {}
  roundFormState = { editId: null, holes: [], scoreType: 'total', selectedFriends: [] };
  window.roundFormState = roundFormState;
  // Clear all inputs
  ["r-total","r-stableford","r-stbl-only","r-notes","r-time","r-course-search",
   "r-opp-score","r-opp-diff","r-opp-stbl"].forEach(id => { const el = $("#"+id); if (el) el.value = ""; });
  ["r-weather","r-temp-cat","r-wind-cat","r-sleep","r-alcohol","r-warmup","r-transport"].forEach(id => { const el = $("#"+id); if (el) el.value = ""; });

  // Land on dashboard and show HCP feedback inline. Forces full refresh.
  if (isNew) {
    const computed = buildRoundComputed(round);
    activateTab('dashboard');
    showHcpInlineBanner(computed);
    setTimeout(() => checkAchievements(round), 400);
    try { showScoreSummary(round); } catch (e) { showToast(`Round saved · ${state.rounds.length} total`); }
    try { frOfferGuestResult(round); } catch (e) {}
  } else {
    showToast("Round updated");
    activateTab('rounds');
  }
});

function showHcpInlineBanner(round) {
  const dash = $("#tab-dashboard");
  if (!dash) return;
  const c = getCourse(round.courseId);
  const tee = c ? getTee(c, round.teeName) : null;

  // Remove any existing banner
  const old = document.getElementById('hcp-inline-banner');
  if (old) old.remove();

  const banner = document.createElement('div');
  banner.id = 'hcp-inline-banner';
  banner.className = 'hcp-banner';
  banner.innerHTML = round.differential != null && tee ? `
    <div class="hcp-banner-inner">
      <div>
        <div class="hcp-banner-label">ROUND SAVED · SCORE DIFFERENTIAL</div>
        <div class="hcp-banner-value">${round.differential.toFixed(1)}</div>
      </div>
      <div class="hcp-banner-meta">
        ${c?.name || ''} · ${round.teeName}<br>
        ${round.total} on a ${tee.cr}/${tee.slope} course
      </div>
      <button class="icon-btn" onclick="document.getElementById('hcp-inline-banner').remove()">✕</button>
    </div>
  ` : `
    <div class="hcp-banner-inner">
      <div>
        <div class="hcp-banner-label">ROUND SAVED</div>
        <div class="hcp-banner-value" style="font-size: 18px">CR/Slope missing for this course</div>
      </div>
      <button class="icon-btn" onclick="document.getElementById('hcp-inline-banner').remove()">✕</button>
    </div>
  `;
  dash.insertBefore(banner, dash.firstChild);
  // Auto-dismiss after 12 seconds
  setTimeout(() => { const b = document.getElementById('hcp-inline-banner'); if (b) b.remove(); }, 12000);
}

function showHcpFeedback(round) {
  const c = getCourse(round.courseId);
  const tee = c ? getTee(c, round.teeName) : null;
  openModal(`
    <div class="hcp-feedback" style="margin: 0">
      ${round.differential != null && tee ? `
        <div class="label">Score Differential</div>
        <div class="value">${round.differential.toFixed(1)}</div>
        <div class="body">
          Denne runden tilsvarer omtrent <strong style="color: var(--text)">${round.differential.toFixed(1)}</strong> i handicap.<br>
          <span style="font-size: 11px; color: var(--muted-2)">Formula: (113 ÷ Slope) × (Score − CR) = (113 ÷ ${tee.slope}) × (${round.total} − ${tee.cr})</span>
        </div>
      ` : `
        <div class="label">Ufullstendig data</div>
        <div class="value" style="font-size: 18px">Kan ikke beregne</div>
        <div class="body">For å beregne handicap-resultat trenger vi <strong style="color: var(--text)">Course Rating</strong> og <strong style="color: var(--text)">Slope Rating</strong> for denne banen. Rediger banen og fyll inn disse verdiene.</div>
      `}
    </div>
    <div class="actions">
      <button class="btn" onclick="closeModal(); activateTab('rounds')">Se alle runder</button>
      <button class="btn btn-ghost" onclick="closeModal(); activateTab('dashboard')">Til dashboard</button>
    </div>
  `);
}

/* ---------- Render: All rounds ---------- */
function renderAllRounds() {
  const csel = $("#rd-filter-course");
  csel.innerHTML = '<option value="">Alle baner</option>' + state.courses.map(c => `<option value="${c.id}">${c.name}</option>`).join('');
  renderRoundsTable();
}
$("#rd-search")?.addEventListener("input", renderRoundsTable);
$("#rd-filter-course")?.addEventListener("change", renderRoundsTable);

function renderRoundsTable() {
  const search = ($("#rd-search").value || "").toLowerCase();
  const filterCourse = $("#rd-filter-course").value;
  const rounds = state.rounds.map(buildRoundComputed)
    .filter(r => {
      if (filterCourse && r.courseId !== filterCourse) return false;
      if (search) {
        const c = getCourse(r.courseId);
        const hay = `${c?.name||''} ${r.notes||''} ${r.gameLabel||''}`.toLowerCase();
        if (!hay.includes(search)) return false;
      }
      return true;
    })
    .sort((a,b) => new Date(b.date) - new Date(a.date));
  const tbody = $("#all-rounds tbody");
  if (rounds.length === 0) {
    tbody.innerHTML = `<tr><td colspan="8" style="text-align:center; color:var(--muted); padding: 30px">No rounds found.</td></tr>`;
    return;
  }
  tbody.innerHTML = rounds.map(r => {
    const friendNames = (r.friends||[]).map(fid => frFindFriend(fid)?.name).filter(Boolean).join(", ");
    // Minigame / other-game rows render compactly
    if (r.gameKind && r.gameKind !== 'golf') {
      const winnerLabel = r.winner === 'me' ? '🟢 You'
        : r.winner === 'opp' ? `🔴 ${friendNames}`
        : r.winner === 'tie' ? '½ Tied'
        : '—';
      const countsBadge = r.countsInRivalry
        ? '<span style="font-size: 10px; padding: 1px 6px; border-radius: 999px; background: rgba(74,222,128,0.12); color: var(--accent); margin-left: 6px">RIVALRY</span>'
        : '<span style="font-size: 10px; padding: 1px 6px; border-radius: 999px; background: rgba(143,165,153,0.12); color: var(--muted); margin-left: 6px">FOR FUN</span>';
      return `<tr class="row-clickable" onclick="viewRound('${r.id}')" style="cursor: pointer">
        <td>${fmtDate(r.date)}</td>
        <td colspan="2">${r.gameIcon || '🎲'} <strong>${r.gameLabel || r.gameSubtype || 'Minigame'}</strong>${countsBadge}</td>
        <td class="num" style="font-size: 12px; color: var(--muted)">${r.myScore || '—'}</td>
        <td class="num" style="font-size: 12px; color: var(--muted)">${r.oppScore || '—'}</td>
        <td>${winnerLabel}</td>
        <td>${friendNames}</td>
        <td onclick="event.stopPropagation()">
          <button class="icon-btn" onclick="deleteRound('${r.id}')" title="Delete">🗑️</button>
        </td>
      </tr>`;
    }
    const c = getCourse(r.courseId);
    const tee = c ? getTee(c, r.teeName) : null;
    return `<tr class="row-clickable" onclick="viewRound('${r.id}')" style="cursor: pointer">
      <td>${fmtDate(r.date)}</td>
      <td>${c?.name || "—"}</td>
      <td>${tee ? `<span class="badge tee-${tee.color}">${tee.name}</span>` : r.teeName || ''}</td>
      <td class="num">${r.total || "—"}</td>
      <td class="num">${r.stableford || "—"}</td>
      <td class="num">${fmt(r.differential, 1)}</td>
      <td>${friendNames}</td>
      <td onclick="event.stopPropagation()">
        <button class="icon-btn" onclick="shareRound('${r.id}')" title="Share">📤</button>
        <button class="icon-btn" onclick="editRound('${r.id}')" title="Edit">✏️</button>
        <button class="icon-btn" onclick="deleteRound('${r.id}')" title="Delete">🗑️</button>
      </td>
    </tr>`;
  }).join('');
}

window.editRound = function(id) {
  const r = state.rounds.find(x => x.id === id);
  if (!r) return;
  roundFormState = {
    editId: id,
    holes: r.holes ? r.holes.map(h => ({...h})) : [],
    scoreType: r.scoreType || 'total',
    selectedFriends: [...(r.friends||[])]
  };
  window.roundFormState = roundFormState;
  activateTab('round');
  $("#r-date").value = r.date;
  $("#r-course").value = r.courseId;
  $("#r-course").dispatchEvent(new Event('change'));
  $("#r-tee").value = r.teeName;
  $("#r-total").value = r.total || "";
  $("#r-stableford").value = r.stableford || "";
  $("#r-stbl-only").value = r.stableford || "";
  $("#r-notes").value = r.notes || "";
  $("#r-time").value = r.teeTime || "";
  if ($("#r-time-of-day")) $("#r-time-of-day").value = r.time || "";
  if ($("#r-cart")) $("#r-cart").checked = !!r.cart;
  $("#r-course-search").value = getCourse(r.courseId)?.name || "";
  if ($("#r-weather")) $("#r-weather").value = r.weather || "";
  if ($("#r-temp-cat")) $("#r-temp-cat").value = r.tempCat || "";
  if ($("#r-wind-cat")) $("#r-wind-cat").value = r.windCat || "";
  if ($("#r-sleep")) $("#r-sleep").value = r.sleep || "";
  if ($("#r-alcohol")) $("#r-alcohol").value = r.alcohol || "";
  if ($("#r-warmup")) $("#r-warmup").value = r.warmup || "";
  if ($("#r-transport")) $("#r-transport").value = r.transport || "";
  applyScoreType(r.scoreType || 'total');
  if (r.holes) {
    roundFormState.holes = r.holes.map(h => ({...h}));
    const c = getCourse(r.courseId);
    if (c) buildHolesGrid(c);
  }
};

window.deleteRound = function(id) {
  if (!confirm("Delete this round?")) return;
  const p = activeProfile();
  p.rounds = p.rounds.filter(r => r.id !== id);
  state.rounds = p.rounds;
  refreshProfileAliases();
  saveState();
  cloudDeleteRound(id);
  renderRoundsTable();
  renderDashboard();
  showToast("Round deleted");
};

/* ---------- Share functions ---------- */
function shareText(text) {
  if (navigator.share) {
    navigator.share({ text, title: "Fairway Rivalry" }).catch(() => copyToClipboard(text));
  } else {
    copyToClipboard(text);
  }
}
function copyToClipboard(text) {
  navigator.clipboard.writeText(text).then(
    () => showToast("Copied to clipboard ✓"),
    () => showToast("Couldn't copy", true)
  );
}

window.shareRound = function(id) {
  const r = state.rounds.find(x => x.id === id);
  if (!r) return;
  showShareCardModal(r);
};

window.viewRound = function(id) {
  const r = state.rounds.find(x => x.id === id);
  if (!r) return;
  const friendNames = (r.friends || []).map(fid => frFindFriend(fid)?.name).filter(Boolean).join(", ");
  // Minigame / other-game detail
  if (r.gameKind && r.gameKind !== 'golf') {
    const winnerLabel = r.winner === 'me' ? '🟢 You won' : r.winner === 'opp' ? `🔴 ${friendNames || 'Opponent'} won` : r.winner === 'tie' ? '½ Tied' : '—';
    const winnerColor = r.winner === 'me' ? 'var(--accent-bright)' : r.winner === 'opp' ? 'var(--tension)' : 'var(--muted)';
    openModal(`
      <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 16px">
        <div>
          <div style="font-size: 11px; color: var(--gold); letter-spacing: 0.12em; text-transform: uppercase">${r.gameKind === 'golfmini' ? 'Golf minigame' : r.gameKind === 'other' ? 'Other game' : 'Minigame'}</div>
          <h2 style="margin: 4px 0 0 0; display: flex; align-items: center; gap: 10px"><span style="font-size: 24px">${r.gameIcon || '🎲'}</span>${r.gameLabel || 'Minigame'}</h2>
          <div style="color: var(--muted); font-size: 12px; margin-top: 4px">${fmtDate(r.date)}${friendNames ? ' · vs ' + friendNames : ''}</div>
        </div>
        <div style="text-align: right">
          <div style="font-size: 11px; color: var(--muted); letter-spacing: 0.1em; text-transform: uppercase">${r.countsInRivalry ? 'Counts in rivalry' : 'For fun'}</div>
        </div>
      </div>
      <div style="background: var(--bg-2); border: 1px solid var(--border); border-radius: 12px; padding: 22px; text-align: center; margin-bottom: 14px">
        <div style="font-size: 22px; font-weight: 600; color: ${winnerColor}; letter-spacing: -0.01em">${winnerLabel}</div>
        ${r.myScore != null || r.oppScore != null ? `
          <div style="display: flex; justify-content: center; gap: 32px; margin-top: 16px">
            <div><div style="font-size: 11px; color: var(--muted); letter-spacing: 0.08em">YOU</div><div style="font-size: 28px; font-weight: 600; margin-top: 4px">${r.myScore != null ? r.myScore : '—'}</div></div>
            <div><div style="font-size: 11px; color: var(--muted); letter-spacing: 0.08em">${(friendNames || 'OPPONENT').toUpperCase()}</div><div style="font-size: 28px; font-weight: 600; margin-top: 4px">${r.oppScore != null ? r.oppScore : '—'}</div></div>
          </div>
        ` : ''}
      </div>
      ${r.notes ? `<div style="background: var(--bg-2); border-radius: 10px; padding: 12px 14px; margin-bottom: 14px"><div style="font-size: 11px; color: var(--muted); letter-spacing: 0.08em; text-transform: uppercase; margin-bottom: 6px">Notes</div><div style="font-size: 13px; line-height: 1.5; color: var(--text)">${r.notes}</div></div>` : ''}
      <div class="actions">
        <button class="btn btn-ghost" onclick="closeModal()">Close</button>
        <button class="btn btn-danger" onclick="closeModal(); deleteRound('${r.id}')">Delete</button>
      </div>
    `);
    return;
  }
  // Golf round detail
  const c = getCourse(r.courseId);
  const tee = c ? getTee(c, r.teeName) : null;
  const computed = buildRoundComputed(r);
  const holesHtml = (r.holes && r.holes.some(h => h && h.score)) ? `
    <h3 style="margin-top: 18px">Hole-by-hole</h3>
    <div class="table-wrap" style="max-height: 380px; overflow-y: auto">
      <table>
        <thead><tr><th>Hole</th><th class="num">Par</th><th class="num">Score</th><th class="num">vs Par</th>${r.opponentHoles ? `<th class="num">Opp</th>` : ''}</tr></thead>
        <tbody>${r.holes.map((h, i) => {
          if (!h.score) return '';
          const vsPar = h.par ? h.score - h.par : null;
          const vsParStr = vsPar == null ? '—' : vsPar === 0 ? 'E' : vsPar > 0 ? `+${vsPar}` : `${vsPar}`;
          const vsParColor = vsPar < 0 ? 'var(--accent-bright)' : vsPar === 0 ? 'var(--gold)' : vsPar === 1 ? 'var(--warn)' : 'var(--tension)';
          const opp = r.opponentHoles?.[i];
          return `<tr>
            <td><strong>${i+1}</strong></td>
            <td class="num">${h.par || '—'}</td>
            <td class="num">${h.score}</td>
            <td class="num" style="color: ${vsParColor}">${vsParStr}</td>
            ${r.opponentHoles ? `<td class="num">${opp?.score || '—'}</td>` : ''}
          </tr>`;
        }).join('')}</tbody>
      </table>
    </div>
  ` : '';
  const attrs = [
    r.weather && ['☁️ Weather', r.weather],
    r.tempCat && ['🌡️ Temperature', r.tempCat],
    r.windCat && ['💨 Wind', r.windCat],
    r.sleep && ['😴 Sleep', r.sleep],
    r.alcohol && ['🍺 Alcohol', r.alcohol],
    r.warmup && ['🏋️ Warm-up', r.warmup],
    r.transport && ['🚗 Transport', r.transport],
    r.teeTime && ['⏰ Tee time', r.teeTime],
  ].filter(Boolean);
  openModal(`
    <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 16px; gap: 10px; flex-wrap: wrap">
      <div>
        <div style="font-size: 11px; color: var(--gold); letter-spacing: 0.12em; text-transform: uppercase">Golf round</div>
        <h2 style="margin: 4px 0 0 0">${c?.name || 'Unknown course'}</h2>
        <div style="color: var(--muted); font-size: 12px; margin-top: 4px">
          ${fmtDate(r.date)}${tee ? ` · ${tee.name} (CR ${tee.cr} / Slope ${tee.slope})` : ''}${friendNames ? ' · vs ' + friendNames : ''}
        </div>
      </div>
      ${r.matchPlay ? '<span style="font-size: 10px; padding: 3px 10px; border-radius: 999px; background: rgba(201,169,97,0.18); color: var(--gold); letter-spacing: 0.1em; text-transform: uppercase; font-weight: 600; height: max-content"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" style="width:11px;height:11px;vertical-align:-1px"><line x1="5" y1="3" x2="19" y2="21"/><line x1="19" y1="3" x2="5" y2="21"/></svg> Match play</span>' : ''}
    </div>

    ${(function(){
      let banner='';
      if (r.holePoints && (r.myPoints!=null||r.oppPoints!=null)) {
        const mine=r.myPoints||0, opp=r.oppPoints||0; const won=mine>opp, tie=mine===opp;
        banner=`<div class="ro-result ${won?'win':tie?'tie':'loss'}"><div class="ro-result-label">HOLE WINNER</div><div class="ro-result-score">${mine}<span>\u2013</span>${opp}</div><div class="ro-result-sub">${won?'You won':tie?'All square':(friendNames||'Rival')+' won'}</div></div>`;
      } else if (r.opponentScore!=null && r.total!=null) {
        const won=r.total<r.opponentScore, tie=r.total===r.opponentScore;
        banner=`<div class="ro-result ${won?'win':tie?'tie':'loss'}"><div class="ro-result-label">RESULT</div><div class="ro-result-score">${r.total}<span>\u2013</span>${r.opponentScore}</div><div class="ro-result-sub">${won?'You won':tie?'Tied':(friendNames||'Rival')+' won'}</div></div>`;
      }
      const chips=[];
      if (r.scoreType) chips.push(r.scoreType==='winner'?'Match Play':r.scoreType==='hbh'?'Stroke Play':'Total only');
      chips.push(r.withHcp?'With handicap':'Gross');
      chips.push((r.friends&&r.friends.length)?friendNames:'Solo');
      if (r.stake) chips.push('Stakes: '+(r.stakeNote||r.stake));
      const chipRow=`<div class="ro-teeoff">${chips.filter(Boolean).map(c=>`<span class="ro-chip">${c}</span>`).join('')}</div>`;
      return banner+chipRow;
    })()}

    <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(110px, 1fr)); gap: 10px; margin-bottom: 14px">
      <div style="background: var(--bg-2); border-radius: 10px; padding: 14px; text-align: center">
        <div style="font-size: 10px; color: var(--muted); letter-spacing: 0.08em">SCORE</div>
        <div style="font-size: 28px; font-weight: 600; margin-top: 4px">${r.total || '—'}</div>
      </div>
      <div style="background: var(--bg-2); border-radius: 10px; padding: 14px; text-align: center">
        <div style="font-size: 10px; color: var(--muted); letter-spacing: 0.08em">DIFFERENTIAL</div>
        <div style="font-size: 28px; font-weight: 600; margin-top: 4px; color: var(--gold)">${computed.differential != null ? fmt(computed.differential, 1) : '—'}</div>
      </div>
      ${r.stableford ? `
      <div style="background: var(--bg-2); border-radius: 10px; padding: 14px; text-align: center">
        <div style="font-size: 10px; color: var(--muted); letter-spacing: 0.08em">STABLEFORD</div>
        <div style="font-size: 28px; font-weight: 600; margin-top: 4px">${r.stableford}</div>
      </div>` : ''}
      ${r.opponentScore ? `
      <div style="background: var(--bg-2); border-radius: 10px; padding: 14px; text-align: center">
        <div style="font-size: 10px; color: var(--muted); letter-spacing: 0.08em">OPPONENT</div>
        <div style="font-size: 28px; font-weight: 600; margin-top: 4px">${r.opponentScore}</div>
      </div>` : ''}
    </div>

    ${attrs.length ? `
    <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 8px; margin-bottom: 14px">
      ${attrs.map(([k,v]) => `<div style="background: var(--bg-2); border-radius: 8px; padding: 8px 12px; font-size: 12px"><span style="color: var(--muted)">${k}:</span> <strong style="color: var(--text)">${v}</strong></div>`).join('')}
    </div>
    ` : ''}

    ${r.notes ? `<div style="background: var(--bg-2); border-radius: 10px; padding: 12px 14px; margin-bottom: 14px"><div style="font-size: 11px; color: var(--muted); letter-spacing: 0.08em; text-transform: uppercase; margin-bottom: 6px">Notes</div><div style="font-size: 13px; line-height: 1.5; color: var(--text)">${r.notes}</div></div>` : ''}

    ${holesHtml}

    <div class="actions">
      <button class="btn btn-ghost" onclick="closeModal()">Close</button>
      <button class="btn btn-ghost" onclick="closeModal(); shareRound('${r.id}')">📤 Share</button>
      <button class="btn" onclick="closeModal(); editRound('${r.id}')">Edit</button>
    </div>
  `);
};

/* =====================================================
   CINEMATIC SHARE CARD - the viral mechanism
   ===================================================== */

function showShareCardModal(round) {
  const rc = buildRoundComputed(round);
  const c = getCourse(round.courseId);
  const me = activeProfile()?.name || "You";
  const isMatchup = round.friends?.length > 0 && (round.opponentScore != null || round.opponentDifferential != null || round.opponentStableford != null);
  const friend = isMatchup ? state.friends.find(f => f.id === round.friends[0]) : null;

  let funFact = null;
  if (friend) funFact = pickBestFact(rc, state.rounds, friend, me);

  // Determine outcome
  let outcome = null, myScore, theirScore, margin;
  if (friend && isMatchup) {
    myScore = rc.total;
    theirScore = round.opponentScore;
    if (myScore != null && theirScore != null) {
      outcome = myScore < theirScore ? 'win' : myScore > theirScore ? 'loss' : 'tie';
      margin = Math.abs(myScore - theirScore);
    }
  }

  const cardId = `card-${Date.now()}`;
  openModal(`
    <div style="text-align: center; margin-bottom: 14px">
      <h2 style="margin: 0">Share your round</h2>
      <p style="color: var(--muted); font-size: 12px; margin-top: 4px">Tap to download or share. Looks great on Instagram, WhatsApp, Discord.</p>
    </div>

    <div style="display: flex; justify-content: center; margin-bottom: 18px">
      <div id="${cardId}-container" style="max-width: 100%; overflow: hidden; border-radius: 16px; box-shadow: 0 12px 40px rgba(0,0,0,0.5)"></div>
    </div>

    <div style="display: flex; gap: 8px; flex-wrap: wrap; justify-content: center">
      <button class="btn" id="card-download">📥 Download PNG</button>
      <button class="btn btn-ghost" id="card-share">📤 Share</button>
      <button class="btn btn-ghost" id="card-text">Copy text</button>
      <button class="btn btn-ghost" onclick="closeModal()">Close</button>
    </div>
  `);

  const svgString = buildShareCardSVG({ round: rc, course: c, me, friend, outcome, myScore, theirScore, margin, funFact });
  // Display
  $(`#${cardId}-container`).innerHTML = svgString;
  const svg = $(`#${cardId}-container svg`);
  svg.style.width = "100%";
  svg.style.height = "auto";
  svg.style.maxWidth = "400px";

  $("#card-download").addEventListener("click", () => downloadCardAsPNG(svgString, `fairway-${round.date}.png`));
  $("#card-share").addEventListener("click", async () => {
    const blob = await svgToPngBlob(svgString);
    if (navigator.share && navigator.canShare?.({ files: [new File([blob], 'fairway.png', { type: 'image/png' })] })) {
      try {
        await navigator.share({ files: [new File([blob], 'fairway.png', { type: 'image/png' })], title: "Fairway Rivalry" });
      } catch (e) { /* user cancelled */ }
    } else {
      downloadCardAsPNG(svgString, `fairway-${round.date}.png`);
    }
  });
  $("#card-text").addEventListener("click", () => {
    let text;
    if (friend && outcome) {
      const verb = outcome === 'win' ? 'defeats' : outcome === 'loss' ? 'falls to' : 'ties';
      text = `${me} ${verb} ${friend.name}\n${myScore} – ${theirScore} at ${c?.name || ''}\n${funFact ? funFact + '\n' : ''}\nFairway ⛳`;
    } else {
      text = `${me} shot ${rc.total} at ${c?.name || ''}\n${rc.differential != null ? `Diff: ${rc.differential.toFixed(1)}\n` : ''}\nFairway ⛳`;
    }
    copyToClipboard(text);
  });
}

function buildShareCardSVG({ round, course, me, friend, outcome, myScore, theirScore, margin, funFact }) {
  const W = 1080, H = 1080;
  const isMatchup = !!friend && outcome != null;
  const headline = isMatchup
    ? (outcome === 'win' ? `${escapeXml(me)} defeats ${escapeXml(friend.name)}` : outcome === 'loss' ? `${escapeXml(friend.name)} beats ${escapeXml(me)}` : `${escapeXml(me)} & ${escapeXml(friend.name)} tied`)
    : `${escapeXml(me)} shot ${round.total}`;

  const subtitle = course ? escapeXml(course.name) + (course.country ? ` · ${escapeXml(course.country)}` : '') : '';
  const dateStr = fmtDate(round.date);
  const accentColor = outcome === 'win' ? '#84c5a3' : outcome === 'loss' ? '#c25a5a' : '#c9a961';

  // SVG content
  return `
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" width="${W}" height="${H}">
  <defs>
    <linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="#0a1410"/>
      <stop offset="55%" stop-color="#12201a"/>
      <stop offset="100%" stop-color="#0a1410"/>
    </linearGradient>
    <radialGradient id="glow" cx="0.5" cy="0.35" r="0.6">
      <stop offset="0%" stop-color="${accentColor}" stop-opacity="0.18"/>
      <stop offset="100%" stop-color="${accentColor}" stop-opacity="0"/>
    </radialGradient>
    <linearGradient id="cardEdge" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="rgba(255,255,255,0.06)"/>
      <stop offset="100%" stop-color="rgba(255,255,255,0)"/>
    </linearGradient>
  </defs>

  <rect width="${W}" height="${H}" fill="url(#bg)"/>
  <rect width="${W}" height="${H}" fill="url(#glow)"/>

  <!-- Subtle border frame -->
  <rect x="40" y="40" width="${W-80}" height="${H-80}" rx="32" fill="none" stroke="rgba(201,169,97,0.15)" stroke-width="1.5"/>
  <rect x="40" y="40" width="${W-80}" height="${H-80}" rx="32" fill="none" stroke="url(#cardEdge)" stroke-width="1"/>

  <!-- Top brand row -->
  <g transform="translate(80, 100)">
    <rect width="44" height="44" rx="12" fill="${accentColor}"/>
    <text x="60" y="30" fill="#ebf2ed" font-family="-apple-system, system-ui, sans-serif" font-size="22" font-weight="600" letter-spacing="-0.5">Fairway Rivalry</text>
    <text x="60" y="52" fill="#7d918a" font-family="-apple-system, system-ui, sans-serif" font-size="13" letter-spacing="0.8" text-transform="uppercase">Every rivalry starts with one round</text>
  </g>

  <!-- Date badge -->
  <g transform="translate(${W - 80 - 200}, 100)">
    <rect width="200" height="44" rx="22" fill="rgba(255,255,255,0.05)" stroke="rgba(255,255,255,0.08)"/>
    <text x="100" y="30" fill="#c8d4ce" font-family="-apple-system, system-ui, sans-serif" font-size="16" font-weight="500" text-anchor="middle" letter-spacing="0.5">${dateStr}</text>
  </g>

  <!-- Main headline -->
  <text x="${W/2}" y="320" fill="#ebf2ed" font-family="-apple-system, system-ui, sans-serif" font-size="${headline.length > 30 ? 48 : 60}" font-weight="700" text-anchor="middle" letter-spacing="-1.5">${headline}</text>

  ${course ? `<text x="${W/2}" y="380" fill="#7d918a" font-family="-apple-system, system-ui, sans-serif" font-size="22" text-anchor="middle" letter-spacing="0.3">${subtitle}</text>` : ''}

  ${isMatchup ? `
    <!-- Score showdown -->
    <g transform="translate(${W/2}, 540)">
      <text x="-220" y="0" fill="${outcome === 'win' ? accentColor : '#7d918a'}" font-family="-apple-system, system-ui, sans-serif" font-size="28" font-weight="600" text-anchor="middle">${escapeXml(me)}</text>
      <text x="-220" y="100" fill="${outcome === 'win' ? accentColor : '#ebf2ed'}" font-family="-apple-system, system-ui, sans-serif" font-size="120" font-weight="700" text-anchor="middle" letter-spacing="-3">${myScore}</text>

      <text x="0" y="50" fill="#5d716a" font-family="-apple-system, system-ui, sans-serif" font-size="32" font-weight="500" text-anchor="middle" letter-spacing="2">VS</text>

      <text x="220" y="0" fill="${outcome === 'loss' ? accentColor : '#7d918a'}" font-family="-apple-system, system-ui, sans-serif" font-size="28" font-weight="600" text-anchor="middle">${escapeXml(friend.name)}</text>
      <text x="220" y="100" fill="${outcome === 'loss' ? accentColor : '#ebf2ed'}" font-family="-apple-system, system-ui, sans-serif" font-size="120" font-weight="700" text-anchor="middle" letter-spacing="-3">${theirScore}</text>
    </g>

    <!-- Margin badge -->
    ${margin > 0 ? `
    <g transform="translate(${W/2}, 720)">
      <rect x="-90" y="0" width="180" height="44" rx="22" fill="${accentColor}" opacity="0.15" stroke="${accentColor}" stroke-width="1.5"/>
      <text x="0" y="30" fill="${accentColor}" font-family="-apple-system, system-ui, sans-serif" font-size="18" font-weight="600" text-anchor="middle" letter-spacing="0.5">
        ${outcome === 'win' ? 'WIN BY' : 'LOSE BY'} ${margin}
      </text>
    </g>
    ` : ''}
  ` : `
    <!-- Solo score display -->
    <g transform="translate(${W/2}, 540)">
      <text x="0" y="0" fill="${accentColor}" font-family="-apple-system, system-ui, sans-serif" font-size="180" font-weight="700" text-anchor="middle" letter-spacing="-5">${round.total || '—'}</text>
      ${round.differential != null ? `<text x="0" y="60" fill="#7d918a" font-family="-apple-system, system-ui, sans-serif" font-size="22" text-anchor="middle">Differential ${round.differential.toFixed(1)}</text>` : ''}
    </g>
  `}

  ${funFact ? `
    <!-- Fun fact -->
    <g transform="translate(${W/2}, ${isMatchup ? 850 : 780})">
      <rect x="-450" y="-50" width="900" height="100" rx="20" fill="rgba(201,169,97,0.08)" stroke="rgba(201,169,97,0.25)" stroke-width="1.5"/>
      <text x="0" y="-12" fill="#c9a961" font-family="-apple-system, system-ui, sans-serif" font-size="13" font-weight="600" text-anchor="middle" letter-spacing="2">DID YOU KNOW</text>
      <text x="0" y="22" fill="#ebf2ed" font-family="-apple-system, system-ui, sans-serif" font-size="${funFact.length > 60 ? 22 : 26}" font-weight="500" text-anchor="middle">${escapeXml(funFact)}</text>
    </g>
  ` : ''}

  <!-- Bottom watermark -->
  <text x="${W/2}" y="${H - 70}" fill="#5d716a" font-family="-apple-system, system-ui, sans-serif" font-size="14" font-weight="500" text-anchor="middle" letter-spacing="4">FAIRWAY.GOLF</text>
</svg>`;
}

function escapeXml(s) {
  return String(s || '').replace(/[<>&"']/g, c => ({ '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&apos;' }[c]));
}

async function svgToPngBlob(svgString) {
  return new Promise((resolve, reject) => {
    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = 1080;
      canvas.height = 1080;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, 1080, 1080);
      URL.revokeObjectURL(url);
      canvas.toBlob(b => resolve(b), 'image/png');
    };
    img.onerror = reject;
    img.src = url;
  });
}

async function downloadCardAsPNG(svgString, filename) {
  try {
    const blob = await svgToPngBlob(svgString);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
    showToast("Card saved ✓");
  } catch (e) {
    showToast("Couldn't generate image: " + e.message, true);
  }
}

function profileSettings() { return activeProfile()?.settings || {}; }

