window.irSendEmail = async function () {
  const email = (document.getElementById('ir-email')?.value || '').trim();
  if (!email) { showToast('Enter an email', true); return; }
  if (window.fairwayCloud?.sendFriendInvite) {
    const r = await window.fairwayCloud.sendFriendInvite({ email });
    if (r && r.error) showToast('Invite failed: ' + r.error, true);
    else { showToast('Invite sent to ' + email); closeModal(); }
  } else showToast('Sign in to send invites', true);
};
window.irSendSms = function () {
  const phone = (document.getElementById('ir-phone')?.value || '').trim();
  const link = (typeof inviteLink === 'function') ? inviteLink() : (location.origin + location.pathname);
  const me = (activeProfile()?.name) || 'A friend';
  const body = encodeURIComponent(`${me} added you on Fairway Rivalry — sign up to start: ${link}`);
  window.open(`sms:${phone}?&body=${body}`, '_blank');
};
window.irCopyLink = function () {
  const link = (typeof inviteLink === 'function') ? inviteLink() : (location.origin + location.pathname);
  if (navigator.clipboard) navigator.clipboard.writeText(link).then(() => showToast('Invite link copied'));
};
window.openRivalCard = function (id) {
  const f = (state.friends || []).find(x => x.id === id); if (!f) return;
  const rounds = (state.rounds || []).filter(r => (r.friends || []).includes(id));
  let w = 0, l = 0;
  rounds.forEach(r => { if (r.opponentScore == null || r.total == null) return; if (r.total < r.opponentScore) w++; else if (r.total > r.opponentScore) l++; });
  const rv = (state.rivalries || []).find(r => r.friendId === id);
  const sr = (typeof computeStakeRecord === 'function') ? computeStakeRecord(id) : { count: 0 };
  const winRate = (w + l) ? Math.round(w / (w + l) * 100) : null;
  const lastDate = rounds.length ? rounds.map(r => r.date).filter(Boolean).sort().slice(-1)[0] : null;
  let bigWin = null;
  rounds.forEach(r => { if (r.opponentScore != null && r.total != null && r.total < r.opponentScore) { const m = r.opponentScore - r.total; if (!bigWin || m > bigWin) bigWin = m; } });
  const streak = (typeof clubhouseStreak === 'function') ? clubhouseStreak(rounds) : null;
  const bestSub = lastDate ? 'last ' + fmtDate(lastDate) : 'none yet';
  openModal(`
    <div class="player-card pc-cardified">
      <div class="pc-head">
        <div class="pc-avatar pc-avatar-sm">${avatarMarkup(f.avatar || 'golfer', 64)}</div>
        <div class="pc-head-meta">
          <div class="pc-name">${f.name}</div>
          <div class="pc-headline">
            <span class="pc-hc-chip">HC ${f.hcp != null ? f.hcp : '\u2014'}</span>
            ${f.homeClub ? `<span class="pc-club-chip">${f.homeClub}</span>` : '<span class="pc-club-chip muted">No home club</span>'}
          </div>
        </div>
      </div>
      <div class="rival-wall-eyebrow">Your head-to-head</div>
      <div class="ch-stat3 pc-mini-grid">
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">RECORD</div><div class="ch-wall-num-s">${w}&ndash;${l}</div><div class="ch-wall-sub">you vs them</div></div>
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">ROUNDS</div><div class="ch-wall-num-s">${rounds.length}</div><div class="ch-wall-sub">${rounds.length ? 'together' : 'play one'}</div></div>
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">WIN RATE</div><div class="ch-wall-num-s">${winRate != null ? winRate + '%' : '\u2014'}</div><div class="ch-wall-sub">${winRate != null ? 'your edge' : '\u2014'}</div></div>
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">STREAK</div><div class="ch-wall-num-s">${streak || '\u2014'}</div><div class="ch-wall-sub">${streak ? (streak[0] === 'W' ? 'on a roll' : 'bounce back') : '\u2014'}</div></div>
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">BIGGEST WIN</div><div class="ch-wall-num-s">${bigWin != null ? '+' + bigWin : '\u2014'}</div><div class="ch-wall-sub">${bestSub}</div></div>
        <div class="ch-wall-tile"><div class="ch-wall-eyebrow-s">STAKES</div><div class="ch-wall-num-s">${sr.count ? (sr.won||0)+'\u2013'+(sr.lost||0) : '\u2014'}</div><div class="ch-wall-sub">${sr.count ? 'won\u2013lost' : 'none'}</div></div>
      </div>
      ${sr.count ? `<div class="pc-stake-row"><span>Stakes &middot; <b>Won ${sr.won} · Lost ${sr.lost}</b>${sr.net ? ` · ${sr.net>0?'+':''}${sr.net}` : ''}</span><button class="btn btn-ghost btn-small" onclick="settleStakes('${id}')">Settle up</button></div>` : ''}
      <div class="pc-actions" style="margin-top:14px">
        <button class="btn btn-gold" style="flex:1" onclick="closeModal(); activateTab('rivalry')">View rivalry</button>
        <button class="btn btn-ghost" style="flex:1" onclick="closeModal()">Close</button>
      </div>
    </div>
  `);
};

