window.bulkAddRivals = function () {
  openModal(`
    <div style="text-align:center; padding:4px 0">
      <div class="section-eyebrow">BULK ADD</div>
      <h2 style="margin:6px 0 8px">Add multiple rivals</h2>
      <p style="color:var(--muted); font-size:13px; max-width:340px; margin:0 auto 14px">One name per line. You can add emails / phones later from each rival's card.</p>
    </div>
    <textarea id="bulk-rivals" rows="8" style="width:100%; padding:14px; background:var(--panel-2); border:1px solid var(--gold-dim); border-radius:10px; color:var(--text); font-family:inherit; font-size:14px; resize:vertical; margin-bottom:14px" placeholder="Petter&#10;Lars&#10;Anna&#10;Kevin" autofocus></textarea>
    <button class="btn btn-gold" style="width:100%; padding:14px; font-weight:700" onclick="bulkAddRivalsSubmit()">Add all</button>
    <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="closeModal()">Cancel</button>
  `);
  setTimeout(() => document.getElementById('bulk-rivals')?.focus(), 50);
};
window.bulkAddRivalsSubmit = function () {
  const raw = (document.getElementById('bulk-rivals')?.value || '').trim();
  if (!raw) { showToast('Add at least one name', true); return; }
  const names = raw.split(/\n/).map(s => s.trim()).filter(Boolean);
  const existingNames = new Set((state.friends || []).map(f => (f.name || '').toLowerCase()));
  let added = 0, skipped = 0;
  names.forEach(n => {
    if (existingNames.has(n.toLowerCase())) { skipped++; return; }
    state.friends.push({ id: uid(), name: n, hcp: null });
    existingNames.add(n.toLowerCase());
    added++;
  });
  saveState();
  closeModal();
  renderFriends();
  showToast(`Added ${added} rival${added === 1 ? '' : 's'}${skipped ? ', skipped ' + skipped + ' duplicates' : ''}`);
};

