$("#s-test-api").addEventListener("click", async () => {
  const key = $("#s-api-key").value.trim();
  const scheme = $("#s-api-auth").value;
  const base = ($("#s-api-base").value.trim() || "https://api.golfcourseapi.com").replace(/\/+$/, "");
  if (!key) { showToast("Paste API key first", true); return; }
  showToast("Testing...");
  try {
    const res = await fetch(`${base}/v1/search?search_query=oslo`, {
      headers: { "Authorization": `${scheme} ${key}` }
    });
    if (res.ok) showToast("Connection OK ✓");
    else if (res.status === 401 || res.status === 403) showToast("Invalid key or auth format - try the other", true);
    else showToast(`Feil: ${res.status} ${res.statusText}`, true);
  } catch (e) {
    showToast("Network/CORS error — start golf-proxy.py and set Base URL to http://localhost:8765", true);
  }
});
