// Community courses export - bidragene dine til delingen
function exportCommunityCourses() {
  const communityCourses = state.courses.filter(c => c.userContributed);
  if (communityCourses.length === 0) {
    showToast("You have no community contributions to export", true);
    return;
  }
  const payload = {
    type: "fairway-community-courses",
    version: 1,
    exportedAt: new Date().toISOString(),
    exportedBy: activeProfile()?.name || "anonymous",
    courses: communityCourses,
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `fairway-community-${todayISO()}.json`; a.click();
  URL.revokeObjectURL(url);
  showToast(`${communityCourses.length} community-baner eksportert ✓`);
}
window.exportCommunityCourses = exportCommunityCourses;

$("#s-export-csv").addEventListener("click", () => {
  const lines = [["Dato","Bane","Land","Tee","CR","Slope","Par","Score","Stableford","Differensial","Medspillere","Notater"]];
  state.rounds.map(buildRoundComputed).forEach(r => {
    const c = getCourse(r.courseId);
    const tee = c ? getTee(c, r.teeName) : null;
    const friends = (r.friends||[]).map(fid => frFindFriend(fid)?.name).filter(Boolean).join("; ");
    lines.push([r.date, c?.name||'', c?.country||'', r.teeName, tee?.cr||'', tee?.slope||'', c?.par||'', r.total||'', r.stableford||'', r.differential != null ? r.differential.toFixed(1) : '', friends, (r.notes||'').replace(/[\n\r]/g,' ')]);
  });
  const csv = lines.map(row => row.map(cell => {
    const s = String(cell);
    return /[,"\n]/.test(s) ? `"${s.replace(/"/g,'""')}"` : s;
  }).join(",")).join("\n");
  const blob = new Blob(["﻿" + csv], { type: 'text/csv;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `golf-runder-${todayISO()}.csv`; a.click();
  URL.revokeObjectURL(url);
});

$("#s-import-file").addEventListener("change", e => {
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = ev => {
    try {
      const imported = JSON.parse(ev.target.result);
      // Type 1: Full backup
      if (imported.profiles && imported.courses) {
        if (!confirm("Erstatt ALL eksisterende data med importert backup?")) return;
        state = imported;
        saveState();
        refreshProfileAliases();
        renderHeader();
        showToast("Backup imported ✓");
        activateTab('dashboard');
        return;
      }
      // Type 2: Community courses pack
      if (imported.type === "fairway-community-courses" && Array.isArray(imported.courses)) {
        const existing = new Set(state.courses.map(c => c.name.toLowerCase()));
        const toAdd = imported.courses.filter(c => !existing.has(c.name.toLowerCase()));
        if (toAdd.length === 0) { showToast("You already have all these courses."); return; }
        if (!confirm(`Add ${toAdd.length} community courses from ${imported.exportedBy || 'unknown'}?`)) return;
        toAdd.forEach(c => state.courses.push({...c, id: uid()}));
        saveState();
        renderCourses();
        showToast(`${toAdd.length} community-baner importert ✓`);
        return;
      }
      // Type 3: Legacy v1 format
      if (imported.courses && imported.rounds) {
        if (!confirm("Erstatt all eksisterende data med importert data?")) return;
        state = imported;
        saveState();
        refreshProfileAliases();
        renderHeader();
        showToast("Data imported!");
        activateTab('dashboard');
        return;
      }
      throw new Error("Filen er ikke gyldig Fairway Rivalry-format");
    } catch (err) {
      showToast("Couldn't import: " + err.message, true);
    }
  };
  reader.readAsText(file);
});

