/* =====================================================
   INSIGHTS TAB - kreative KPIer
   ===================================================== */

function getTimeOfDayBucket(timeStr) {
  // Buckets are in English now
  if (!timeStr) return null;
  const h = parseInt(timeStr.split(":")[0]);
  if (h < 8) return "🌅 Early morning";
  if (h < 11) return "☕ Morning";
  if (h < 14) return "🌤️ Midday";
  if (h < 17) return "🌞 Afternoon";
  return "🌆 Evening";
}
const TOD_ORDER = ["🌅 Early morning", "☕ Morning", "🌤️ Midday", "🌞 Afternoon", "🌆 Evening"];

function getDayOfWeek(dateStr) {
  const d = new Date(dateStr);
  const days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  return days[d.getDay()];
}
const DOW_ORDER = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];

function getSeason(dateStr) {
  const m = new Date(dateStr).getMonth() + 1;
  if (m >= 3 && m <= 5) return "🌱 Spring";
  if (m >= 6 && m <= 8) return "☀️ Summer";
  if (m >= 9 && m <= 11) return "🍂 Autumn";
  return "❄️ Winter";
}

function average(arr) {
  const a = arr.filter(x => x != null && !isNaN(x));
  return a.length ? a.reduce((s,x) => s+x, 0) / a.length : null;
}
function stddev(arr) {
  const a = arr.filter(x => x != null && !isNaN(x));
  if (a.length < 2) return null;
  const m = average(a);
  return Math.sqrt(a.reduce((s,x) => s + (x-m)**2, 0) / a.length);
}

let insightCharts = {};
function destroyInsightCharts() {
  Object.values(insightCharts).forEach(c => c?.destroy?.());
  insightCharts = {};
}

