function fglFmtRel(date) {
  if (!date) return '';
  const d = new Date(date), now = new Date();
  const days = Math.floor((now - d) / 86400000);
  if (days <= 0) return 'today';
  if (days === 1) return 'yesterday';
  if (days < 14) return `${days}d ago`;
  return `${Math.floor(days / 7)}w ago`;
}

// Drama cards on the FGL tab — six bites of story instead of just numbers
function buildDramaCards(standings, me, year) {
  if (!standings || standings.length < 2) return '';
  const cards = [];
  const leader = standings[0];
  if (leader && !leader.isMe) cards.push({ icon: '👑', eyebrow: 'CURRENT LEADER', text: `<strong>${leader.name}</strong> leads the ${year} season with ${leader.points} pts` });
  else if (leader && leader.isMe) cards.push({ icon: '👑', eyebrow: 'YOU LEAD', text: `You lead the ${year} season with ${leader.points} pts — defend it` });

  if (me) {
    const ahead = standings.filter(p => p.rank < me.rank).pop();
    if (ahead) cards.push({ icon: '🎯', eyebrow: 'RIVAL TO CATCH', text: `You're <strong>${ahead.points - me.points} pts behind ${ahead.name}</strong> — beat them once and you might pass them` });

    // Biggest scalp (mine this season)
    if (me.biggestWinOpp) cards.push({ icon: '🔥', eyebrow: 'YOUR BIGGEST SCALP', text: `Beat <strong>${me.biggestWinOpp}</strong> for +${me.biggestWinPts} rating` });

    // Revenge match — someone who beat me last and I haven't beaten back since
    if (me.recentResults && me.recentResults.length) {
      const lastLoss = me.recentResults.find(r => r.result === 'L');
      if (lastLoss) cards.push({ icon: '⚔', eyebrow: 'REVENGE AVAILABLE', text: `<strong>${lastLoss.opp}</strong> beat you ${fglFmtRel(lastLoss.date)}. Play them again` });
    }
  }

  // Form king
  const formKing = [...standings].sort((a, b) => b.form - a.form)[0];
  if (formKing && formKing.form > 0) cards.push({ icon: '📈', eyebrow: 'FORM KING', text: `<strong>${formKing.isMe ? 'You' : formKing.name}</strong> ${formKing.isMe ? 'have' : 'has'} the best form this season (${formKing.form} / 100)` });

  // Most dangerous — best last-5 streak
  const dangerous = [...standings].map(p => ({ ...p, w5: (p.last5 || []).filter(r => r === 'W').length })).sort((a, b) => b.w5 - a.w5)[0];
  if (dangerous && dangerous.w5 >= 3) cards.push({ icon: '⚠', eyebrow: 'MOST DANGEROUS', text: `<strong>${dangerous.isMe ? 'You' : dangerous.name}</strong> ${dangerous.isMe ? 'have' : 'has'} won ${dangerous.w5} of ${(dangerous.last5 || []).length} recent matches` });

  if (!cards.length) return '';
  return `<div class="drama-grid">${cards.slice(0, 6).map(c =>
    `<div class="drama-card"><div class="drama-icon">${c.icon}</div><div><div class="drama-eyebrow">${c.eyebrow}</div><div class="drama-text">${c.text}</div></div></div>`
  ).join('')}</div>`;
}


