window.doCreateLeague = async function (year) {
  const me = activeProfile();
  if (!me) return closeModal();
  const name = (document.getElementById('lg-name')?.value || '').trim() || `League ${year}`;
  const fmtBtn = document.querySelector('#lg-format .lg-fmt-btn.selected');
  const format = fmtBtn ? fmtBtn.dataset.fmt : 'season';
  const periodStart = document.getElementById('lg-start')?.value || (year + '-01-01');
  const periodEnd = document.getElementById('lg-end')?.value || (year + '-12-31');
  const list = leaguesGet();
  // Try cloud first so we get the canonical, globally-unique code
  let cloudData = null;
  if (window.fairwayCloud?.isLoggedIn?.() && window.fairwayCloud.createLeague) {
    try {
      const res = await window.fairwayCloud.createLeague({ name, year });
      if (!res.error && res.data) cloudData = res.data;
    } catch (e) { console.warn('cloud createLeague', e); }
  }
  // Local fallback (also adopt cloud code if we got one)
  let code = cloudData?.code || genLeagueCode();
  while (!cloudData && list.some(l => l.code === code)) code = genLeagueCode();
  const league = {
    id: cloudData?.id || 'lg' + Date.now().toString(36),
    cloudId: cloudData?.id || null,
    code,
    name,
    year,
    format,
    periodStart,
    periodEnd,
    ownerId: me.id,
    ownerName: me.name,
    createdAt: cloudData?.created_at || new Date().toISOString(),
    members: [{ userId: me.id, name: me.name, role: 'owner', joinedAt: new Date().toISOString(), status: 'active' }]
  };
  list.push(league);
  leaguesSet(list);
  closeModal();
  try { renderFGL?.(); } catch (e) {}
  shareLeagueInvite(league.id, true);
};

