function caddiePickGreeting(name) {
  const tpl = CADDIE_GREETINGS[Math.floor(Math.random() * CADDIE_GREETINGS.length)];
  return tpl.replace(/\{name\}/g, name);
}

// Short, in-character opening report — looks at form, last round, biggest leak
function caddieOpeningReport() {
  try {
    const { rounds, hcp } = caddieData();
    if (!rounds.length) {
      return `You haven't logged a round yet — once you do, I'll have something real to say. Until then: <strong>warm up your wedges</strong> before every range session and you'll see strokes drop faster than any swing change.`;
    }
    const last = rounds[0];
    const lastDate = new Date(last.date);
    const days = Math.floor((Date.now() - lastDate) / 86400000);
    const last5 = rounds.slice(0, 5);
    const avg = last5.reduce((s, r) => s + r.differential, 0) / last5.length;
    const lastDiff = last.differential;
    let line = '';
    if (hcp != null) line += `Your index sits at <span class="cd-stat">${hcp}</span>. `;
    if (days <= 1) line += `Yesterday's differential was <span class="cd-stat">${lastDiff.toFixed(1)}</span>${lastDiff < avg ? ' — sharper than your recent average. Build on it.' : ' — a touch off your run; nothing structural.'} `;
    else if (days <= 7) line += `Last round (${days}d ago) came in at <span class="cd-stat">${lastDiff.toFixed(1)}</span>. `;
    else line += `It's been <span class="cd-stat">${days}d</span> since your last round — let's not let the rust set in. `;
    // Tactical tip rotation
    const TIPS = [
      "Quick fix for a slice: <strong>strengthen the grip</strong> (lead hand shows 2 knuckles) and feel the toe release through impact.",
      "Want longer carries? <strong>Tee it higher</strong> and clip up on the driver — +3° attack angle is worth 8–10 yards.",
      "Bleeding strokes around the green? Default to your <strong>lowest-loft chip</strong> that carries the fringe and runs out.",
      "Three-putts haunting you? Drill <strong>lag putts to a 1m circle</strong> for 10 minutes before every round.",
      "Wedge yardages should gap every <strong>4–6° of loft</strong> — get them precise and you stop guessing from 100m.",
      "Pre-shot routine: <strong>pick a precise target</strong>, one rehearsal, step in, one look, go. Every time.",
      "The fairway is wider than you think. Aim at the <strong>fat of the green</strong>, not the pin, unless you're under 130m.",
      "Wind in your face? <strong>Take more club and swing easy.</strong> Lower flight, less drift.",
      "Bogey from trouble is a great score. <strong>Don't compound mistakes</strong> chasing the hero shot.",
      "From 50–100m the strokes hide. <strong>One wedge, one rehearsal, one tempo</strong> — that's the work."
    ];
    line += TIPS[Math.floor(Math.random() * TIPS.length)];
    return line;
  } catch (e) {
    console.warn('caddieOpeningReport', e);
    return '';
  }
}

const CADDIE_BELL = `<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M6 9a6 6 0 0 1 12 0c0 4.5 1.8 5.5 1.8 5.5H4.2S6 13.5 6 9Z"/><path d="M10 20a2 2 0 0 0 4 0"/></svg>`;
const CADDIE_BELL_OFF = `<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M8.5 4.6A6 6 0 0 1 18 9c0 2.7 0.8 4.1 1.4 4.9M16 17H4.2S6 13.5 6 9c0-.5.06-1 .18-1.46"/><path d="M10 20a2 2 0 0 0 4 0"/><line x1="3" y1="3" x2="21" y2="21"/></svg>`;
