function rwzTeamDefaultColor(pid, idx) { if (pid === '__me__') return 'a'; return (idx <= 0) ? 'a' : 'b'; }
function rwzTeamColorOf(pid, idx) { const m = (window.roundFormState && window.roundFormState.teamColors) || {}; return m[pid] || rwzTeamDefaultColor(pid, idx); }
