function clubhouseSummaryLine(d) {
  const parts = [];
  const total = (d.wins || 0) + (d.losses || 0);
  if (total > 0) {
    if (d.wins > d.losses) parts.push(`You're on top this season at ${d.wins}\u2013${d.losses}`);
    else if (d.wins < d.losses) parts.push(`You're chasing at ${d.wins}\u2013${d.losses} this season`);
    else parts.push(`All square at ${d.wins}\u2013${d.losses} this season`);
  } else {
    parts.push(`No ranked rounds yet \u2014 challenge a rival to start your season`);
  }
  if (d.roundsPlayed) parts.push(`${d.roundsPlayed} round${d.roundsPlayed === 1 ? '' : 's'} logged`);
  if (d.hcp != null) parts.push(`handicap ${Number(d.hcp).toFixed(1)}`);
  if (d.streak && /^[WL]\d+$/.test(d.streak)) {
    const t = d.streak[0], n = parseInt(d.streak.slice(1), 10);
    if (n >= 2) parts.push(`on a ${n}-${t === 'W' ? 'win' : 'loss'} streak`);
  }
  return parts.join(' \u00b7 ') + '.';
}
