/* === Clubhouse stat helpers === */
function clubhouseStreak(raw) {
  const h2h = (raw || []).filter(r => r.opponentScore != null && r.total != null)
    .sort((a, b) => new Date(b.date) - new Date(a.date));
  if (!h2h.length) return null;
  const resOf = r => r.total < r.opponentScore ? 'W' : (r.total > r.opponentScore ? 'L' : 'T');
  const first = resOf(h2h[0]);
  if (first === 'T') return 'T';
  let n = 0;
  for (const r of h2h) { if (resOf(r) === first) n++; else break; }
  return first + n;
}
function clubhouseStrongestCourse(built) {
  const groups = {};
  (built || []).forEach(r => { const c = getCourse(r.courseId); if (c) (groups[c.name] = groups[c.name] || []).push(r.differential); });
  let bc = null;
  Object.entries(groups).forEach(([n, ds]) => { const a = ds.reduce((s, x) => s + x, 0) / ds.length; if (bc == null || a < bc.avg) bc = { name: n, avg: a }; });
  return bc ? bc.name.split(' ')[0] : null;
}
function clubhouseNextMilestone(roundsPlayed) {
  const ladder = [1, 5, 10, 25, 50, 100];
  const next = ladder.find(n => n > roundsPlayed);
  if (!next) return { label: 'Legend', sub: '100+ rounds' };
  return { label: next + ' rounds', sub: (next - roundsPlayed) + ' to go' };
}

