/* === Shared clubhouse stat computation (used by panel + detail modals) === */
function clubhouseStatData() {
  const p = activeProfile() || {};
  const raw = (p.rounds || []);
  const rounds = raw.map(buildRoundComputed).filter(r => r.differential != null);
  const hcp = p.settings?.manualHcp != null ? p.settings.manualHcp : (rounds.length ? calcHcpIndex(rounds) : null);
  const totals = raw.filter(r => r.total != null);
  const best = totals.reduce((b, r) => !b || r.total < b.total ? r : b, null);
  let wins = 0, losses = 0;
  { const _rr = (typeof frTotalRivalRecord==='function') ? frTotalRivalRecord() : {wins:0,losses:0}; wins = _rr.wins; losses = _rr.losses; }
  const streak = clubhouseStreak(raw);
  const strong = clubhouseStrongestCourse(rounds);
  const roundsPlayed = raw.length;
  const bd = rounds.reduce((b, r) => !b || r.differential < b.differential ? r : b, null);
  const h2h = {};
  raw.forEach(r => {
    let res = null;
    if (r.winner === 'me') res = 'w'; else if (r.winner === 'opp') res = 'l';
    else if (r.opponentScore != null && r.total != null) res = r.total < r.opponentScore ? 'w' : (r.total > r.opponentScore ? 'l' : null);
    if (!res) return;
    (r.friends || []).forEach(fid => { const o = h2h[fid] = h2h[fid] || { w: 0, l: 0 }; o[res]++; });
  });
  // Nemesis = the rival you've played the MOST rounds against
  const playCount = {};
  raw.forEach(r => (r.friends || []).forEach(fid => { playCount[fid] = (playCount[fid] || 0) + 1; }));
  let nemesis = null, ownRival = null;
  Object.entries(playCount).forEach(([fid, n]) => {
    const f = frFindFriend(fid); if (!f) return;
    const o = h2h[fid] || { w: 0, l: 0 };
    if (nemesis == null || n > nemesis.n) nemesis = { name: f.name.split(' ')[0], n, w: o.w, l: o.l, net: o.w - o.l };
  });
  let birdies = 0, pars = 0, scored = 0;
  rounds.forEach(r => (r.holes || []).forEach(h => { if (h && h.score != null) { scored++; const d = h.score - (h.par || 4); if (d <= -1) birdies++; else if (d === 0) pars++; } }));
  const sig = scored ? (birdies / scored > 0.10 ? 'Birdie maker' : (pars / scored > 0.42 ? 'Steady par' : 'Battler')) : '\u2014';
  // Front 9 / Back 9 strength (avg over/under par per nine)
  let f9 = 0, f9n = 0, b9 = 0, b9n = 0;
  rounds.forEach(r => (r.holes || []).forEach((h, i) => { if (h && h.score != null) { const d = h.score - (h.par || 4); if (i < 9) { f9 += d; f9n++; } else { b9 += d; b9n++; } } }));
  const f9avg = f9n ? f9 / f9n : null, b9avg = b9n ? b9 / b9n : null;
  let nine = '\u2014', nineSub = 'play hole-by-hole';
  if (f9avg != null && b9avg != null) { if (f9avg <= b9avg) { nine = 'Front 9'; nineSub = `${(b9avg - f9avg).toFixed(2)} better/hole`; } else { nine = 'Back 9'; nineSub = `${(f9avg - b9avg).toFixed(2)} better/hole`; } }
  const earnedRows = (typeof evaluateAchievements === 'function' ? evaluateAchievements() : []).filter(a => a.earned);
  const jewelObj = earnedRows.reduce((b, a) => (!b || (a.tierIdx || 0) > (b.tierIdx || 0)) ? a : b, null);
  const jewel = jewelObj ? (jewelObj.title || '\u2014') : '\u2014';
  const formH2H = raw.filter(r => r.opponentScore != null && r.total != null).sort((a, b) => new Date(b.date) - new Date(a.date)).slice(0, 5);
  const form = formH2H.length ? formH2H.map(r => r.total < r.opponentScore ? 'W' : (r.total > r.opponentScore ? 'L' : '\u00bd')).join(' ') : (streak || '\u2014');
  return { hcp, best, wins, losses, streak, strong, roundsPlayed, bd, nemesis, ownRival, sig, jewel, jewelObj, nine, nineSub, form, scored, birdies, pars };
}

/* === Real stats panel for users who have rounds (new layout #112, clickable #121) === */
function renderClubhouseInnerStats() {
  const d = clubhouseStatData();
  const tile = (key, label, val, sub) => `<div class="ch-wall-tile ch-tap" onclick="openStatDetail('${key}')"><div class="ch-wall-eyebrow-s">${label}</div><div class="ch-wall-num-s">${val}</div><div class="ch-wall-sub">${sub}</div></div>`;
  const _earned = (typeof evaluateAchievements === 'function' ? evaluateAchievements() : []).filter(a => a.earned);
  const _best = d.jewelObj || _earned.slice().sort((a, b) => (b.tierIdx || 0) - (a.tierIdx || 0))[0];
  const _ldesc = _best ? (_best.desc || '').replace(/^[A-Za-z]+:\s*/, '') : '';
  const hero = _best ? `
    <div class="ch-trophy-hero ch-tap" onclick="activateTab('trophies')">
      <div class="ch-trophy-ic">${(typeof ICON_TROPHY !== 'undefined') ? ICON_TROPHY : '\ud83c\udfc6'}</div>
      <div class="ch-trophy-meta">
        <div class="ch-trophy-eyebrow">BEST ACHIEVEMENT${_best.tierLabel ? ' \u00b7 ' + _best.tierLabel.toUpperCase() : ''}</div>
        <div class="ch-trophy-name">${_best.title || '\u2014'}</div>
        <div class="ch-trophy-desc">${_ldesc || 'A trophy on your wall.'}</div>
      </div>
    </div>` : '';
  return `
    <div class="ch-stat3 ch-stat4">
      ${tile('hcp', 'YOUR HC', d.hcp != null ? Number(d.hcp).toFixed(1) : '\u2014', 'tap for 20-round history')}
      ${tile('rounds', 'ROUNDS PLAYED', d.roundsPlayed, 'total logged')}
      ${tile('lowhcp', 'LOWEST HCP PLAYED', d.bd ? d.bd.differential.toFixed(1) : '\u2014', d.bd ? (getCourse(d.bd.courseId)?.name?.split(' ')[0] || fmtDate(d.bd.date)) : 'best differential')}
      ${tile('lowscore', 'LOWEST ROUND', d.best?.total ?? '\u2014', d.best?.date ? fmtDate(d.best.date) : 'your best round')}
      ${tile('nemesis', 'NEMESIS', d.nemesis ? d.nemesis.name : '\u2014', d.nemesis ? d.nemesis.n + ' rounds together' : 'play a rival')}
      ${tile('course', 'OWNED COURSE', d.strong || '\u2014', d.strong ? 'best scoring course' : 'play one a few times')}
      ${tile('nine', 'STRONGER NINE', d.nine, d.nineSub)}
      ${tile('jewel', 'BEST TROPHY', d.jewel || '\u2014', (d.jewelObj && d.jewelObj.tierLabel) ? d.jewelObj.tierLabel : 'your rarest')}
    </div>
    <div class="ch-bs-wrap">${(typeof renderBreakscore==='function')?renderBreakscore((activeProfile()&&activeProfile().rounds)||[]):''}</div>
  `;
}

window.openStatDetail = function (key) {
  if (key === 'hcp') { try { return openHcOverview(); } catch (e) {} }
  const d = clubhouseStatData();
  const M = {
    record: ['Record this season', `${d.wins}\u2013${d.losses}`, 'Your head-to-head wins and losses across every rival this season. Win a ranked round against a rival to move it.'],
    rounds: ['Rounds played', String(d.roundsPlayed), 'Every round you have logged. Keep logging to sharpen your handicap and unlock trophies.'],
    form: ['Current form', d.form, 'Your last five head-to-head results against rivals, newest first \u2014 W is a win, L a loss, \u00bd a tie. Several Ws in a row means you are peaking right now.'],
    lowhcp: ['Lowest HCP played', d.bd ? d.bd.differential.toFixed(1) : '\u2014', d.bd ? `Your best score differential, set at ${getCourse(d.bd.courseId)?.name || 'a course'} on ${fmtDate(d.bd.date)}.` : 'Play rated rounds to record your best differential.'],
    lowscore: ['Lowest score', d.best?.total != null ? String(d.best.total) : '\u2014', d.best?.date ? `Your lowest round, shot on ${fmtDate(d.best.date)}.` : 'Your best gross round will show here.'],
    nemesis: ['Nemesis', d.nemesis ? d.nemesis.name : '\u2014', d.nemesis ? `The rival you have faced the most \u2014 ${d.nemesis.n} rounds together, ${d.nemesis.w}\u2013${d.nemesis.l} in your favour.` : 'Play a rival a few times to name your nemesis.'],
    course: ['Owned course', d.strong || '\u2014', d.strong ? `The course you score best on by average differential \u2014 your home turf.` : 'Play a course a few times to claim it.'],
    jewel: ['Crown jewel', d.jewel, d.jewelObj ? `${(d.jewelObj.desc||'').replace(/^[A-Za-z]+:\\s*/,'')} \u2014 one of your rarest trophies.` : 'Win trophies to fill your cabinet.'],
    nine: ['Stronger nine', d.nine, d.nine !== '\u2014' ? `You score better on your ${d.nine.toLowerCase()} \u2014 ${d.nineSub}.` : 'Log hole-by-hole rounds to reveal which nine you own.'],
  };
  const m = M[key]; if (!m) return;
  openModal(`<div style="text-align:center">
    <div class="section-eyebrow" style="margin-bottom:6px">${m[0].toUpperCase()}</div>
    <div style="font-family:Georgia,serif;font-size:40px;font-weight:700;color:var(--gold-bright);line-height:1.1;margin:4px 0 8px">${m[1]}</div>
    <p style="color:var(--muted);font-size:14px;line-height:1.55;max-width:330px;margin:0 auto 14px">${m[2]}</p>
    <button class="btn btn-ghost" style="width:100%" onclick="closeModal()">Close</button>
  </div>`);
};

