  const mF=me.split(/\s+/)[0], tF=fr.split(/\s+/)[0];
  const avg=a=>{a=a.filter(v=>v!=null);return a.length?a.reduce((s,x)=>s+x,0)/a.length:null;};
  const myS=[],thS=[];
  ms.forEach(m=>{const r=m.round||{};const mv=(r.total!=null)?r.total:m.myVal;const tv=(r.opponentScore!=null)?r.opponentScore:m.theirVal;if(mv!=null)myS.push(mv);if(tv!=null)thS.push(tv);});
  const myAvg=avg(myS),thAvg=avg(thS);
  const myLow=myS.length?Math.min.apply(null,myS):null, thLow=thS.length?Math.min.apply(null,thS):null;
  let f9=[0,0],b9=[0,0],hbhN=0;
  ms.forEach(m=>{const r=m.round;if(!r||!r.holes||!r.opponentHoles)return;let fm=0,ft=0,bm=0,bt=0,ok=false;for(let i=0;i<18;i++){const a=r.holes[i],b=r.opponentHoles[i];if(!a||a.score==null||!b||b.score==null)continue;ok=true;if(i<9){fm+=a.score;ft+=b.score;}else{bm+=a.score;bt+=b.score;}}if(!ok)return;hbhN++;if(fm<ft)f9[0]++;else if(ft<fm)f9[1]++;if(bm<bt)b9[0]++;else if(bt<bm)b9[1]++;});
  const seq=ms.filter(m=>!m.tie).map(m=>m.won?'W':'L');
  let curStreak=0,curC='';for(let i=seq.length-1;i>=0;i--){if(!curC){curC=seq[i];curStreak=1;}else if(seq[i]===curC)curStreak++;else break;}
  let longW=0,longL=0,run=0,rc='';seq.forEach(c=>{if(c===rc)run++;else{rc=c;run=1;}if(c==='W')longW=Math.max(longW,run);else longL=Math.max(longL,run);});
  const margins=ms.filter(m=>!m.tie&&m.myVal!=null&&m.theirVal!=null).map(m=>Math.abs(m.myVal-m.theirVal));
  const avgMargin=margins.length?margins.reduce((s,x)=>s+x,0)/margins.length:null;
  const biggest=margins.length?Math.max.apply(null,margins):null, closest=margins.length?Math.min.apply(null,margins):null;
  const byC={};ms.forEach(m=>{let nm=(m.round&&m.round.courseName)||'';if(!nm&&typeof getCourse==='function'&&m.round){const c=getCourse(m.round.courseId);nm=c&&c.name||'';}if(!nm)return;const c=byC[nm]=byC[nm]||{w:0,l:0,n:0};c.n++;if(!m.tie){if(m.won)c.w++;else c.l++;}});
