  const bestCourse=courseArr.filter(c=>c.w>c.l).sort((a,b)=>(b.w-b.l)-(a.w-a.l))[0]||null;
  const wxName={sun:'Sunny',partial:'Partly cloudy',cloud:'Cloudy',overcast:'Overcast',rain:'Rain',heavy_rain:'Heavy rain',wind:'Windy',storm:'Storm'};
  const byWx={};ms.forEach(m=>{const w=m.round&&m.round.weather;if(!w||m.tie)return;const x=byWx[w]=byWx[w]||{w:0,l:0};if(m.won)x.w++;else x.l++;});
  const rec=pred=>{let w=0,l=0;ms.forEach(m=>{if(m.tie)return;if(!pred(m.round||{}))return;if(m.won)w++;else l++;});return{w,l};};
  const warmup=rec(r=>r.warmup&&['no','none','0',''].indexOf(String(r.warmup))<0);
  const walked=rec(r=>['walk','walked','foot'].indexOf(String(r.transport))>=0);
  const sober=rec(r=>!r.alcohol||['none','no','0',''].indexOf(String(r.alcohol))>=0);
  const slAvg=g=>{const a=ms.map(m=>{const r=m.round||{};if(!g(r))return null;return (r.total!=null)?r.total:m.myVal;}).filter(v=>v!=null);return a.length?a.reduce((s,x)=>s+x,0)/a.length:null;};
  const sleepHi=slAvg(r=>r.sleep!=null&&r.sleep!==''&&Number(r.sleep)>=8), sleepLo=slAvg(r=>r.sleep!=null&&r.sleep!==''&&Number(r.sleep)<8);
