  ms.forEach(m=>{const r=m.round||{};if(!r.stake)return;bets++;const amt=Number(r.stakeAmount)||1;const won=m.won&&!m.tie;const sign=m.tie?0:(won?1:-1);const t=String(r.stake).toLowerCase();
    if(/beer|drink|pint|ale/.test(t))drinks+=sign*amt;else if(/dinner|food|meal|burger|lunch/.test(t))meals+=sign*amt;else if(/green|fee/.test(t))fees+=sign*amt;else{cash+=sign*amt;if(won){lifetime+=amt;if(amt>biggestWon)biggestWon=amt;}}});
