  const courseTop = `<div class="rv-exp-stats rv2col">
    ${cell(D.bestCourse?D.bestCourse.nm:'—',D.mF+' best course')}
    ${cell(D.mostPlayed?D.mostPlayed.nm:'—','Most played')}
  </div>`;
  // Conditions
  const wxKeys=Object.keys(D.byWx);
  const condBody = wxKeys.length ? wxKeys.map(w=>{const x=D.byWx[w];const own=x.w>x.l?D.mF:(x.l>x.w?D.tF:'Even');return `<div class="rv-dim"><span class="rv-dim-l">${D.wxName[w]||w}</span><span class="rv-dim-v">${own==='Even'?('Even '+x.w+'–'+x.l):(own+' '+Math.max(x.w,x.l)+'–'+Math.min(x.w,x.l))}</span></div>`;}).join('') : '<div class="rv-dim-note">Log the weather on your rounds to unlock who wins in sun, rain and wind.</div>';
  // Lifestyle
