  if(D.walked.w+D.walked.l) lifeBits.push(`<div class="rv-dim"><span class="rv-dim-l">Walking the course</span><span class="rv-dim-v">${D.mF} ${D.walked.w}–${D.walked.l}</span></div>`);
  if(D.sober.w+D.sober.l) lifeBits.push(`<div class="rv-dim"><span class="rv-dim-l">No alcohol</span><span class="rv-dim-v">${D.mF} ${D.sober.w}–${D.sober.l}</span></div>`);
  if(D.sleepHi!=null&&D.sleepLo!=null) lifeBits.push(`<div class="rv-dim"><span class="rv-dim-l">8+ hrs sleep</span><span class="rv-dim-v">${D.sleepHi.toFixed(1)} avg vs ${D.sleepLo.toFixed(1)}</span></div>`);
  const lifeBody = lifeBits.length ? lifeBits.join('') : '<div class="rv-dim-note">Fill in sleep, warm-up and how you got there before a round — the app starts spotting your patterns.</div>';
  // Betting
