/* ============================================================
   NARRATIVE ENGINE — sports-commentary style facts from data
   ============================================================ */
function computeNarratives(rounds, rivalry) {
  const out = [];
  const rs = (rounds || []).filter(r => !r.gameKind || r.gameKind === 'golf').map(buildRoundComputed);
  if (!rs.length) return out;
  const sorted = [...rs].sort((a, b) => new Date(b.date) - new Date(a.date));

  // 1. Active win streak overall
  let winStreak = 0;
  for (const r of sorted) {
    const w = _didIWin(r);
    if (w === true) winStreak++;
    else if (w === false) break;
  }
  if (winStreak >= 3) out.push({ icon: 'streak', text: `${winStreak} straight wins.` });

  // 2. Per-rival narratives (when rivalry filter is supplied)
  if (rivalry) {
    const rvRounds = sorted.filter(r => (r.friends||[]).includes(rivalry.friendId));
    const wins = rvRounds.filter(r => _didIWin(r) === true).length;
    const losses = rvRounds.filter(r => _didIWin(r) === false).length;
    const friendName = (state.friends||[]).find(f => f.id === rivalry.friendId)?.name || 'them';

    // Last-N record
    const last5 = rvRounds.slice(0, 5);
    const last5Wins = last5.filter(r => _didIWin(r) === true).length;
    if (last5.length >= 3 && last5Wins >= 3) {
      out.push({ icon: 'battle', text: `You've won ${last5Wins} of the last ${last5.length} rounds against ${friendName}.` });
    }
    if (last5.length >= 3 && (last5.length - last5Wins) >= 3) {
      out.push({ icon: 'battle', text: `${friendName} has won ${last5.length - last5Wins} of the last ${last5.length}.` });
    }

    // Wind-specific
    const windWins = rvRounds.filter(r => _didIWin(r) === true && ['strong','extreme','noticeable'].includes(r.windCat));
    const windLosses = rvRounds.filter(r => _didIWin(r) === false && ['strong','extreme','noticeable'].includes(r.windCat));
    if (windWins.length >= 2 && windWins.length >= 2 * windLosses.length) {
      out.push({ icon: 'form', text: `You dominate in the wind: ${windWins.length} wins to ${windLosses.length} losses.` });
    }

    // Cold/rain pattern
    const rainWins = rvRounds.filter(r => _didIWin(r) === true && ['rain','heavy_rain'].includes(r.weather));
    if (rainWins.length >= 2) {
      out.push({ icon: 'streak', text: `You've beaten ${friendName} ${rainWins.length} times in the rain.` });
    }

    // Course-specific dominance
    const byCourse = {};
    rvRounds.forEach(r => { if (r.courseId) (byCourse[r.courseId] = byCourse[r.courseId] || []).push(r); });
    Object.entries(byCourse).forEach(([cid, list]) => {
      if (list.length < 3) return;
      const w = list.filter(r => _didIWin(r) === true).length;
      const courseName = getCourse(cid)?.name;
      if (w >= 3 && w === list.length) {
        out.push({ icon: 'course', text: `You own ${courseName}. Every round against ${friendName} there has gone your way.` });
      } else if (w === 0 && list.length >= 3) {
        out.push({ icon: 'course', text: `${friendName} owns ${courseName}. You haven't won there in ${list.length} attempts.` });
      }
    });

    // Days since they won
    const theirLastWin = rvRounds.find(r => _didIWin(r) === false);
    if (theirLastWin) {
      const days = Math.floor((Date.now() - new Date(theirLastWin.date)) / 86400000);
      if (days >= 90) out.push({ icon: 'milestone', text: `${friendName} hasn't beaten you in ${days} days.` });
    } else if (rvRounds.length >= 3) {
      out.push({ icon: 'crown', text: `${friendName} has never beaten you. You're a perfect ${wins}-0.` });
    }

    // Close-match clutch
    const closeWins = rvRounds.filter(r => _didIWin(r) === true && r.opponentScore != null && r.total != null && Math.abs(r.total - r.opponentScore) <= 2).length;
    const closeLosses = rvRounds.filter(r => _didIWin(r) === false && r.opponentScore != null && r.total != null && Math.abs(r.total - r.opponentScore) <= 2).length;
    const closeTotal = closeWins + closeLosses;
    if (closeTotal >= 3) {
      const pct = Math.round((closeWins / closeTotal) * 100);
      if (pct >= 70) out.push({ icon: 'spark', text: `You win ${pct}% of close matches against ${friendName}.` });
      if (pct <= 30) out.push({ icon: 'spark', text: `${friendName} edges you in close matches (${closeTotal - closeWins}-${closeWins}).` });
    }
  }

  // 3. Solo-mode narratives (when no rivalry)
  if (!rivalry) {
    // Trend over last 5 vs prior 5
    const last5 = sorted.slice(0, 5).filter(r => r.differential != null);
    const prior5 = sorted.slice(5, 10).filter(r => r.differential != null);
    if (last5.length >= 3 && prior5.length >= 3) {
      const a = last5.reduce((s,r) => s+r.differential, 0) / last5.length;
      const b = prior5.reduce((s,r) => s+r.differential, 0) / prior5.length;
      const delta = b - a;
      if (delta > 2) out.push({ icon: 'form', text: `Your differential is down ${delta.toFixed(1)} over your last 5 rounds. Form is climbing.` });
      if (delta < -2) out.push({ icon: 'form', text: `Your last 5 are ${Math.abs(delta).toFixed(1)} above your prior 5. Time to refocus.` });
    }

    // Best course
    const byCourseSolo = {};
    rs.forEach(r => { if (r.courseId && r.differential != null) (byCourseSolo[r.courseId] = byCourseSolo[r.courseId] || []).push(r.differential); });
    let bestCourse = null;
    Object.entries(byCourseSolo).forEach(([cid, diffs]) => {
      if (diffs.length < 3) return;
      const avg = diffs.reduce((a,b) => a+b, 0) / diffs.length;
      if (!bestCourse || avg < bestCourse.avg) bestCourse = { cid, avg, n: diffs.length };
    });
    if (bestCourse) {
      const name = getCourse(bestCourse.cid)?.name;
      if (name) out.push({ icon: 'course', text: `You play best at ${name} — avg differential ${bestCourse.avg.toFixed(1)} over ${bestCourse.n} rounds.` });
    }
  }

  return out.slice(0, 6);
}

function renderNarratives(narratives, opts) {
  if (!narratives || !narratives.length) return '';
  const title = opts?.title || 'FAIRWAY INSIGHTS';
  return `
    <div class="narrative-block">
      <div class="narrative-label">${title}</div>
      <ul class="narrative-list">
        ${narratives.map(n => `<li><span class="narrative-icon">${typeof fgIcon === 'function' ? fgIcon(n.icon || 'spark') : ''}</span><span class="narrative-text">${n.text}</span></li>`).join('')}
      </ul>
    </div>`;
}

function computeRivalryStats(rv) {
  // Only golf rounds count toward the main rivalry — minigames/other are handled separately.
  const rounds = (state.rounds || []).map(buildRoundComputed)
    .filter(r => frRoundHasFriend(r, rv.friendId))
    .filter(r => r.date >= rv.startDate && r.date <= rv.endDate)
    .filter(r => r.rivalryId === rv.id || !r.rivalryId)
    .filter(r => !r.gameKind || r.gameKind === 'golf'); // golf-only here

  let myScore = 0, theirScore = 0;
  const matches = [];
  rounds.forEach(r => {
    // Hole Winner (points) round — count by points won.
    if (r.holePoints) {
      const mp = r.myPoints || 0, op = r.oppPoints || 0;
      if (mp === 0 && op === 0) return;
      matches.push({ round: r, myVal: mp, theirVal: op, won: mp > op, tie: mp === op });
      return;
    }
    // Match play (per-hole) takes precedence when both have HBH data
    if (r.matchPlay && r.holes && r.opponentHoles) {
      let myH = 0, theirH = 0;
      r.holes.forEach((h, i) => {
        const opp = r.opponentHoles[i];
        if (!h?.score || !opp?.score) return;
        if (h.score < opp.score) myH++;
        else if (h.score > opp.score) theirH++;
      });
      if (myH === 0 && theirH === 0) return;
      const won = myH > theirH;
      const tie = myH === theirH;
      matches.push({ round: r, myVal: myH, theirVal: theirH, won, tie, matchPlay: true });
      return;
    }

    let myVal, theirVal, won, tie;
    // Derive opponent_differential from opponent_score using same CR/Slope as round
    let oppDiff = r.opponentDifferential;
    if (oppDiff == null && r.opponentScore != null) {
      const c = getCourse(r.courseId);
      const tee = c ? getTee(c, r.teeName) : null;
      if (tee?.cr && tee?.slope) {
        oppDiff = calcDifferential(r.opponentScore, tee.cr, tee.slope);
      }
    }
    if (rv.format === 'lowest_diff' || rv.format === 'best_avg') {
      myVal = r.differential;
      theirVal = oppDiff;
    } else if (rv.format === 'stroke_play') {
      myVal = r.total;
      theirVal = r.opponentScore;
    } else if (rv.format === 'stableford') {
      myVal = r.stableford;
      theirVal = r.opponentStableford;
    }
    // Fallback: round logged with an explicit winner but no opponent score still counts as a head-to-head result
    if ((myVal == null || theirVal == null) && (r.winner === 'me' || r.winner === 'opp' || r.winner === 'tie')) {
      matches.push({ round: r, myVal: null, theirVal: null, won: r.winner === 'me', tie: r.winner === 'tie', winnerOnly: true });
      return;
    }
    if (myVal == null || theirVal == null) return;
    if (rv.format === 'stableford') {
      // higher is better
      won = myVal > theirVal;
      tie = myVal === theirVal;
    } else {
      // lower is better
      won = myVal < theirVal;
      tie = myVal === theirVal;
    }
    matches.push({ round: r, myVal, theirVal, won, tie });
  });

  if (rv.format === 'best_avg') {
    const myVals = matches.map(m => m.myVal).filter(v => v != null);
    const theirVals = matches.map(m => m.theirVal).filter(v => v != null);
    myScore = myVals.length ? Number((myVals.reduce((s,x)=>s+x,0)/myVals.length).toFixed(1)) : 0;
    theirScore = theirVals.length ? Number((theirVals.reduce((s,x)=>s+x,0)/theirVals.length).toFixed(1)) : 0;
    // for best_avg, lower wins so flip display
    { const _f = (state.friends||[]).find(f => f.id === rv.friendId); if (_f) { myScore += (_f.baseWins||0); theirScore += (_f.baseLosses||0); } }
  return { myScore, theirScore, rounds: matches.length, matches, lowerWins: true };
  }
  matches.forEach(m => {
    if (m.tie) { myScore += 0.5; theirScore += 0.5; }
    else if (m.won) myScore += 1;
    else theirScore += 1;
  });
  { const _f = (state.friends||[]).find(f => f.id === rv.friendId); if (_f) { myScore += (_f.baseWins||0); theirScore += (_f.baseLosses||0); } }
  return { myScore, theirScore, rounds: matches.length, matches, lowerWins: false };
}

function rivalryRich(stats) {
  const ms = (stats && stats.matches) || [];
  const wins = ms.filter(m => m.won && !m.tie).length;
  const losses = ms.filter(m => !m.won && !m.tie).length;
  const ties = ms.filter(m => m.tie).length;
  const winRate = ms.length ? Math.round(wins / ms.length * 100) : 0;
  const margins = ms.filter(m => !m.tie).map(m => Math.abs((m.myVal ?? 0) - (m.theirVal ?? 0)));
  const avgMargin = margins.length ? margins.reduce((a, x) => a + x, 0) / margins.length : null;
  let streak = 0, sc = '';
  for (let k = ms.length - 1; k >= 0; k--) { const m = ms[k]; if (m.tie) break; const c = m.won ? 'W' : 'L'; if (!sc) { sc = c; streak = 1; } else if (c === sc) streak++; else break; }
  const streakTxt = streak ? sc + streak : '—';
  const form = ms.slice(-5).map(m => m.tie ? 'T' : (m.won ? 'W' : 'L'));
  const myS = ms.map(m => m.round?.total ?? m.myVal).filter(v => v != null);
  const thS = ms.map(m => m.round?.opponentScore ?? m.theirVal).filter(v => v != null);
  const myAvg = myS.length ? myS.reduce((a, x) => a + x, 0) / myS.length : null;
  const theirAvg = thS.length ? thS.reduce((a, x) => a + x, 0) / thS.length : null;
  let biggest = null, toughest = null, closest = null;
  ms.forEach(m => {
    if (m.tie) return;
    const margin = Math.abs((m.myVal ?? 0) - (m.theirVal ?? 0));
    if (m.won) { if (!biggest || margin > biggest.margin) biggest = { margin, m }; }
    else { if (!toughest || margin > toughest.margin) toughest = { margin, m }; }
    if (!closest || margin < closest.margin) closest = { margin, m };
  });
  return { wins, losses, ties, winRate, avgMargin, streakTxt, form, myAvg, theirAvg, biggest, toughest, closest };
}
function rivalryNarrative(r, me, fname) {
  if (!r || (r.wins + r.losses + r.ties) === 0) return 'No rounds yet — play one and the story starts here.';
  const am = r.avgMargin || 0;
  const tight = am < 3 ? 'Razor-thin' : (am < 6 ? 'Competitive' : 'One-sided');
  const who = r.wins > r.losses ? (me + ' usually edges it') : (r.wins < r.losses ? (fname + ' usually edges it') : 'Dead even');
  return `${tight} — decided by an average of ${am.toFixed(1)} strokes. ${who} (${r.winRate}% wins for ${me}).`;
}
function rvFormDots(form) {
  return ((form && form.length) ? form : ['—']).map(f => `<span class="rv-fdot ${f === 'W' ? 'w' : f === 'L' ? 'l' : ''}">${f}</span>`).join('');
}

/* Minigame / other-game standings (separate ledger; only includes ones that count) */
function computeMinigameStandings(rv) {
  const games = (state.rounds || [])
    .filter(r => frRoundHasFriend(r, rv.friendId))
    .filter(r => r.date >= rv.startDate && r.date <= rv.endDate)
    .filter(r => r.gameKind && r.gameKind !== 'golf')
    .sort((a, b) => new Date(b.date) - new Date(a.date));
  const counting = games.filter(g => g.countsInRivalry);
  const offBooks = games.filter(g => !g.countsInRivalry);
  let myWins = 0, theirWins = 0, ties = 0;
  counting.forEach(g => {
    if (g.winner === 'me') myWins++;
    else if (g.winner === 'opp') theirWins++;
    else if (g.winner === 'tie') ties++;
  });
  let myOffWins = 0, theirOffWins = 0, offTies = 0;
  offBooks.forEach(g => {
    if (g.winner === 'me') myOffWins++;
    else if (g.winner === 'opp') theirOffWins++;
    else if (g.winner === 'tie') offTies++;
  });
  return {
    counting, offBooks,
    counts: { myWins, theirWins, ties, total: counting.length },
    offBooksCounts: { myWins: myOffWins, theirWins: theirOffWins, ties: offTies, total: offBooks.length },
  };
}

// ===================== RIVALRY CHALLENGES — discreet, in-the-rivalry ====================
const CHALLENGE_TYPES = {
  lowest_gross: { label: 'Lowest gross score', desc: 'Lowest single round during the period wins', metric: 'gross' },
  lowest_net: { label: 'Lowest net score', desc: 'Handicap-adjusted lowest round wins', metric: 'net' },
  most_rounds: { label: 'Most rounds', desc: 'Whoever plays the most rounds wins', metric: 'count' },
  best_stableford: { label: 'Best Stableford', desc: 'Highest single Stableford during the period wins', metric: 'stableford' },
  lowest_avg_diff: { label: 'Lowest average differential', desc: 'Best avg differential over the period', metric: 'avg_diff' },
  closest_to_par: { label: 'Closest to par', desc: 'Smallest single-round over-par result wins', metric: 'closest_par' },
  custom: { label: 'Custom (manual)', desc: 'You decide the winner together at the end', metric: 'manual' }
};
const CHALLENGE_PERIODS = {
  this_week: { label: 'This week', days: 7 },
  this_month: { label: 'This month', days: 30 },
  next_round: { label: 'Next single round', days: 14 },
  two_weeks: { label: 'Two weeks', days: 14 }
};

function renderChallengeStrip(rv) {
  const ch = (rv.challenges || []).filter(c => c.status === 'active');
  const pending = (rv.challenges || []).filter(c => c.status === 'awaiting_result');
  const total = ch.length + pending.length;
  return `<div class="ch-strip" onclick="openChallenges('${rv.id}')">
    <div class="ch-strip-icon">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><path d="M 6 3 L 18 3 L 18 9 Q 18 14 12 15 Q 6 14 6 9 Z"/><path d="M 9 21 L 15 21 L 14 16 L 10 16 Z"/></svg>
    </div>
    <div class="ch-strip-body">
      <div class="ch-strip-title">Challenges</div>
      <div class="ch-strip-sub">${total === 0 ? 'Add a side-bet to spice up the rivalry' : `${ch.length} active${pending.length ? ' · ' + pending.length + ' awaiting result' : ''}`}</div>
    </div>
    <div class="ch-strip-cta">${total === 0 ? '+ New' : 'Open →'}</div>
  </div>`;
}

window.openChallenges = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const friend = state.friends.find(f => f.id === rv.friendId);
  const fname = friend?.name || 'Rival';
  const me = activeProfile()?.name || 'You';
  const list = rv.challenges || [];
  const active = list.filter(c => c.status === 'active');
  const awaiting = list.filter(c => c.status === 'awaiting_result');
  const done = list.filter(c => c.status === 'completed');

  openModal(`
    <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:10px">
      <div><div class="section-eyebrow">CHALLENGES</div><h2 style="margin:2px 0 0">${me} vs ${fname}</h2></div>
      <button class="btn btn-ghost btn-small" onclick="closeModal()">Close</button>
    </div>
    <button class="btn btn-gold" style="width:100%; padding:13px; margin-bottom:14px; font-weight:700" onclick="newChallengeFlow('${rvId}')">+ New challenge</button>
    ${active.length ? '<div class="ch-section-h">ACTIVE</div>' + active.map(c => renderChallengeCard(rv, c, me, fname)).join('') : ''}
    ${awaiting.length ? '<div class="ch-section-h">AWAITING RESULT</div>' + awaiting.map(c => renderChallengeCard(rv, c, me, fname)).join('') : ''}
    ${done.length ? '<div class="ch-section-h">COMPLETED</div>' + done.slice(-5).reverse().map(c => renderChallengeCard(rv, c, me, fname)).join('') : ''}
    ${list.length === 0 ? '<p style="color:var(--muted); font-size:13px; text-align:center; padding:14px 0">No challenges yet. Try "Lowest round this week" for a quick one.</p>' : ''}
  `);
};

function renderChallengeCard(rv, c, me, fname) {
  const type = CHALLENGE_TYPES[c.type] || {};
  const period = CHALLENGE_PERIODS[c.period] || { label: 'Custom' };
  const now = new Date();
  const end = new Date(c.endsAt);
  const daysLeft = Math.max(0, Math.ceil((end - now) / 86400000));
  let status = '';
  if (c.status === 'active') status = daysLeft === 0 ? 'Ends today' : `${daysLeft}d left`;
  else if (c.status === 'awaiting_result') status = 'Pending winner confirm';
  else if (c.status === 'completed') status = `Won by ${c.winner === 'me' ? me : c.winner === 'them' ? fname : 'Tied'}`;
  const progress = computeChallengeProgress(rv, c);
  return `<div class="ch-card ${c.status}">
    <div class="ch-card-head">
      <div class="ch-card-name">${c.name || type.label}</div>
      <div class="ch-card-status">${status}</div>
    </div>
    <div class="ch-card-meta">${type.label} · ${period.label} · ${c.prizePoints || 1}pt to winner</div>
    ${progress ? `<div class="ch-progress">
      <div class="ch-progress-row">
        <span>${me}</span><strong>${progress.meValue == null ? '—' : progress.meValue}</strong>
      </div>
      <div class="ch-progress-row">
        <span>${fname}</span><strong>${progress.themValue == null ? '—' : progress.themValue}</strong>
      </div>
      ${progress.leader ? `<div class="ch-leader">${progress.leader === 'me' ? me : fname} leading</div>` : ''}
    </div>` : ''}
    ${c.status === 'active' && daysLeft === 0 ? `<button class="btn btn-gold" style="width:100%; margin-top:10px" onclick="resolveChallenge('${rv.id}','${c.id}')">Resolve now</button>` : ''}
    ${c.status === 'awaiting_result' ? `<div class="ch-pending-row">
      <div class="ch-pending-text">${c.proposedByName || 'Someone'} says <strong>${c.proposedWinner === 'me' ? me : c.proposedWinner === 'them' ? fname : 'tie'}</strong> won. Accept?</div>
      <div style="display:flex; gap:6px">
        <button class="btn btn-gold btn-small" onclick="acceptChallengeResult('${rv.id}','${c.id}')">Accept</button>
        <button class="btn btn-ghost btn-small" onclick="rejectChallengeResult('${rv.id}','${c.id}')">Reject</button>
      </div>
    </div>` : ''}
  </div>`;
}

function computeChallengeProgress(rv, c) {
  // Find rounds in period for me and for friend
  const rounds = (state.rounds || []).filter(r =>
    new Date(r.date) >= new Date(c.startsAt) &&
    new Date(r.date) <= new Date(c.endsAt) &&
    (r.gameKind === 'golf' || r.gameKind === 'simulator' || !r.gameKind)
  );
  const myRounds = rounds.map(buildRoundComputed);
  const friendId = rv.friendId;
  const friendRounds = rounds.filter(r => r.friends && r.friends.includes(friendId));
  let meValue = null, themValue = null;
  const type = c.type;
  function bestBy(arr, getter, dir) {
    let best = null;
    arr.forEach(r => { const v = getter(r); if (v == null) return; if (best == null || (dir === 'min' ? v < best : v > best)) best = v; });
    return best;
  }
  if (type === 'lowest_gross') {
    meValue = bestBy(myRounds, r => r.total, 'min');
    themValue = bestBy(friendRounds, r => r.opponentScore, 'min');
  } else if (type === 'lowest_net') {
    meValue = bestBy(myRounds, r => r.differential, 'min');
    themValue = bestBy(friendRounds, r => r.opponentDifferential, 'min');
    if (meValue != null) meValue = Math.round(meValue * 10) / 10;
    if (themValue != null) themValue = Math.round(themValue * 10) / 10;
  } else if (type === 'most_rounds') {
    meValue = myRounds.length;
    themValue = friendRounds.length;
  } else if (type === 'best_stableford') {
    meValue = bestBy(myRounds, r => r.stableford, 'max');
    themValue = bestBy(friendRounds, r => r.opponentStableford, 'max');
  } else if (type === 'lowest_avg_diff') {
    const md = myRounds.map(r => r.differential).filter(x => x != null);
    const td = friendRounds.map(r => r.opponentDifferential).filter(x => x != null);
    meValue = md.length ? Math.round((md.reduce((s,x)=>s+x,0)/md.length) * 10) / 10 : null;
    themValue = td.length ? Math.round((td.reduce((s,x)=>s+x,0)/td.length) * 10) / 10 : null;
  } else if (type === 'closest_to_par') {
    function over(r) { const c = getCourse(r.courseId); const tee = c && r.teeName ? c.tees.find(t => t.name === r.teeName) : null; const par = (tee && tee.par) || (c && c.par) || 72; return r.total != null ? Math.abs(r.total - par) : null; }
    function overOpp(r) { const c = getCourse(r.courseId); const tee = c && r.teeName ? c.tees.find(t => t.name === r.teeName) : null; const par = (tee && tee.par) || (c && c.par) || 72; return r.opponentScore != null ? Math.abs(r.opponentScore - par) : null; }
    meValue = bestBy(myRounds, over, 'min');
    themValue = bestBy(friendRounds, overOpp, 'min');
  } else {
    return null; // custom, no auto-progress
  }
  let leader = null;
  if (meValue != null && themValue != null) {
    const lowerWins = (type === 'lowest_gross' || type === 'lowest_net' || type === 'lowest_avg_diff' || type === 'closest_to_par');
    if (meValue === themValue) leader = null;
    else if (lowerWins) leader = meValue < themValue ? 'me' : 'them';
    else leader = meValue > themValue ? 'me' : 'them';
  } else if (meValue != null) leader = 'me';
  else if (themValue != null) leader = 'them';
  return { meValue, themValue, leader };
}

window.newChallengeFlow = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  closeModal();
  setTimeout(() => {
    const typeOpts = Object.entries(CHALLENGE_TYPES).map(([k, v]) => `<option value="${k}">${v.label} — ${v.desc}</option>`).join('');
    const periodOpts = Object.entries(CHALLENGE_PERIODS).map(([k, v]) => `<option value="${k}">${v.label}</option>`).join('');
    openModal(`
      <div style="text-align:center; padding:4px 0">
        <div class="section-eyebrow">NEW CHALLENGE</div>
        <h2 style="margin:6px 0 8px">Add a side-bet</h2>
      </div>
      <label class="field" style="margin-bottom:10px"><span>Type</span>
        <select id="ch-type">${typeOpts}</select>
      </label>
      <label class="field" style="margin-bottom:10px"><span>Period</span>
        <select id="ch-period">${periodOpts}</select>
      </label>
      <label class="field" style="margin-bottom:10px"><span>Custom name <span style="color:var(--muted-2)">— optional</span></span>
        <input id="ch-name" type="text" placeholder="e.g. Best of the boys">
      </label>
      <label class="field" style="margin-bottom:14px"><span>Prize</span>
        <input id="ch-prize" type="number" value="1" min="1" max="10">
        <small style="color:var(--muted-2); font-size:11px">Points awarded to the manual standings</small>
      </label>
      <button class="btn btn-gold" style="width:100%; padding:13px; font-weight:700" onclick="createChallenge('${rvId}')">Send to ${(state.friends.find(f=>f.id===rv.friendId)?.name) || 'rival'}</button>
      <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="openChallenges('${rvId}')">← Back</button>
    `);
  }, 100);
};

window.createChallenge = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const type = document.getElementById('ch-type').value;
  const periodKey = document.getElementById('ch-period').value;
  const name = (document.getElementById('ch-name').value || '').trim();
  const prize = parseInt(document.getElementById('ch-prize').value || '1', 10);
  const period = CHALLENGE_PERIODS[periodKey];
  const start = new Date();
  const end = new Date(start.getTime() + period.days * 86400000);
  rv.challenges = rv.challenges || [];
  rv.challenges.push({
    id: 'ch' + Date.now().toString(36),
    name: name || CHALLENGE_TYPES[type].label,
    type, period: periodKey,
    startsAt: start.toISOString(),
    endsAt: end.toISOString(),
    prizePoints: prize,
    status: 'active',
    createdBy: activeProfile()?.id || '__me__',
    createdByName: activeProfile()?.name || 'You'
  });
  saveState();
  showToast('Challenge sent ⚔');
  openChallenges(rvId);
};

window.resolveChallenge = function (rvId, chId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const c = (rv.challenges || []).find(x => x.id === chId);
  if (!c) return;
  const friend = state.friends.find(f => f.id === rv.friendId);
  const progress = computeChallengeProgress(rv, c);
  const me = activeProfile()?.name || 'You';
  const fname = friend?.name || 'Rival';
  const auto = progress ? progress.leader : null;
  const suggested = auto || 'me';
  closeModal();
  setTimeout(() => {
    openModal(`
      <div style="text-align:center; padding:4px 0">
        <div class="section-eyebrow">RESOLVE</div>
        <h2 style="margin:6px 0 8px">${c.name}</h2>
        <p style="color:var(--muted); font-size:13px; max-width:340px; margin:0 auto 14px">Both players need to agree on the result.</p>
      </div>
      <div class="ch-resolve-row">
        <button class="btn ch-res-btn ${suggested==='me'?'on':''}" data-r="me" onclick="chPick('me')">${me} won</button>
        <button class="btn ch-res-btn ${suggested==='tie'?'on':''}" data-r="tie" onclick="chPick('tie')">Tied</button>
        <button class="btn ch-res-btn ${suggested==='them'?'on':''}" data-r="them" onclick="chPick('them')">${fname} won</button>
      </div>
      <input type="hidden" id="ch-pick" value="${suggested}">
      <button class="btn btn-gold" style="width:100%; padding:14px; font-weight:700; margin-top:14px" onclick="proposeChallengeWinner('${rvId}','${chId}')">Submit for ${fname} to confirm</button>
      <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="openChallenges('${rvId}')">← Back</button>
    `);
  }, 100);
};
window.chPick = function (r) {
  document.querySelectorAll('.ch-res-btn').forEach(b => b.classList.toggle('on', b.dataset.r === r));
  document.getElementById('ch-pick').value = r;
};

window.proposeChallengeWinner = function (rvId, chId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const c = (rv.challenges || []).find(x => x.id === chId);
  if (!c) return;
  c.status = 'awaiting_result';
  c.proposedWinner = document.getElementById('ch-pick').value;
  c.proposedBy = activeProfile()?.id || '__me__';
  c.proposedByName = activeProfile()?.name || 'You';
  saveState();
  showToast('Result sent for confirm');
  openChallenges(rvId);
};

window.acceptChallengeResult = function (rvId, chId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const c = (rv.challenges || []).find(x => x.id === chId);
  if (!c) return;
  c.status = 'completed';
  c.winner = c.proposedWinner;
  c.completedAt = new Date().toISOString();
  // Award prize points to manual standings (auto-propose)
  if (c.winner !== 'tie' && c.prizePoints) {
    const ms = rv.manualStandings || { me: 0, friend: 0 };
    const delta = c.prizePoints;
    const newScore = {
      me: ms.me + (c.winner === 'me' ? delta : 0),
      friend: ms.friend + (c.winner === 'them' ? delta : 0)
    };
    rv.manualHistory = rv.manualHistory || [];
    if (rv.manualStandings) rv.manualHistory.push({ ...rv.manualStandings, replacedAt: new Date().toISOString() });
    rv.manualStandings = { me: newScore.me, friend: newScore.friend, confirmedAt: new Date().toISOString(), confirmedBy: ['__both__'], history: rv.manualHistory };
  }
  saveState();
  showToast('Challenge result locked in ✓');
  openChallenges(rvId);
};
window.rejectChallengeResult = function (rvId, chId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const c = (rv.challenges || []).find(x => x.id === chId);
  if (!c) return;
  c.status = 'active';
  delete c.proposedWinner;
  delete c.proposedBy;
  delete c.proposedByName;
  saveState();
  showToast('Result rejected');
  openChallenges(rvId);
};

// ===================== RIVALRY — manual standings + two-party confirm =====================
function renderManualStandingsCard(rv, friend, meName) {
  const ms = rv.manualStandings || null;
  const pp = rv.pendingProposal || null;
  const friendName = (friend && friend.name) || 'Rival';
  const meDisplay = meName || 'You';
  let body = '';
  if (!ms && !pp) {
    body = `<div class="rms-empty">
      <p>Track the current standing manually — for matches played before FGL, or extra side-bets.</p>
      <button class="btn btn-gold" onclick="rmsPropose('${rv.id}')">Set the current standing</button>
    </div>`;
  } else {
    const showMe = (pp ? pp.me : ms.me);
    const showOpp = (pp ? pp.friend : ms.friend);
    body = `<div class="rms-score">
      <div class="rms-side ${showMe > showOpp ? 'lead' : ''}">
        <div class="rms-name">${meDisplay}</div>
        <div class="rms-val">${showMe}</div>
      </div>
      <div class="rms-vs">vs</div>
      <div class="rms-side ${showOpp > showMe ? 'lead' : ''}">
        <div class="rms-name">${friendName}</div>
        <div class="rms-val">${showOpp}</div>
      </div>
    </div>
    ${ms ? `<div class="rms-meta">Last confirmed ${rmsDate(ms.confirmedAt)} · ${(ms.history || []).length} adjustment(s)</div>` : ''}
    ${pp ? `<div class="rms-pending">
      <div class="rms-pending-eyebrow">PROPOSED CHANGE</div>
      <div class="rms-pending-text">${pp.proposedByName || 'Someone'} proposed <strong>${meDisplay} ${pp.me} – ${pp.friend} ${friendName}</strong>${ms ? ` (was ${ms.me} – ${ms.friend})` : ''}. Both players must confirm.</div>
      <div class="rms-pending-actions">
        <button class="btn btn-gold" onclick="rmsAccept('${rv.id}')">Accept</button>
        <button class="btn btn-ghost" onclick="rmsReject('${rv.id}')">Reject</button>
      </div>
    </div>` : `
    <div class="rms-actions">
      <button class="btn btn-ghost" onclick="rmsPropose('${rv.id}')">Propose adjustment</button>
      ${(ms.history || []).length ? `<button class="btn btn-ghost" onclick="rmsHistory('${rv.id}')">History</button>` : ''}
    </div>`}`;
  }
  return renderChallengeStrip(rv) + `<div class="rms-card">
    <div class="rms-head">
      <div class="rms-eyebrow">MANUAL STANDINGS</div>
      <div class="rms-help" title="Both players confirm any change">requires both to confirm</div>
    </div>
    ${body}
  </div>`;
}
function rmsDate(d) { if (!d) return ''; const x = new Date(d); return x.toLocaleDateString(); }

window.rmsPropose = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const friend = state.friends.find(f => f.id === rv.friendId);
  const me = activeProfile()?.name || 'You';
  const cur = rv.manualStandings || { me: 0, friend: 0 };
  openModal(`
    <div style="text-align:center; padding:4px 0">
      <div class="section-eyebrow" style="margin-bottom:6px">${rv.manualStandings ? 'PROPOSE ADJUSTMENT' : 'SET CURRENT STANDING'}</div>
      <h2 style="margin:2px 0 8px">${me} vs ${friend?.name || 'Rival'}</h2>
      <p style="color:var(--muted); font-size:12px; max-width:340px; margin:0 auto 16px">${rv.manualStandings ? 'Any change will wait for the other player to accept before it locks in.' : 'Enter where the rivalry stands today. Both players will confirm to lock it.'}</p>
    </div>
    <div class="rms-input-row">
      <label class="rms-input-field">
        <span>${me}</span>
        <input type="number" id="rms-me" min="0" max="999" value="${cur.me}">
      </label>
      <div class="rms-input-dash">–</div>
      <label class="rms-input-field">
        <span>${friend?.name || 'Rival'}</span>
        <input type="number" id="rms-friend" min="0" max="999" value="${cur.friend}">
      </label>
    </div>
    <button class="btn btn-gold" style="width:100%; padding:14px; font-weight:700; margin-top:14px" onclick="rmsSubmit('${rvId}')">Submit for confirmation</button>
    <button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="closeModal()">Cancel</button>
  `);
  setTimeout(() => document.getElementById('rms-me')?.focus(), 50);
};

window.rmsSubmit = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return closeModal();
  const me = parseInt(document.getElementById('rms-me')?.value || '0', 10);
  const fr = parseInt(document.getElementById('rms-friend')?.value || '0', 10);
  if (isNaN(me) || isNaN(fr) || me < 0 || fr < 0) { showToast('Enter valid numbers', true); return; }
  const meName = activeProfile()?.name || 'You';
  rv.pendingProposal = {
    me, friend: fr,
    proposedBy: activeProfile()?.id || '__me__',
    proposedByName: meName,
    proposedAt: new Date().toISOString(),
  };
  saveState();
  closeModal();
  showRivalryDetail(rvId);
  // If this is the FIRST set ever AND nothing was locked before, treat the proposer as auto-accepting their own number; opponent still confirms.
  showToast('Proposal sent. Waiting for ' + ((state.friends.find(f => f.id === rv.friendId)?.name) || 'rival') + ' to confirm.');
};

window.rmsAccept = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv || !rv.pendingProposal) return;
  // Local-only: we treat accept as both parties having agreed once the OTHER side opens and taps Accept
  // For now (single-device local), accepting locks it in.
  const pp = rv.pendingProposal;
  rv.manualHistory = rv.manualHistory || [];
  if (rv.manualStandings) rv.manualHistory.push({ ...rv.manualStandings, replacedAt: new Date().toISOString() });
  rv.manualStandings = { me: pp.me, friend: pp.friend, confirmedAt: new Date().toISOString(), confirmedBy: ['__both__'], history: rv.manualHistory };
  delete rv.pendingProposal;
  saveState();
  showRivalryDetail(rvId);
  showToast('Standing locked in ✓');
};
window.rmsReject = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  delete rv.pendingProposal;
  saveState();
  showRivalryDetail(rvId);
  showToast('Proposal rejected');
};
window.rmsHistory = function (rvId) {
  const rv = (state.rivalries || []).find(r => r.id === rvId);
  if (!rv) return;
  const me = activeProfile()?.name || 'You';
  const friend = state.friends.find(f => f.id === rv.friendId);
  const hist = (rv.manualStandings?.history || []).slice().reverse();
  openModal(`
    <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:10px">
      <div><div class="section-eyebrow">STANDINGS HISTORY</div><h2 style="margin:2px 0 0">${rv.name}</h2></div>
      <button class="btn btn-ghost btn-small" onclick="closeModal()">Close</button>
    </div>
    ${hist.length === 0 ? '<p style="color:var(--muted); font-size:13px">No previous standings.</p>' : `
      <div class="rms-history">${hist.map(h => `<div class="rms-history-row"><div>${me} <strong>${h.me}</strong> – <strong>${h.friend}</strong> ${friend?.name || 'Rival'}</div><div class="rms-history-d">until ${rmsDate(h.replacedAt)}</div></div>`).join('')}</div>`}
  `);
};

window.showRivalryDetail = function(id) {
  const rv = (state.rivalries || []).find(r => r.id === id);
  if (!rv) return;
  const friend = state.friends.find(f => f.id === rv.friendId);
  const stats = computeRivalryStats(rv);
  const me = activeProfile().name;
  $("#rivalry-detail-panel").style.display = "";
  const matchesHtml = stats.matches.length === 0
    ? `<p style="color: var(--muted); padding: 14px 0">No rounds yet. When you play with ${friend?.name}, enter their score so the round counts in this season.</p>`
    : `<table>
        <thead><tr><th>Dato</th><th>Bane</th><th class="num">Din</th><th class="num">${friend?.name}</th><th>Resultat</th></tr></thead>
        <tbody>${stats.matches.map(m => {
          const c = getCourse(m.round.courseId);
          return `<tr>
            <td>${fmtDate(m.round.date)}</td>
            <td>${c?.name || '—'}</td>
            <td class="num" style="color: ${m.won ? 'var(--accent-bright)' : ''}">${m.myVal != null ? (typeof m.myVal === 'number' ? m.myVal.toFixed(rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0) : m.myVal) : '—'}</td>
            <td class="num" style="color: ${!m.won && !m.tie ? 'var(--accent-bright)' : ''}">${m.theirVal != null ? (typeof m.theirVal === 'number' ? m.theirVal.toFixed(rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0) : m.theirVal) : '—'}</td>
            <td>${m.tie ? '½' : m.won ? '🟢 Du vant' : `🔴 ${friend?.name} vant`}</td>
          </tr>`;
        }).join("")}</tbody>
      </table>`;
  const fname = friend?.name || "Motspiller";
  const richStats = analyzeRivalry(stats.matches, rv);

  $("#rivalry-detail").innerHTML = `
    <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 16px; flex-wrap: wrap; gap: 10px">
      <div>
        <h2 style="margin: 0">${rv.name}</h2>
        <div style="color: var(--muted); font-size: 12px; margin-top: 4px">
          ${RIVALRY_FORMATS[rv.format]?.label} · ${fmtDate(rv.startDate)} → ${fmtDate(rv.endDate)}
        </div>
        <div style="color: var(--muted); font-size: 11px; margin-top: 4px">${RIVALRY_FORMATS[rv.format]?.desc}</div>
      </div>
      <div style="display: flex; gap: 8px">
        <button class="btn btn-ghost btn-small" onclick="shareRivalry('${rv.id}')">📤 Share</button>
        <button class="btn btn-ghost btn-small" onclick="editRivalry('${rv.id}')">Edit</button>
        <button class="icon-btn" onclick="deleteRivalry('${rv.id}')">🗑️</button>
      </div>
    </div>
    ${renderManualStandingsCard(rv, friend, me)}
    ${(() => {
      const myLeading = stats.myScore > stats.theirScore;
      const tie = stats.myScore === stats.theirScore;
      const daysLeft = Math.max(0, Math.ceil((new Date(rv.endDate) - new Date()) / 86400000));
      let tagline = '';
      if (stats.matches.length === 0) tagline = 'No rounds yet. The first one is always the most memorable.';
      else if (tie) tagline = `Locked at ${stats.myScore} all. ${daysLeft} days remain.`;
      else if (myLeading) tagline = `You lead by ${stats.myScore - stats.theirScore}. ${daysLeft} days to seal it.`;
      else tagline = `Down by ${stats.theirScore - stats.myScore}. ${daysLeft} days to flip the season.`;
      // Last battle
      const lastMatch = stats.matches.length ? stats.matches[stats.matches.length - 1] : null;
      let lastBattleHTML = '';
      if (lastMatch) {
        const c = getCourse(lastMatch.round.courseId);
        const verb = lastMatch.tie ? 'tied with' : lastMatch.won ? `defeated ${fname}` : `lost to ${fname}`;
        const diff = (lastMatch.myVal != null && lastMatch.theirVal != null) ? Math.abs(lastMatch.myVal - lastMatch.theirVal) : 0;
        const margin = diff <= 1 ? 'by 1 stroke after a tight finish' : diff <= 3 ? `by ${diff.toFixed(0)} strokes` : `by ${diff.toFixed(0)} clear strokes`;
        const story = lastMatch.tie ? `Halved it ${lastMatch.myVal}–${lastMatch.theirVal} at ${c?.name || 'the course'}.` : `${me} ${verb} ${margin} at ${c?.name || 'the course'}.`;
        lastBattleHTML = `
          <div class="cine-section-label">LAST BATTLE</div>
          <div class="last-battle-card">
            <div class="last-battle-course">${fmtDate(lastMatch.round.date)} · ${c?.name || 'Course unknown'}</div>
            <div class="last-battle-story">${story}</div>
            <div class="last-battle-scores">
              <span class="lb-num ${lastMatch.won ? 'win' : ''}">${typeof lastMatch.myVal === 'number' ? lastMatch.myVal.toFixed(rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0) : lastMatch.myVal || '—'}</span>
              <span style="color:var(--muted-2)">—</span>
              <span class="lb-num ${!lastMatch.won && !lastMatch.tie ? 'win' : 'loss'}">${typeof lastMatch.theirVal === 'number' ? lastMatch.theirVal.toFixed(rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0) : lastMatch.theirVal || '—'}</span>
            </div>
          </div>`;
      }
      // Narratives
      const narratives = (typeof computeNarratives === 'function') ? computeNarratives(profileRounds(), rv) : [];
      const narrativesHTML = narratives.length ? renderNarratives(narratives, { title: 'WHAT THE NUMBERS SAY' }) : '';
      return `
        <div class="cine-rivalry">
          <div class="cine-meta">SEASON · ${daysLeft} DAYS LEFT</div>
          <div class="cine-matchup ${!myLeading && !tie ? 'losing' : ''}">
            <span class="me">${me}</span>
            <span class="cine-vs">vs</span>
            <span class="them">${fname}</span>
          </div>
          <div class="cine-score-row">
            <div class="cine-score ${myLeading ? 'win' : tie ? '' : 'loss'}">${stats.myScore}</div>
            <div class="cine-sep">—</div>
            <div class="cine-score ${!myLeading && !tie ? 'win' : tie ? '' : 'loss'}">${stats.theirScore}</div>
          </div>
          <div class="cine-tagline">${tagline}</div>
        </div>
        ${lastBattleHTML}
        ${narrativesHTML}
      `;
    })()}

    ${new Date() <= new Date(rv.endDate) ? `
    <div style="display: flex; gap: 10px; margin-bottom: 18px; flex-wrap: wrap">
      <button class="btn btn-gold" onclick="quickLogVs('${rv.friendId}')" style="flex: 1; min-width: 200px">
        + Log a round vs ${friend?.name || 'opponent'} →
      </button>
      <button class="btn btn-ghost" onclick="quickLogMinigameVs('${rv.friendId}')" style="flex: 1; min-width: 200px">
        🎲 Log a minigame
      </button>
    </div>
    ` : ''}

    ${renderRivalryStreakBanner(richStats, me, fname)}

    ${stats.matches.length > 0 ? renderRivalryRichStats(richStats, me, fname, rv) : ''}

    ${renderMinigameSection(rv, me, fname)}

    <h3 style="margin-top: 22px">Round history</h3>
    <div class="table-wrap">${stats.matches.length === 0
      ? `<p style="color: var(--muted); padding: 14px 0">No rounds yet. When you play with ${fname}, enter their score so the round counts in this season.</p>`
      : `<table>
          <thead><tr><th>Date</th><th>Course</th><th class="num">You</th><th class="num">${fname}</th><th class="num">Margin</th><th>Result</th></tr></thead>
          <tbody>${stats.matches.map(m => {
            const c = getCourse(m.round.courseId);
            const margin = m.myVal != null && m.theirVal != null ? Math.abs(m.myVal - m.theirVal).toFixed(rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0) : '—';
            const formatStr = m.matchPlay ? 0 : (rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0);
            return `<tr>
              <td>${fmtDate(m.round.date)}</td>
              <td>${c?.name || '—'}${m.matchPlay ? ' <span style="font-size:10px;color:var(--gold)">MATCH PLAY</span>' : ''}</td>
              <td class="num" style="color: ${m.won ? 'var(--accent-bright)' : ''}">${m.myVal != null ? (typeof m.myVal === 'number' ? m.myVal.toFixed(formatStr) : m.myVal) : '—'}</td>
              <td class="num" style="color: ${!m.won && !m.tie ? 'var(--accent-bright)' : ''}">${m.theirVal != null ? (typeof m.theirVal === 'number' ? m.theirVal.toFixed(formatStr) : m.theirVal) : '—'}</td>
              <td class="num">${margin}</td>
              <td>${m.tie ? '½' : m.won ? '🟢 You' : `🔴 ${fname}`}</td>
            </tr>`;
          }).join("")}</tbody>
        </table>`
    }</div>
  `;
};

window.quickLogVs = function(friendId) {
  roundFormState = { editId: null, holes: [], scoreType: 'total', selectedFriends: [friendId], gameKind: null, gameSubtype: null };
  window.roundFormState = roundFormState;
  activateTab('round');
  setTimeout(() => showRoundForm('golf'), 50);
};

window.quickLogMinigameVs = function(friendId) {
  roundFormState = { editId: null, holes: [], scoreType: 'total', selectedFriends: [friendId], gameKind: null, gameSubtype: null, _mgSelectedFriends: [friendId] };
  window.roundFormState = roundFormState;
  activateTab('round');
  setTimeout(() => showRoundForm('minigame'), 50);
};

function renderRivalryStreakBanner(stats, me, fname) {
  if (!stats || !stats.currentStreak || stats.currentStreak.count < 3) return '';
  const cs = stats.currentStreak;
  if (cs.type === 'win') {
    return `<div style="background: linear-gradient(135deg, rgba(74,222,128,0.12), rgba(201,169,97,0.08)); border: 1px solid var(--accent); border-radius: 12px; padding: 14px 18px; margin-bottom: 18px; display: flex; align-items: center; gap: 14px">
      <div style="font-size: 28px">🔥</div>
      <div>
        <div style="font-weight: 600; color: var(--accent-bright); font-size: 14px; letter-spacing: -0.01em">${cs.count}-win streak — keep it going</div>
        <div style="color: var(--muted); font-size: 12px; margin-top: 2px">You're owning ${fname} right now.</div>
      </div>
    </div>`;
  } else if (cs.type === 'loss') {
    return `<div style="background: linear-gradient(135deg, rgba(255,99,71,0.10), rgba(0,0,0,0)); border: 1px solid var(--tension); border-radius: 12px; padding: 14px 18px; margin-bottom: 18px; display: flex; align-items: center; gap: 14px">
      <div style="font-size: 28px">⚠️</div>
      <div>
        <div style="font-weight: 600; color: var(--tension); font-size: 14px; letter-spacing: -0.01em">${cs.count} losses in a row — time to break the slump</div>
        <div style="color: var(--muted); font-size: 12px; margin-top: 2px">${fname} has your number. Get back on the course.</div>
      </div>
    </div>`;
  }
  return '';
}

function renderMinigameSection(rv, me, fname) {
  const mg = computeMinigameStandings(rv);
  if (mg.counting.length === 0 && mg.offBooks.length === 0) return '';
  const renderRow = g => {
    const friend = state.friends.find(f => f.id === (g.friends||[])[0]);
    const winnerLabel = g.winner === 'me' ? '🟢 You' : g.winner === 'opp' ? `🔴 ${friend?.name || fname}` : '½ Tied';
    return `<tr>
      <td>${fmtDate(g.date)}</td>
      <td>${g.gameIcon || '🎲'} ${g.gameLabel}</td>
      <td class="num" style="font-size: 11px; color: var(--muted)">${g.myScore != null ? g.myScore : '—'}</td>
      <td class="num" style="font-size: 11px; color: var(--muted)">${g.oppScore != null ? g.oppScore : '—'}</td>
      <td>${winnerLabel}</td>
    </tr>`;
  };
  const inHtml = mg.counting.length === 0 ? '' : `
    <div class="panel" style="margin-bottom: 12px">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px">
        <h3 style="margin: 0">🎯 Minigame standings <span style="font-size: 11px; color: var(--muted); margin-left: 8px">counts in rivalry</span></h3>
        <div style="font-size: 14px; font-weight: 600; color: var(--gold)">${me}: ${mg.counts.myWins} · ${fname}: ${mg.counts.theirWins}${mg.counts.ties ? ` · ½: ${mg.counts.ties}` : ''}</div>
      </div>
      <div class="table-wrap"><table>
        <thead><tr><th>Date</th><th>Game</th><th class="num">You</th><th class="num">${fname}</th><th>Result</th></tr></thead>
        <tbody>${mg.counting.map(renderRow).join('')}</tbody>
      </table></div>
    </div>
  `;
  const offHtml = mg.offBooks.length === 0 ? '' : `
    <div class="panel" style="margin-bottom: 12px; opacity: 0.85">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px">
        <h3 style="margin: 0">🎲 Off the books <span style="font-size: 11px; color: var(--muted); margin-left: 8px">just for fun</span></h3>
        <div style="font-size: 13px; color: var(--muted)">${me}: ${mg.offBooksCounts.myWins} · ${fname}: ${mg.offBooksCounts.theirWins}${mg.offBooksCounts.ties ? ` · ½: ${mg.offBooksCounts.ties}` : ''}</div>
      </div>
      <div class="table-wrap"><table>
        <thead><tr><th>Date</th><th>Game</th><th class="num">You</th><th class="num">${fname}</th><th>Result</th></tr></thead>
        <tbody>${mg.offBooks.map(renderRow).join('')}</tbody>
      </table></div>
    </div>
  `;
  return inHtml + offHtml;
}

function analyzeRivalry(matches, rv) {
  if (!matches.length) return null;

  const byCourse = {};
  matches.forEach(m => {
    const cid = m.round.courseId;
    if (!byCourse[cid]) byCourse[cid] = { wins: 0, losses: 0, ties: 0, total: 0 };
    byCourse[cid].total++;
    if (m.tie) byCourse[cid].ties++;
    else if (m.won) byCourse[cid].wins++;
    else byCourse[cid].losses++;
  });

  const byTod = {};
  matches.forEach(m => {
    const tod = getTimeOfDayBucket(m.round.teeTime);
    if (!tod) return;
    if (!byTod[tod]) byTod[tod] = { wins: 0, losses: 0, ties: 0, total: 0 };
    byTod[tod].total++;
    if (m.tie) byTod[tod].ties++;
    else if (m.won) byTod[tod].wins++;
    else byTod[tod].losses++;
  });

  const WEATHER_LABELS = { sun: "☀️ Sun", cloud: "☁️ Cloudy", rain: "🌧️ Rain", wind: "💨 Wind", cold: "🥶 Cold", hot: "🥵 Hot" };
  const byWeather = {};
  matches.forEach(m => {
    const w = m.round.weather;
    if (!w) return;
    const k = WEATHER_LABELS[w] || w;
    if (!byWeather[k]) byWeather[k] = { wins: 0, losses: 0, ties: 0, total: 0 };
    byWeather[k].total++;
    if (m.tie) byWeather[k].ties++;
    else if (m.won) byWeather[k].wins++;
    else byWeather[k].losses++;
  });

  const sorted = [...matches].sort((a, b) => new Date(a.round.date) - new Date(b.round.date));
  let currentStreak = { type: null, count: 0 };
  let longestRunWin = 0, longestRunLoss = 0;
  sorted.forEach(m => {
    if (m.tie) {
      currentStreak = { type: 'tie', count: 1 };
    } else if (m.won) {
      if (currentStreak.type === 'win') currentStreak.count++;
      else currentStreak = { type: 'win', count: 1 };
      longestRunWin = Math.max(longestRunWin, currentStreak.count);
    } else {
      if (currentStreak.type === 'loss') currentStreak.count++;
      else currentStreak = { type: 'loss', count: 1 };
      longestRunLoss = Math.max(longestRunLoss, currentStreak.count);
    }
  });

  const myMargins = matches.filter(m => m.won && !m.tie).map(m => Math.abs((m.myVal||0) - (m.theirVal||0)));
  const theirMargins = matches.filter(m => !m.won && !m.tie).map(m => Math.abs((m.myVal||0) - (m.theirVal||0)));
  const avg = a => a.length ? a.reduce((s,x)=>s+x,0)/a.length : null;

  const last5Form = sorted.slice(-5).map(m => m.tie ? 'T' : m.won ? 'W' : 'L');

  // Per-hole H2H (requires opponentHoles)
  const holesH2H = {};
  matches.forEach(m => {
    if (!m.round.holes || !m.round.opponentHoles) return;
    m.round.holes.forEach((h, i) => {
      const opp = m.round.opponentHoles[i];
      if (!h?.score || !opp?.score) return;
      if (!holesH2H[i]) holesH2H[i] = { myWins: 0, theirWins: 0, ties: 0, total: 0 };
      holesH2H[i].total++;
      if (h.score < opp.score) holesH2H[i].myWins++;
      else if (h.score > opp.score) holesH2H[i].theirWins++;
      else holesH2H[i].ties++;
    });
  });

  return {
    byCourse, byTod, byWeather,
    currentStreak, longestRunWin, longestRunLoss,
    avgMyMargin: avg(myMargins),
    avgTheirMargin: avg(theirMargins),
    biggestWin: myMargins.length ? Math.max(...myMargins) : null,
    biggestLoss: theirMargins.length ? Math.max(...theirMargins) : null,
    last5Form,
    holesH2H,
  };
}

function renderRivalryRichStats(stats, me, fname, rv) {
  if (!stats) return '';
  const fmtMargin = rv.format === 'lowest_diff' || rv.format === 'best_avg' ? 1 : 0;

  const courseRows = Object.entries(stats.byCourse)
    .map(([cid, s]) => ({ cid, name: getCourse(cid)?.name || 'Unknown', ...s }))
    .sort((a, b) => b.total - a.total);

  const courseHtml = courseRows.length === 0 ? '' : `
    <div class="panel" style="margin-bottom: 14px">
      <h3>🏛️ By course</h3>
      <div class="table-wrap">
        <table>
          <thead><tr><th>Course</th><th class="num">Rounds</th><th class="num">You</th><th class="num">${fname}</th><th class="num">T</th><th>Trend</th></tr></thead>
          <tbody>${courseRows.map(r => {
            const meLeads = r.wins > r.losses;
            const tie = r.wins === r.losses;
            return `<tr>
              <td><strong>${r.name}</strong></td>
              <td class="num">${r.total}</td>
              <td class="num" style="color: ${meLeads ? 'var(--accent-bright)' : ''}">${r.wins}</td>
              <td class="num" style="color: ${!meLeads && !tie ? 'var(--accent-bright)' : ''}">${r.losses}</td>
              <td class="num">${r.ties}</td>
              <td style="font-size: 12px">${meLeads ? `🟢 You own this` : tie ? '🟡 Even' : `🔴 ${fname} dominates`}</td>
            </tr>`;
          }).join('')}</tbody>
        </table>
      </div>
    </div>
  `;

  const todHtml = Object.keys(stats.byTod).length === 0 ? '' : `
    <div class="panel" style="margin-bottom: 14px">
      <h3>⏰ Time of day</h3>
      ${TOD_ORDER.filter(k => stats.byTod[k]).map(k => {
        const s = stats.byTod[k];
        const width = s.total > 0 ? (s.wins / s.total * 100).toFixed(0) : 0;
        return `<div class="bar-row" style="grid-template-columns: 150px 1fr 90px">
          <span style="font-size: 12px">${k}</span>
          <div class="bar-bg"><div class="bar-fill" style="width: ${width}%"></div></div>
          <span class="bar-val" style="font-size: 11px">${s.wins}-${s.losses}${s.ties ? '-'+s.ties : ''}</span>
        </div>`;
      }).join('')}
    </div>
  `;

  const weatherHtml = Object.keys(stats.byWeather).length === 0 ? '' : `
    <div class="panel" style="margin-bottom: 14px">
      <h3>🌤️ Weather</h3>
      ${Object.entries(stats.byWeather).map(([k, s]) => {
        const width = s.total > 0 ? (s.wins / s.total * 100).toFixed(0) : 0;
        return `<div class="bar-row" style="grid-template-columns: 110px 1fr 90px">
          <span style="font-size: 12px">${k}</span>
          <div class="bar-bg"><div class="bar-fill" style="width: ${width}%"></div></div>
          <span class="bar-val" style="font-size: 11px">${s.wins}-${s.losses}${s.ties ? '-'+s.ties : ''}</span>
        </div>`;
      }).join('')}
    </div>
  `;

  const formColors = { W: 'var(--accent-bright)', L: 'var(--danger)', T: 'var(--muted)' };
  const formHtml = `
    <div class="grid grid-3" style="margin-bottom: 14px">
      <div class="panel" style="margin: 0">
        <h3>📈 Form (last 5)</h3>
        <div style="display: flex; gap: 6px; margin-top: 8px">
          ${stats.last5Form.map(f => `<div style="width: 32px; height: 32px; display: flex; align-items: center; justify-content: center; background: var(--bg-2); border: 1px solid var(--border); border-radius: 8px; font-weight: 600; color: ${formColors[f]}">${f}</div>`).join('')}
        </div>
      </div>
      <div class="panel" style="margin: 0">
        <h3>🔥 Streak</h3>
        <div style="font-size: 26px; font-weight: 600; margin-top: 6px; letter-spacing: -0.02em; color: ${stats.currentStreak.type === 'win' ? 'var(--accent-bright)' : stats.currentStreak.type === 'loss' ? 'var(--danger)' : 'var(--muted)'}">
          ${stats.currentStreak.count}${stats.currentStreak.type === 'win' ? 'W' : stats.currentStreak.type === 'loss' ? 'L' : 'T'}
        </div>
        <div style="font-size: 11px; color: var(--muted); margin-top: 6px">Longest win streak: ${stats.longestRunWin} · Longest loss streak: ${stats.longestRunLoss}</div>
      </div>
      <div class="panel" style="margin: 0">
        <h3>📏 Margin</h3>
        <div style="display: flex; justify-content: space-between; gap: 12px; margin-top: 6px">
          <div>
            <div style="font-size: 10px; color: var(--muted)">When you win</div>
            <div style="font-size: 18px; font-weight: 600; color: var(--accent-bright)">${stats.avgMyMargin != null ? '+' + stats.avgMyMargin.toFixed(fmtMargin) : '—'}</div>
          </div>
          <div>
            <div style="font-size: 10px; color: var(--muted)">When ${fname} wins</div>
            <div style="font-size: 18px; font-weight: 600; color: var(--danger)">${stats.avgTheirMargin != null ? '−' + stats.avgTheirMargin.toFixed(fmtMargin) : '—'}</div>
          </div>
        </div>
        ${stats.biggestWin ? `<div style="font-size: 10px; color: var(--muted); margin-top: 6px">Biggest win: ${stats.biggestWin.toFixed(fmtMargin)}${stats.biggestLoss ? ' · Biggest loss: ' + stats.biggestLoss.toFixed(fmtMargin) : ''}</div>` : ''}
      </div>
    </div>
  `;

  const holesRows = Object.entries(stats.holesH2H).map(([i, s]) => ({ hole: parseInt(i)+1, ...s }));
  const holesHtml = holesRows.length === 0 ? `
    <div class="panel" style="margin-bottom: 14px; border-style: dashed; background: var(--bg-2)">
      <h3>🎯 Hole-by-hole record</h3>
      <p style="color: var(--muted); font-size: 12px; margin: 0">
        Log both your and your opponent's score per hole (in the round form, "Hole-by-hole" mode) to see which holes you each win/lose.
      </p>
    </div>
  ` : `
    <div class="panel" style="margin-bottom: 14px">
      <h3>🎯 Hole-by-hole record</h3>
      <div class="table-wrap" style="max-height: 360px; overflow-y: auto">
        <table>
          <thead><tr><th>Hole</th><th class="num">N</th><th class="num">You</th><th class="num">${fname}</th><th class="num">T</th><th>Winner</th></tr></thead>
          <tbody>${holesRows.map(r => {
            const meLeads = r.myWins > r.theirWins;
            const tie = r.myWins === r.theirWins;
            return `<tr>
              <td><strong>${r.hole}</strong></td>
              <td class="num">${r.total}</td>
              <td class="num" style="color: ${meLeads ? 'var(--accent-bright)' : ''}">${r.myWins}</td>
              <td class="num" style="color: ${!meLeads && !tie ? 'var(--accent-bright)' : ''}">${r.theirWins}</td>
              <td class="num">${r.ties}</td>
              <td>${meLeads ? '🟢 You' : tie ? '🟡' : `🔴 ${fname}`}</td>
            </tr>`;
          }).join('')}</tbody>
        </table>
      </div>
    </div>
  `;

  return `
    <h3 style="margin-top: 22px; margin-bottom: 12px">📊 Statistics</h3>
    ${formHtml}
    ${courseHtml}
    ${todHtml}
    ${weatherHtml}
    ${holesHtml}
  `;
}

$("#rv-new")?.addEventListener("click", () => openAddRival());  // New Rivalry now just opens Add Rival (old season/format flow removed)

function openRivalryEditor(id) {
  const rv = id ? state.rivalries.find(r => r.id === id) : {
    name: "Sommerligaen " + new Date().getFullYear(),
    friendId: state.friends[0]?.id,
    startDate: todayISO(),
    endDate: `${new Date().getFullYear()}-12-31`,
    format: 'lowest_diff',
  };
  const isEdit = !!id;
  if (state.friends.length === 0) { openModal('<div style="text-align:center"><div class="section-eyebrow" style="margin-bottom:6px">NEW RIVALRY</div><h2 style="margin:2px 0 8px">You have no rivals yet</h2><p style="color:var(--muted); font-size:14px; line-height:1.5; max-width:320px; margin:0 auto 16px">Add a rival first — then you can start a rivalry against them.</p><button class="btn btn-gold" style="width:100%" onclick="closeModal(); openAddRival()">Add a rival</button><button class="btn btn-ghost" style="width:100%; margin-top:8px" onclick="closeModal()">Close</button></div>'); return; }
  openModal(`
    <h2>${isEdit ? 'Edit rivalry' : 'New rivalry season'}</h2>
    <div class="form-row cols-2">
      <label class="field"><span>Season name</span><input id="rv-name" value="${rv.name}" placeholder="e.g. Summer League 2026"></label>
      <label class="field"><span>Opponent</span>
        <select id="rv-friend">${state.friends.map(f => `<option value="${f.id}" ${f.id === rv.friendId ? 'selected' : ''}>${f.name}</option>`).join('')}</select>
      </label>
    </div>
    <div class="form-row cols-2" style="margin-top: 10px">
      <label class="field"><span>From date</span><input type="date" id="rv-start" value="${rv.startDate}"></label>
      <label class="field"><span>To date</span><input type="date" id="rv-end" value="${rv.endDate}"></label>
    </div>
    <div style="margin-top: 12px">
      <label class="field"><span>Format</span>
        <select id="rv-format">
          ${Object.entries(RIVALRY_FORMATS).map(([k, v]) => `<option value="${k}" ${k === rv.format ? 'selected' : ''}>${v.label}</option>`).join('')}
        </select>
      </label>
      <div id="rv-format-desc" style="margin-top: 6px; padding: 8px 12px; background: var(--bg-2); border-radius: 8px; font-size: 12px; color: var(--muted)"></div>
    </div>
    <div class="actions">
      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn" id="rv-save">${isEdit ? 'Update' : 'Start season'}</button>
    </div>
  `);
  function updateDesc() {
    const f = $("#rv-format").value;
    $("#rv-format-desc").textContent = RIVALRY_FORMATS[f]?.desc || "";
  }
  updateDesc();
  $("#rv-format").addEventListener("change", updateDesc);
  $("#rv-save").addEventListener("click", () => {
    const newRv = {
      id: rv.id || (window.fairwayCloud?.ensureUuid ? window.fairwayCloud.ensureUuid(null) : uid()),
      name: $("#rv-name").value.trim(),
      friendId: $("#rv-friend").value,
      startDate: $("#rv-start").value,
      endDate: $("#rv-end").value,
      format: $("#rv-format").value,
      status: 'active',
      createdAt: rv.createdAt || new Date().toISOString(),
    };
    if (!newRv.name || !newRv.friendId || !newRv.startDate || !newRv.endDate) {
      showToast("Fill in all fields", true);
      return;
    }
    if (isEdit) {
      const i = state.rivalries.findIndex(r => r.id === rv.id);
      state.rivalries[i] = newRv;
    } else {
      state.rivalries.push(newRv);
    }
    saveState();
    cloudPushRivalry(newRv);
    closeModal();
    renderRivalry();
    if (!isEdit) {
      setTimeout(() => showInviteModal(newRv), 200);
    } else {
      showToast("Rivalry updated");
    }
  });
}

function showInviteModal(rv) {
  const friend = state.friends.find(f => f.id === rv.friendId);
  const me = activeProfile()?.name || "din kompis";
  const inviteText = `Hei ${friend?.name}! 👋

Jeg har startet en golf-rivalry mot deg på Fairway Rivalry:

⚔️ *${rv.name}*
📅 ${fmtDate(rv.startDate)} → ${fmtDate(rv.endDate)}
🏆 Format: ${RIVALRY_FORMATS[rv.format]?.label}

Hver runde vi spiller sammen i perioden teller i sesongen. Fairway Rivalry logger hvem som vinner på hvilken bane, dag, vær - og lager rik H2H-statistikk.

Last ned eller åpne: [LIM INN URL HER]

Bring it on. - ${me} ⛳`;

  openModal(`
    <div style="text-align: center; padding: 4px 0 12px">
      <div style="display:inline-flex; width: 56px; height: 56px; border-radius: 14px;
        background: linear-gradient(135deg, var(--gold), #b8993f);
        align-items: center; justify-content: center; font-size: 28px;
        box-shadow: 0 8px 24px rgba(201,169,97,0.3); margin-bottom: 12px">🏆</div>
      <h2 style="font-size: 22px; margin-bottom: 8px">Sesongen er i gang!</h2>
      <p style="color: var(--muted); font-size: 13px; max-width: 420px; margin: 0 auto; line-height: 1.6">
        Send denne meldingen til ${friend?.name || 'motspilleren'} så de vet at de er med. Du kan kopiere teksten eller dele direkte.
      </p>
    </div>

    <div style="margin-top: 16px">
      <label class="field"><span>Invitasjonsmelding</span>
        <textarea id="inv-text" rows="10" style="font-family: Georgia, 'Times New Roman', serif; font-size: 12px">${inviteText}</textarea>
      </label>
    </div>

    <div style="margin-top: 14px; padding: 12px; background: var(--bg-2); border-radius: 8px; font-size: 12px; color: var(--muted); line-height: 1.6">
      <strong style="color: var(--text)">💡 Tip:</strong> If you've published Fairway Rivalry as a website (Cloudflare Pages), paste the URL where it says [PASTE URL HERE]. Then ${friend?.name || 'your opponent'} can open the app straight from the message.
    </div>

    <div class="actions">
      <button class="btn btn-ghost" onclick="closeModal()">Skip</button>
      <button class="btn" id="inv-copy">📋 Copy message</button>
      <button class="btn btn-gold" id="inv-share">📤 Share</button>
    </div>
  `);
  $("#inv-copy").addEventListener("click", () => {
    copyToClipboard($("#inv-text").value);
  });
  $("#inv-share").addEventListener("click", () => {
    shareText($("#inv-text").value);
  });
}

window.editRivalry = function(id) { closeModal(); openRivalryEditor(id); };

window.shareRivalry = function(id) {
  event?.stopPropagation?.();
  const rv = state.rivalries.find(r => r.id === id);
  if (!rv) return;
  const stats = computeRivalryStats(rv);
  const friend = state.friends.find(f => f.id === rv.friendId);
  const me = activeProfile()?.name || "Jeg";
  const winning = stats.myScore > stats.theirScore;
  const tie = stats.myScore === stats.theirScore;
  const trophy = winning ? "🏆" : tie ? "🤝" : "😅";
  const status = new Date() > new Date(rv.endDate) ? "Completed" : "In progress";
  const text = `${trophy} ${rv.name} (${status})

${me}: ${stats.myScore}
${friend?.name || 'Opponent'}: ${stats.theirScore}

${stats.rounds} rounds played · ${RIVALRY_FORMATS[rv.format]?.label}
${fmtDate(rv.startDate)} → ${fmtDate(rv.endDate)}

Tracked with Fairway Rivalry ⛳`;
  shareText(text);
};

window.deleteRivalry = function(id) {
  if (!confirm("Delete this rivalry season? Round history is kept.")) return;
  state.rivalries = state.rivalries.filter(r => r.id !== id);
  activeProfile().rivalries = state.rivalries;
  saveState();
  cloudDeleteRivalry(id);
  renderRivalry();
};

