function _didIWin(r) {
  if (!r) return null;
  if (r.gameKind && r.gameKind !== 'golf') {
    if (r.winner === 'me') return true;
    if (r.winner === 'opp') return false;
    return null;
  }
  // Hole Winner (points) round — decided by points/winner, not stroke totals.
  if (r.holePoints) {
    if (r.winner === 'me') return true;
    if (r.winner === 'opp') return false;
    if (r.myPoints != null && r.oppPoints != null) return r.myPoints > r.oppPoints ? true : (r.myPoints < r.oppPoints ? false : null);
    return null;
  }
  if (r.opponentScore != null && r.total != null) return r.total < r.opponentScore;
  if (r.opponentDifferential != null && r.differential != null) return r.differential < r.opponentDifferential;
  if (r.opponentStableford != null && r.stableford != null) return r.stableford > r.opponentStableford;
  return null;
}


// Helper: compute counters once
function buildTrophyStats(rs) {
  rs = rs.map(buildRoundComputed);
  const sorted = [...rs].sort((a,b) => new Date(a.date) - new Date(b.date));
  function didIWin(r) {
    if (r.opponentScore != null && r.total != null) return r.total < r.opponentScore;
    if (r.opponentDifferential != null && r.differential != null) return r.differential < r.opponentDifferential;
    if (r.opponentStableford != null && r.stableford != null) return r.stableford > r.opponentStableford;
    return null;
  }
  const winsByFriend = {}, lossesByFriend = {};
  sorted.forEach(r => (r.friends||[]).forEach(fid => {
    if (didIWin(r) === true) winsByFriend[fid] = (winsByFriend[fid]||0) + 1;
    if (didIWin(r) === false) lossesByFriend[fid] = (lossesByFriend[fid]||0) + 1;
  }));
  const courseCount = new Set(rs.map(r => r.courseId)).size;
  const courseWins = {};
  Object.entries(rs.reduce((m,r) => { (m[r.courseId]=m[r.courseId]||[]).push(r); return m; }, {})).forEach(([cid, list]) => {
    courseWins[cid] = list.length;
  });
  const birdies = rs.reduce((n, r) => n + (r.holes||[]).filter(h => h.score && h.par && h.score-h.par === -1).length, 0);
  const eagles = rs.reduce((n, r) => n + (r.holes||[]).filter(h => h.score && h.par && h.score-h.par <= -2).length, 0);

  let longestWinStreak = 0, cur = 0;
  for (const r of sorted) {
    const w = didIWin(r);
    if (w === true) { cur++; longestWinStreak = Math.max(longestWinStreak, cur); }
    else if (w === false) cur = 0;
  }

  // Comeback wins: won after being behind in rivalry
  // (Approximation: any rivalry where you came from behind at midpoint)
  return {
    totalRounds: rs.length,
    winsByFriend, lossesByFriend,
    maxWinsAgainstSingle: Math.max(0, ...Object.values(winsByFriend)),
    courseCount,
    maxRoundsOnSingleCourse: Math.max(0, ...Object.values(courseWins)),
    bestGross: Math.min(...rs.filter(r => r.total).map(r => r.total).concat([999])),
    bestDiff: Math.min(...rs.filter(r => r.differential != null).map(r => r.differential).concat([99])),
    birdies, eagles,
    longestWinStreak,
    countriesPlayed: new Set(rs.map(r => getCourse(r.courseId)?.country).filter(Boolean)).size,
  };
}

