function computeAchievementData() {
  const allRounds = (state.rounds || []);
  const rounds = allRounds.filter(r => !r.gameKind || r.gameKind === 'golf' || r.gameKind === 'simulator').map(buildRoundComputed);
  const scoredRounds = rounds.filter(r => r.differential != null);
  const courses = state.courses || [];
  const minScore = rounds.filter(r => r.total != null).reduce((m, r) => (m == null || r.total < m) ? r.total : m, null);
  // Highlights via hole-by-hole rounds
  let birdies = 0, eagles = 0, albatrosses = 0, aces = 0;
  let maxBirdiesInRound = 0, bogeyFreeRounds = 0, allParRounds = 0, underParRounds = 0;
  rounds.forEach(r => {
    if (!r.holes || !r.holes.length) return;
    let rb = 0, ok = true, allPar = true, score = 0;
    r.holes.forEach(h => {
      if (!h.score || !h.par) return;
      const diff = h.score - h.par;
      if (diff === -1) { birdies++; rb++; allPar = false; }
      else if (diff === -2) { eagles++; rb++; allPar = false; }
      else if (diff <= -3) { albatrosses++; rb++; allPar = false; }
      else if (diff > 0) { ok = false; allPar = false; }
      if (h.score === 1) aces++;
      score += h.score;
    });
    if (rb > maxBirdiesInRound) maxBirdiesInRound = rb;
    if (ok && r.holes.length >= 18) bogeyFreeRounds++;
    if (allPar && r.holes.length >= 18) allParRounds++;
    // Under par
    const c = getCourse(r.courseId);
    const tee = c && r.teeName ? c.tees.find(t => t.name === r.teeName) : null;
    const par = (tee && tee.par) || (c && c.par) || 72;
    if (r.total != null && r.total < par) underParRounds++;
  });
  // Course/country
  const playedCourseIds = new Set(rounds.map(r => r.courseId).filter(Boolean));
  const playedCountries = new Set();
  playedCourseIds.forEach(id => { const c = courses.find(x => x.id === id); if (c && c.country) playedCountries.add(c.country); });
  // H2H wins, distinct friends beaten, max vs same
  let h2hWins = 0, h2hLosses = 0;
  const winsByFriend = {};
  const distinctFriendsBeaten = new Set();
  const distinctFriendsPlayed = new Set();
  let lastResults = [];
  let longestWinStreak = 0, curStreak = 0, hadComeback = false, loseStreak = 0;
  rounds.sort((a, b) => new Date(a.date) - new Date(b.date));
  rounds.forEach(r => {
    if (!r.friends || r.friends.length !== 1) return;
    distinctFriendsPlayed.add(r.friends[0]);
    if (r.opponentDifferential == null && r.opponentScore == null) return;
    const myMetric = r.differential != null ? r.differential : r.total;
    const opMetric = r.opponentDifferential != null ? r.opponentDifferential : r.opponentScore;
    if (myMetric == null || opMetric == null) return;
    if (myMetric < opMetric) {
      h2hWins++; curStreak++; if (curStreak > longestWinStreak) longestWinStreak = curStreak;
      winsByFriend[r.friends[0]] = (winsByFriend[r.friends[0]] || 0) + 1;
      distinctFriendsBeaten.add(r.friends[0]);
      if (loseStreak >= 5) hadComeback = true;
      loseStreak = 0;
    } else if (myMetric > opMetric) {
      h2hLosses++; curStreak = 0; loseStreak++;
    }
  });
  const maxWinsVsSingle = Object.values(winsByFriend).reduce((m, n) => Math.max(m, n), 0);
  // Streak / consistency
  const dates = [...new Set(rounds.map(r => r.date))].sort();
  let longestDailyStreak = 0;
  for (let i = 0; i < dates.length; i++) {
    let n = 1, cur = new Date(dates[i]);
    for (let j = i + 1; j < dates.length; j++) {
      const next = new Date(dates[j]);
      const diffDays = Math.round((next - cur) / 86400000);
      if (diffDays === 1) { n++; cur = next; } else break;
    }
    if (n > longestDailyStreak) longestDailyStreak = n;
  }
  // Months played
  const months = new Set(rounds.map(r => r.date && r.date.slice(0, 7)).filter(Boolean));
  let consecutiveMonths = 0;
  const monthArr = [...months].sort();
  for (let i = 0; i < monthArr.length; i++) {
    let n = 1, [y, m] = monthArr[i].split('-').map(Number);
    for (let j = i + 1; j < monthArr.length; j++) {
      m++; if (m > 12) { m = 1; y++; }
      const expect = `${y}-${String(m).padStart(2, '0')}`;
      if (monthArr[j] === expect) n++; else break;
    }
    if (n > consecutiveMonths) consecutiveMonths = n;
  }
  // Weekly month streak — 4 weeks in a row
  const weekRoundsCount = {};
  rounds.forEach(r => {
    if (!r.date) return;
    const d = new Date(r.date);
    const onejan = new Date(d.getFullYear(), 0, 1);
    const week = Math.ceil((((d - onejan) / 86400000) + onejan.getDay() + 1) / 7);
    const key = d.getFullYear() + '-W' + week;
    weekRoundsCount[key] = (weekRoundsCount[key] || 0) + 1;
  });
  let weeklyMonthStreak = false;
  const weekKeys = Object.keys(weekRoundsCount).sort();
  for (let i = 0; i < weekKeys.length - 3; i++) {
    if (weekRoundsCount[weekKeys[i]] && weekRoundsCount[weekKeys[i + 1]] && weekRoundsCount[weekKeys[i + 2]] && weekRoundsCount[weekKeys[i + 3]]) {
      weeklyMonthStreak = true; break;
    }
  }
  // Max rounds in week / two weeks
  let maxRoundsInWeek = 0, maxRoundsInTwoWeeks = 0;
  rounds.forEach(r => {
    if (!r.date) return;
    const d = new Date(r.date);
    let w7 = 0, w14 = 0;
    rounds.forEach(r2 => {
      const dd = new Date(r2.date);
      const diff = (dd - d) / 86400000;
      if (diff >= 0 && diff < 7) w7++;
      if (diff >= 0 && diff < 14) w14++;
    });
    if (w7 > maxRoundsInWeek) maxRoundsInWeek = w7;
    if (w14 > maxRoundsInTwoWeeks) maxRoundsInTwoWeeks = w14;
  });
  // Consistent rounds (within 3 strokes of avg)
  const totals = rounds.map(r => r.total).filter(x => x != null);
  const avgTotal = totals.length ? totals.reduce((s, x) => s + x, 0) / totals.length : 0;
  const consistentRoundCount = totals.filter(t => Math.abs(t - avgTotal) <= 3).length;
  // Conditions
  const hasDawnRound = rounds.some(r => r.teeTime && parseInt(r.teeTime.split(':')[0], 10) < 7);
  const hasTwilightRound = rounds.some(r => r.teeTime && parseInt(r.teeTime.split(':')[0], 10) >= 17);
  const hasRainRound = rounds.some(r => r.weather === 'rain' || r.weather === 'heavy_rain');
  const hasStormRound = rounds.some(r => r.weather === 'storm');
  const hasColdRound = rounds.some(r => r.tempCat === 'cold');
  const hasHotRound = rounds.some(r => r.tempCat === 'hot');
  const hasExtremeWindRound = rounds.some(r => r.windCat === 'extreme');
  const simRounds = allRounds.filter(r => r.gameKind === 'simulator').length;
  const distinctGameKinds = new Set(allRounds.map(r => r.gameKind || 'golf')).size;
  // League
  const leagues = (typeof leaguesGet === 'function') ? leaguesGet() : [];
  const me = activeProfile();
  const leagueMember = leagues.some(l => (l.members || []).some(m => m.userId === me?.id));
  const leagueOwned = leagues.some(l => l.ownerId === me?.id);
  const leagueMembersInvited = Math.max(0, ...leagues.filter(l => l.ownerId === me?.id).map(l => (l.members || []).length - 1));
  const seasonWins = parseInt(localStorage.getItem('fgl_season_wins') || '0', 10);
  // Match mode + challenges
  const matchModeRounds = parseInt(localStorage.getItem('fgl_mm_rounds') || '0', 10);
  let challengesCreated = 0, challengesWon = 0;
  (state.rivalries || []).forEach(rv => (rv.challenges || []).forEach(c => {
    if (c.createdBy === me?.id) challengesCreated++;
    if (c.status === 'completed' && c.winner === 'me') challengesWon++;
  }));
  const caddieChats = parseInt(localStorage.getItem('fgl_caddie_chats') || '0', 10);
  const cardShared = localStorage.getItem('fgl_card_shared') === '1';
  // Score types
  const scoreTypesUsed = new Set(allRounds.map(r => r.scoreType).filter(Boolean)).size;
  // Handicap
  const hcp = calcHcpIndex(scoredRounds);

  return {
    totalRounds: rounds.length, totalAnyRounds: allRounds.length,
    minScore, hcp,
    birdies, eagles, albatrosses, acesCount: aces,
    maxBirdiesInRound, bogeyFreeRounds, allParRounds, underParRounds,
    coursesPlayed: playedCourseIds.size,
    countriesPlayed: playedCountries.size,
    playedFamous: false,
    h2hWins, h2hLosses, maxWinsVsSingle, longestWinStreak, hadComeback,
    distinctFriendsBeaten: distinctFriendsBeaten.size,
    distinctFriendsPlayed: distinctFriendsPlayed.size,
    friendsCount: (state.friends || []).length,
    leagueMember, leagueOwned, leagueMembersInvited, seasonWins,
    matchModeRounds, challengesCreated, challengesWon,
    caddieChats, cardShared, scoreTypesUsed,
    maxRoundsInWeek, maxRoundsInTwoWeeks, weeklyMonthStreak,
    consecutiveMonths, uniqueMonthsPlayed: months.size,
    longestDailyStreak, consistentRoundCount,
    hasDawnRound, hasTwilightRound, hasRainRound, hasStormRound,
    hasColdRound, hasHotRound, hasExtremeWindRound,
    simRounds, distinctGameKinds,
  };
}

function getUnlockedAchievements() {
  const d = computeAchievementData();
  const first99 = ACHIEVEMENTS_100.slice(0, 99).map(a => ({ ...a, unlocked: !!a.check(d) }));
  const unlockedCount = first99.filter(a => a.unlocked).length;
  d.othersUnlocked = unlockedCount;
  const last = ACHIEVEMENTS_100[99];
  const lastUnlocked = { ...last, unlocked: !!last.check(d) };
  return [...first99, lastUnlocked];
}

// ===================== MEMBERSHIP =====================
function getMembership() {
  try { return JSON.parse(localStorage.getItem('fgl_membership') || 'null'); } catch (e) { return null; }
}
function setMembership(m) { localStorage.setItem('fgl_membership', JSON.stringify(m)); }
function hasMembership() {
  // INTENTIONALLY returns true for now — gating is wired but not enforced.
  // Flip to actual check once payment / completionist flow is live.
  return true;
}
function getMembershipStatus() {
  const m = getMembership();
  if (!m) return { tier: 'free', label: 'Free' };
  if (m.earnedUntil && new Date(m.earnedUntil) > new Date()) return { tier: 'earned', label: 'Earned via Trophies', until: m.earnedUntil };
  if (m.paidUntil && new Date(m.paidUntil) > new Date()) return { tier: 'premium', label: 'Premium', until: m.paidUntil };
  return { tier: 'free', label: 'Free' };
}
function checkMembershipFromTrophies() {
  const list = getUnlockedAchievements();
  const unlockedAll = list.every(a => a.unlocked);
  if (unlockedAll) {
    const cur = getMembership() || {};
    if (!cur.earnedUntil || new Date(cur.earnedUntil) < new Date()) {
      const until = new Date(); until.setFullYear(until.getFullYear() + 1);
      setMembership({ ...cur, earnedUntil: until.toISOString() });
      showToast('🎉 The Completionist! 1-year free membership granted', false);
    }
  }
}

