const ARCHETYPES = [
  { id: 'the_closer', title: 'The Closer', icon: '🎯',
    tagline: 'You perform better late in rounds than early.',
    minRounds: 5,
    score: rs => {
      let sf=0, sb=0, n=0;
      rs.forEach(r => {
        if (!r.holes || r.holes.length < 18) return;
        const fp = r.holes.slice(0,9).reduce((s,h) => s + (h.par||4), 0);
        const bp = r.holes.slice(9,18).reduce((s,h) => s + (h.par||4), 0);
        const fs = r.holes.slice(0,9).reduce((s,h) => s + (h.score||0), 0);
        const bs = r.holes.slice(9,18).reduce((s,h) => s + (h.score||0), 0);
        if (!fs || !bs) return;
        sf += (fs - fp); sb += (bs - bp); n++;
      });
      if (n < 3) return 0;
      return Math.max(0, Math.min(100, ((sf/n) - (sb/n)) * 25));
    }},
  { id: 'front_nine_merchant', title: 'Front Nine Merchant', icon: '🏃',
    tagline: 'You start strong but fade as the round goes on.',
    minRounds: 5,
    score: rs => {
      let sf=0, sb=0, n=0;
      rs.forEach(r => {
        if (!r.holes || r.holes.length < 18) return;
        const fp = r.holes.slice(0,9).reduce((s,h) => s + (h.par||4), 0);
        const bp = r.holes.slice(9,18).reduce((s,h) => s + (h.par||4), 0);
        const fs = r.holes.slice(0,9).reduce((s,h) => s + (h.score||0), 0);
        const bs = r.holes.slice(9,18).reduce((s,h) => s + (h.score||0), 0);
        if (!fs || !bs) return;
        sf += (fs - fp); sb += (bs - bp); n++;
      });
      if (n < 3) return 0;
      return Math.max(0, Math.min(100, ((sb/n) - (sf/n)) * 25));
    }},
  { id: 'rain_king_arch', title: 'Rain King', icon: '🌧',
    tagline: 'You raise your game when the weather turns.',
    minRounds: 3,
    score: rs => {
      const rain = rs.filter(r => r.weather === 'rain' || r.weather === 'heavy_rain');
      const dry = rs.filter(r => r.weather === 'sun' || r.weather === 'cloudy' || !r.weather);
      if (rain.length < 2 || dry.length < 2) return 0;
      const ar = rain.reduce((s,r) => s + (r.differential ?? 99), 0) / rain.length;
      const ad = dry.reduce((s,r) => s + (r.differential ?? 99), 0) / dry.length;
      return Math.max(0, Math.min(100, (ad - ar) * 12 + rain.length * 4));
    }},
  { id: 'course_hunter', title: 'The Course Hunter', icon: '🗺',
    tagline: 'You explore more courses than most players ever will.',
    minRounds: 5,
    score: rs => {
      const c = new Set(rs.filter(r => r.courseId).map(r => r.courseId));
      const ratio = c.size / Math.max(1, rs.length);
      return Math.max(0, Math.min(100, c.size * 8 + ratio * 30));
    }},
  { id: 'home_loyalist', title: 'Home Course Loyalist', icon: '🏠',
    tagline: 'You know one course better than anyone.',
    minRounds: 6,
    score: rs => {
      const m = {};
      rs.forEach(r => { if (r.courseId) m[r.courseId] = (m[r.courseId]||0) + 1; });
      const max = Math.max(0, ...Object.values(m));
      const ratio = max / Math.max(1, rs.length);
      return Math.max(0, Math.min(100, max * 6 + ratio * 50));
    }},
  { id: 'rival_killer_arch', title: 'Rival Killer', icon: '⚔',
    tagline: 'You win when it matters against your rival.',
    minRounds: 5,
    score: rs => {
      const m = {};
      rs.forEach(r => {
        if (_didIWin(r) === true) (r.friends||[]).forEach(f => m[f] = (m[f]||0) + 1);
      });
      const max = Math.max(0, ...Object.values(m));
      const total = rs.filter(r => r.opponentScore != null || (r.friends||[]).length > 0).length;
      if (total < 3) return 0;
      return Math.max(0, Math.min(100, max * 12));
    }},
  { id: 'comeback_artist', title: 'The Comeback Artist', icon: '↩',
    tagline: "You find another gear when you're down.",
    minRounds: 5,
    score: rs => {
      let cbs = 0;
      rs.forEach(r => {
        if (!r.holes || !r.opponentHoles || r.holes.length < 18) return;
        if (_didIWin(r) !== true) return;
        let me=0, them=0;
        for (let i=0; i<9; i++) { me += r.holes[i]?.score||0; them += r.opponentHoles[i]?.score||0; }
        if ((me - them) >= 3) cbs++;
      });
      return Math.max(0, Math.min(100, cbs * 30));
    }},
  { id: 'wind_warrior_arch', title: 'Wind Warrior', icon: '🌪',
    tagline: 'When the wind picks up, your scores hold.',
    minRounds: 4,
    score: rs => {
      const w = rs.filter(r => ['noticeable','strong','extreme'].includes(r.windCat));
      const c = rs.filter(r => ['calm','light'].includes(r.windCat));
      if (w.length < 2 || c.length < 2) return 0;
      const aw = w.reduce((s,r) => s + (r.differential ?? 99), 0) / w.length;
      const ac = c.reduce((s,r) => s + (r.differential ?? 99), 0) / c.length;
      return Math.max(0, Math.min(100, (ac - aw) * 15 + w.length * 5));
    }},
  { id: 'birdie_machine', title: 'The Birdie Machine', icon: '🦅',
    tagline: 'You hunt for birdies — and you find them.',
    minRounds: 4,
    score: rs => {
      let b = 0, h = 0;
      rs.forEach(r => (r.holes||[]).forEach(hh => {
        if (hh.score && hh.par) { h++; if (hh.score - hh.par === -1) b++; }
      }));
      if (h < 36) return 0;
      return Math.max(0, Math.min(100, (b/h) * 1500));
    }},
  { id: 'steady_hand', title: 'The Steady Hand', icon: '🎚',
    tagline: 'Your scores barely move. You are reliably solid.',
    minRounds: 6,
    score: rs => {
      const sc = rs.filter(r => r.total).map(r => r.total);
      if (sc.length < 5) return 0;
      const avg = sc.reduce((a,b) => a+b, 0) / sc.length;
      const stddev = Math.sqrt(sc.reduce((s,x) => s + (x-avg)**2, 0) / sc.length);
      return Math.max(0, Math.min(100, (6 - stddev) * 18));
    }},
];

function computePlayerIdentity() {
  const p = activeProfile();
  if (!p) return null;
  const rs = (p.rounds || []).filter(r => !r.gameKind || r.gameKind === 'golf').map(buildRoundComputed);
  if (rs.length < 3) return { archetype: null, confidence: 0, roundsNeeded: 3 - rs.length, total: rs.length };
  const scored = ARCHETYPES
    .filter(a => rs.length >= a.minRounds)
    .map(a => ({ archetype: a, score: a.score(rs) }))
    .sort((x, y) => y.score - x.score);
  if (!scored.length || scored[0].score < 20) {
    return { archetype: null, confidence: scored[0]?.score || 0, total: rs.length, runnerUp: scored[0]?.archetype };
  }
  return { archetype: scored[0].archetype, confidence: scored[0].score, total: rs.length, runnerUp: scored[1]?.archetype || null, allScores: scored.slice(0, 4) };
}

