function fgIcon(name, opts = {}) {
  const svg = FG_ICONS[name] || FG_ICONS.spark;
  const cls = 'fg-icon' + (opts.lg ? ' lg' : '') + (opts.xl ? ' xl' : '') + (opts.silver ? ' silver' : '') + (opts.muted ? ' muted' : '');
  return `<span class="${cls}" aria-hidden="true">${svg}</span>`;
}

function evaluateAchievements() {
  const p = activeProfile();
  if (!p) return [];
  const rounds = profileRounds();
  const stats = buildTrophyStats(rounds);
  const seenMap = {};
  (p.achievementsSeen || []).forEach(x => { seenMap[x.id] = x.earnedAt; });
  // Expand each trophy into 5 tier-rows
  const results = [];
  TROPHIES.forEach(t => {
    const value = t.stat(stats, rounds.map(buildRoundComputed));
    t.tiers.forEach((threshold, idx) => {
      const tierDef = TIER_DEFS[idx];
      const earned = value >= threshold;
      const tieredId = `${t.id}.${tierDef.tier}`;
      results.push({
        id: tieredId,
        baseId: t.id,
        category: t.cat,
        title: t.title,
        desc: `${tierDef.label}: ${threshold}+ ${t.desc.toLowerCase()}`,
        tier: tierDef.tier,
        tierLabel: tierDef.label,
        tierColor: tierDef.color,
        tierIdx: idx,
        threshold,
        currentValue: value,
        earned,
        earnedAt: seenMap[tieredId],
      });
    });
  });
  // Add Collection meta-trophies
  const earnedCount = results.filter(r => r.earned).length;
  const COLLECTION_TIERS = [
    { threshold: 10,   title: 'Collector I',     desc: 'Unlocked 10 trophies' },
    { threshold: 25,   title: 'Collector II',    desc: 'Unlocked 25 trophies' },
    { threshold: 50,   title: 'Collector III',   desc: 'Unlocked 50 trophies' },
    { threshold: 100,  title: 'Trophy Hunter',   desc: 'Unlocked 100 trophies' },
    { threshold: 250,  title: 'Legacy Builder',  desc: 'Unlocked 250 trophies' },
    { threshold: 500,  title: 'Hall of Fame',    desc: 'Unlocked 500 trophies' },
    { threshold: 1000, title: 'Immortal Rival',  desc: 'Unlocked 1000 trophies' },
  ];
  COLLECTION_TIERS.forEach((c, i) => {
    const tierDef = TIER_DEFS[Math.min(i, 4)];
    const earned = earnedCount >= c.threshold;
    const tieredId = `collection.${c.threshold}`;
    results.push({
      id: tieredId,
      baseId: 'collection',
      category: 'Collection',
      title: c.title,
      desc: c.desc,
      tier: tierDef.tier,
      tierLabel: tierDef.label,
      tierColor: tierDef.color,
      threshold: c.threshold,
      currentValue: earnedCount,
      earned,
      earnedAt: seenMap[tieredId],
    });
  });
  // ── LEGENDS — single-trigger memeworthy unlocks ─────────────────────
  if (typeof LEGENDS !== 'undefined') {
    const ctx = { friends: p.friends || [], myHcp: (p.manualHcp != null ? p.manualHcp : calcHcpIndex(rounds)) };
    LEGENDS.forEach(l => {
      let earned = false;
      try { earned = !!l.check(rounds.map(buildRoundComputed), ctx); } catch(e) {}
      const rarity = RARITY_DEFS[l.rarity] || RARITY_DEFS.common;
      const tieredId = `legend.${l.id}`;
      results.push({
        id: tieredId, baseId: l.id, category: 'Legends',
        title: l.title, desc: l.desc,
        narrativeLine: l.line || '', icon: l.icon, isLegend: true,
        tier: 'legend', tierLabel: rarity.label, tierColor: rarity.color,
        tierGlow: rarity.glow, rarity: l.rarity,
        currentValue: earned ? 1 : 0, threshold: 1, earned,
        earnedAt: seenMap[tieredId],
      });
    });
  }
  return results;
}

function checkAchievements(newRound) {
  const p = activeProfile();
  if (!p) return;
  p.achievementsSeen = p.achievementsSeen || [];
  const seenIds = new Set(p.achievementsSeen.map(x => x.id));
  const achievements = evaluateAchievements();
  const newOnes = achievements.filter(a => a.earned && !seenIds.has(a.id));
  newOnes.forEach(a => {
    p.achievementsSeen.push({ id: a.id, earnedAt: new Date().toISOString() });
    cloudPushAchievement(a.id);
  });
  if (newOnes.length) {
    saveState();
    // Show big toast for the first new achievement
    const a = newOnes[0];
    showBigToast(a.title, a.desc + (newOnes.length > 1 ? ` · +${newOnes.length - 1} more unlocked` : ""));
  }
}

function showBigToast(title, body) {
  const existing = document.querySelector(".toast-large");
  if (existing) existing.remove();
  const t = document.createElement("div");
  t.className = "toast-large";
  t.innerHTML = `<div style="width: 40px; height: 40px; display: flex; align-items: center; justify-content: center">${ICON_TROPHY_SMALL.replace('width: 16px; height: 16px', 'width: 36px; height: 36px').replace('vertical-align: middle', '')}</div><div><div style="font-weight: 700">${title}</div><div style="font-size: 12px; opacity: 0.85">${body}</div></div>`;
  document.body.appendChild(t);
  setTimeout(() => t.classList.add("show"), 50);
  setTimeout(() => { t.classList.remove("show"); setTimeout(() => t.remove(), 500); }, 4500);
}

const TROPHY_CAT_PATHS = {
  Rivalry: '<path d="M6 21 L15 4"/><path d="M18 21 L9 4"/><circle cx="6" cy="21" r="1.6"/><circle cx="18" cy="21" r="1.6"/>',
  Performance: '<circle cx="12" cy="12" r="8"/><circle cx="12" cy="12" r="4"/><circle cx="12" cy="12" r="1" fill="currentColor"/>',
  Consistency: '<polyline points="3 16 9 12 13 14 21 7"/>',
  Course: '<line x1="7" y1="3" x2="7" y2="21"/><path d="M7 4 L18 7 L7 10 Z" fill="currentColor" stroke="none"/>',
  Streak: '<path d="M12 3 C13 7 17 8 16 13 C16 18 8 18 8 13 C8 10 10 10 10 8 C11 9 12 10 12 12 C13 10 13 6 12 3 Z"/>',
  Fun: '<path d="M12 3 L14.5 9 L21 9.5 L16 14 L17.5 21 L12 17.5 L6.5 21 L8 14 L3 9.5 L9.5 9 Z"/>',
  Collection: '<rect x="4" y="5" width="7" height="7" rx="1"/><rect x="13" y="5" width="7" height="7" rx="1"/><rect x="8.5" y="13" width="7" height="7" rx="1"/>',
  Legends: '<path d="M4 8 L7 14 L12 6 L17 14 L20 8 L18 19 L6 19 Z"/>',
};
function trophyCatIcon(cat, size) {
  size = size || 26;
  const path = TROPHY_CAT_PATHS[cat] || '<path d="M7 4 H17 V9 Q17 13 12 14 Q7 13 7 9 Z"/><path d="M7 5 Q3 6 4 10 M17 5 Q21 6 20 10"/><line x1="12" y1="14" x2="12" y2="18"/><path d="M8 20 H16 L15 18 H9 Z"/>';
  return `<svg viewBox="0 0 24 24" width="${size}" height="${size}" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round">${path}</svg>`;
}
window.openTrophyDetail = function(baseId, category) {
  const all = evaluateAchievements().filter(a => String(a.baseId) === String(baseId));
  if (!all.length) return;
  const t0 = all[0];
  const earnedTiers = all.filter(a => a.earned);
  const cur = earnedTiers[earnedTiers.length - 1] || null;
  const rows = all.map(a => `<div class="td-tier ${a.earned ? 'on' : ''}">
      <span class="td-dot" style="background:${a.earned ? a.tierColor : 'var(--border)'}"></span>
      <span class="td-tier-l" style="color:${a.earned ? a.tierColor : 'var(--muted-2)'}">${a.tierLabel}</span>
      <span class="td-tier-d">${a.desc}</span>
      <span class="td-tier-s">${a.earned ? '✓' : Math.min(a.currentValue, a.threshold) + '/' + a.threshold}</span>
    </div>`).join('');
  openModal(`<div class="trophy-detail">
    <div class="td-icon" style="color:${cur ? cur.tierColor : 'var(--gold)'}">${trophyCatIcon(category, 54)}</div>
    <div class="td-title">${t0.title}</div>
    <div class="td-rarity" style="color:${cur ? cur.tierColor : 'var(--muted-2)'}">${cur ? cur.tierLabel + ' unlocked' : 'Locked — keep playing'}</div>
    <div class="td-cat">${all.length > 1 ? category + ' · rarity rises Bronze → Legendary' : (t0.desc || category)}</div>
    <div class="td-tiers">${rows}</div>
  </div>`);
};

function renderTrophies() {
  const rounds = profileRounds().map(buildRoundComputed);

  // Hero
  const achievements = evaluateAchievements();
  const earned = achievements.filter(a => a.earned).length;
  const heroEl = $("#trophies-hero");
  if (heroEl) {
    heroEl.innerHTML = `
      <div class="panel" style="background: linear-gradient(135deg, rgba(201,169,97,0.10), rgba(13,24,19,0.4)); border: 1px solid var(--gold-dim); padding: 24px; display: flex; align-items: center; gap: 20px; flex-wrap: wrap">
        <div style="flex-shrink: 0; width: 80px; height: 80px; border-radius: 18px; background: rgba(13, 24, 19, 0.6); border: 1px solid var(--gold-dim); display: flex; align-items: center; justify-content: center">${ICON_TROPHY}</div>
        <div style="flex: 1; min-width: 0">
          <div style="font-size: 10px; color: var(--gold); letter-spacing: 0.1em; text-transform: uppercase; font-weight: 600; margin-bottom: 4px">Trophy room</div>
          <h2 style="margin: 0 0 6px; font-size: 22px; letter-spacing: -0.02em">${earned} of ${achievements.length} unlocked</h2>
          <div style="color: var(--muted); font-size: 13px">Bronze, silver, gold, platinum, legendary — every milestone in your golf legacy.</div>
        </div>
      </div>
    `;
  }

  // Rarest trophy (replaces Personal records)
  const recordsContainer = $("#personal-records");
  if (recordsContainer) {
    const tierRank = { bronze:1, silver:2, gold:3, platinum:4, legendary:5, legend:5 };
    const unlocked = (achievements || []).filter(a => a.earned);
    if (!unlocked.length) {
      recordsContainer.innerHTML = `<div class="empty" style="grid-column:1/-1">No trophies yet — play rounds to unlock rare ones.</div>`;
    } else {
      const r = unlocked.slice().sort((a,b)=>(tierRank[(b.tier||'').toLowerCase()]||0)-(tierRank[(a.tier||'').toLowerCase()]||0))[0];
      recordsContainer.innerHTML = `<div class="rarest-trophy" style="grid-column:1/-1">
        <div class="rarest-eyebrow">YOUR RAREST TROPHY</div>
        <div class="rarest-row">
          <div class="rarest-ic" style="color:${r.tierColor||'var(--gold-bright)'}">${typeof trophyCatIcon==='function'?trophyCatIcon(r.cat,58):''}</div>
          <div class="rarest-meta"><div class="rarest-name">${r.title||r.name||'Trophy'}</div><div class="rarest-desc">${r.desc||''}</div><div class="rarest-tier">${(r.tier||'').toUpperCase()}</div></div>
        </div>
      </div>`;
    }
  }

  // Group trophies by category
  const byCat = {};
  achievements.forEach(a => {
    if (!byCat[a.category]) byCat[a.category] = {};
    if (!byCat[a.category][a.baseId]) byCat[a.category][a.baseId] = [];
    byCat[a.category][a.baseId].push(a);
  });

  const CAT_ORDER = ['Legends','Rivalry','Performance','Consistency','Course','Streak','Fun','Collection'];
  const grid = $("#achievements-grid");
  const tierRank = { bronze:1, silver:2, gold:3, platinum:4, legendary:5, legend:5 };
  const allGroups = [];
  Object.values(byCat).forEach(catGroups => Object.values(catGroups).forEach(tiers => allGroups.push(tiers)));
  const groupScore = (tiers) => {
    const et = tiers.filter(t => t.earned);
    if (!et.length) return -1;
    const top = et[et.length - 1];
    return tierRank[String(top.tier || top.tierLabel || '').toLowerCase()] || 1;
  };
  // Rarest earned first, then commoner earned, then unearned last
  allGroups.sort((a, b) => groupScore(b) - groupScore(a));
  const earnedGroups = allGroups.filter(g => groupScore(g) >= 0);
  const unearnedGroups = allGroups.filter(g => groupScore(g) < 0);
  const progressHeader = `
    <div style="grid-column: 1/-1; padding: 14px 18px; background: rgba(13,20,15,0.66); border-radius: 12px; margin-bottom: 8px; border: 1px solid rgba(201,169,97,0.28)">
      <div style="font-size: 11px; color: var(--gold); letter-spacing: 0.22em; text-transform: uppercase; font-weight: 600">Progress</div>
      <div style="font-size: 26px; font-weight: 600; color: var(--text); margin-top: 4px; letter-spacing: -0.01em">${earned} <span style="color: var(--muted); font-size: 16px; font-weight: 400">of ${achievements.length} trophies</span></div>
    </div>`;
  const label = txt => `<div style="grid-column: 1/-1; margin-top: 16px; margin-bottom: 4px"><div class="trophy-cat-label">${txt}</div></div>`;
  grid.innerHTML = progressHeader
    + (earnedGroups.length ? label('\u2014 Your trophies \u00b7 rarest first \u2014') + earnedGroups.map(renderTrophyGroup).join("") : "")
    + (unearnedGroups.length ? label('\u2014 Not yet unlocked \u2014') + unearnedGroups.map(renderTrophyGroup).join("") : "");
}

function renderTrophyGroup(tiers) {
  // tiers is array of 5 (Bronze..Legendary) for one trophy. Or single for Collection.
  // Show as one card with tier indicators.
  const baseTrophy = tiers[0];
  const isCollection = baseTrophy.category === 'Collection';
  if (isCollection) {
    return tiers.map(t => `
      <div class="trophy-card ${t.earned ? 'earned' : 'locked'}" onclick="openTrophyDetail('${t.baseId}','${t.category}')" style="cursor:pointer">
        <div class="tcard-mark" style="color: ${t.earned ? t.tierColor : 'var(--muted-2)'}">${trophyCatIcon(t.category)}</div>
        <div class="tcard-title">${t.title}</div>
        <div class="tcard-desc">${t.desc}</div>
        ${t.earned ? `<div class="tcard-date">Unlocked</div>` :
          `<div class="tcard-progress"><div class="tcard-prog-bar"><div style="width: ${Math.min(100, (t.currentValue/t.threshold)*100)}%"></div></div><span>${t.currentValue}/${t.threshold}</span></div>`}
      </div>
    `).join("");
  }
  // Regular trophy with 5 tiers - one card showing highest tier earned + next tier progress
  const earnedTiers = tiers.filter(t => t.earned);
  const nextTier = tiers.find(t => !t.earned);
  const currentTier = earnedTiers.length ? earnedTiers[earnedTiers.length-1] : null;
  const display = currentTier || tiers[0];
  return `
    <div class="trophy-card ${currentTier ? 'earned' : 'locked'}" onclick="openTrophyDetail('${baseTrophy.baseId}','${baseTrophy.category}')" style="cursor:pointer">
      <div class="tcard-tier-row">
        ${tiers.map(t => `<div class="tcard-tier-dot ${t.earned ? 'earned' : ''}" style="background: ${t.earned ? t.tierColor : 'var(--border)'}" title="${t.tierLabel}"></div>`).join("")}
      </div>
      <div class="tcard-mark" style="color: ${currentTier ? currentTier.tierColor : 'var(--muted-2)'}">${trophyCatIcon(baseTrophy.category)}</div>
      <div class="tcard-title">${display.title}</div>
      <div class="tcard-desc">${currentTier ? `${currentTier.tierLabel} reached` : `Bronze: ${tiers[0].threshold}+`}</div>
      ${nextTier ?
        `<div class="tcard-progress"><div class="tcard-prog-bar"><div style="width: ${Math.min(100, (nextTier.currentValue/nextTier.threshold)*100)}%; background: ${nextTier.tierColor}"></div></div><span>${nextTier.currentValue}/${nextTier.threshold}</span></div>` :
        `<div class="tcard-date">${TIER_DEFS[4].label} — maxed</div>`}
    </div>
  `;
}

/* =====================================================
   FUN STATS ENGINE - shareable narrative facts
   Each fact has a "punch" score (0-100) and a "scope".
   Pick the highest-punch fact for share cards.
   ===================================================== */

function findFunStats(round, allRounds, friend, meName) {
  if (!friend || !round) return [];
  const me = meName || "You";
  const fname = friend.name;
  const courseId = round.courseId;
  const c = getCourse(courseId);
  const courseName = c?.name || "this course";

  // Filter rounds that include this friend
  const withFriend = allRounds
    .map(buildRoundComputed)
    .filter(r => (r.friends || []).includes(friend.id))
    .filter(r => r.opponentScore != null || r.opponentDifferential != null || r.opponentStableford != null);

  function didIWin(r) {
    if (r.opponentScore != null && r.total != null) return r.total < r.opponentScore;
    if (r.opponentDifferential != null && r.differential != null) return r.differential < r.opponentDifferential;
    if (r.opponentStableford != null && r.stableford != null) return r.stableford > r.opponentStableford;
    return null;
  }

  const sorted = [...withFriend].sort((a,b) => new Date(a.date) - new Date(b.date));
  const facts = [];

  // 1. Course-specific dominance
  const courseRounds = sorted.filter(r => r.courseId === courseId);
  if (courseRounds.length >= 2) {
    const myWins = courseRounds.filter(r => didIWin(r) === true).length;
    const losses = courseRounds.filter(r => didIWin(r) === false).length;
    if (myWins === courseRounds.length && courseRounds.length >= 3) {
      facts.push({ text: `${me} is unbeaten at ${courseName} (${myWins}–0)`, punch: 85 });
    } else if (losses === courseRounds.length && courseRounds.length >= 3) {
      facts.push({ text: `${fname} owns ${me} at ${courseName} (${losses}–0)`, punch: 80 });
    } else if (didIWin(round) === false) {
      // Just lost at a course they've been losing at
      const recentLosses = courseRounds.slice(-4).filter(r => didIWin(r) === false).length;
      if (recentLosses >= 3) facts.push({ text: `${fname} has won ${recentLosses} straight at ${courseName}`, punch: 78 });
    } else if (didIWin(round) === true) {
      const recentWins = courseRounds.slice(-4).filter(r => didIWin(r) === true).length;
      if (recentWins >= 3) facts.push({ text: `${me} has won ${recentWins} straight at ${courseName}`, punch: 78 });
    }
  }

  // 2. Streak detection
  if (didIWin(round) === true) {
    let streak = 0;
    for (let i = sorted.length - 1; i >= 0; i--) {
      if (didIWin(sorted[i]) === true) streak++;
      else break;
    }
    if (streak >= 3) facts.push({ text: `${streak}-game winning streak`, punch: 70 + streak * 2 });
  } else if (didIWin(round) === false) {
    let streak = 0;
    for (let i = sorted.length - 1; i >= 0; i--) {
      if (didIWin(sorted[i]) === false) streak++;
      else break;
    }
    if (streak >= 3) facts.push({ text: `${me}'s ${streak}-game losing streak continues`, punch: 60 + streak * 2 });
    else {
      // Did they break a streak?
      const beforeLast = sorted.slice(0, -1);
      let prevWinStreak = 0;
      for (let i = beforeLast.length - 1; i >= 0; i--) {
        if (didIWin(beforeLast[i]) === true) prevWinStreak++;
        else break;
      }
      if (prevWinStreak >= 3) facts.push({ text: `${fname} ends ${me}'s ${prevWinStreak}-game streak`, punch: 75 });
    }
  }

  // 3. Weather quirks
  if (round.weather) {
    const sameWeather = sorted.filter(r => r.weather === round.weather);
    if (sameWeather.length >= 3) {
      const myWinsW = sameWeather.filter(r => didIWin(r) === true).length;
      const wlabel = { sun: "in the sun", cloud: "in cloudy weather", rain: "in the rain", wind: "in windy conditions", cold: "in the cold", hot: "in hot weather" }[round.weather] || round.weather;
      if (myWinsW === 0 && sameWeather.length >= 3) facts.push({ text: `${me} has never won ${wlabel} (0–${sameWeather.length})`, punch: 76 });
      else if (myWinsW === sameWeather.length && sameWeather.length >= 3) facts.push({ text: `${me} is undefeated ${wlabel} (${myWinsW}–0)`, punch: 76 });
    }
  }

  // 4. Time of day quirks
  if (round.teeTime) {
    const bucket = getTimeOfDayBucket(round.teeTime);
    const sameTime = sorted.filter(r => getTimeOfDayBucket(r.teeTime) === bucket);
    if (sameTime.length >= 3) {
      const myWinsT = sameTime.filter(r => didIWin(r) === true).length;
      if (myWinsT === sameTime.length) facts.push({ text: `${me} is ${myWinsT}–0 ${bucket.toLowerCase()}`, punch: 72 });
      else if (myWinsT === 0) facts.push({ text: `${me} has never won ${bucket.toLowerCase()} vs ${fname}`, punch: 72 });
    }
  }

  // 5. Margin of victory (cinematic for current round)
  if (round.total != null && round.opponentScore != null) {
    const margin = Math.abs(round.total - round.opponentScore);
    if (margin >= 10) facts.push({ text: didIWin(round) ? `${margin}-shot beating` : `Lost by ${margin}`, punch: 65 + margin });
    else if (margin === 1) facts.push({ text: "Came down to the last hole", punch: 68 });
  }

  // 6. Personal best (lowest score against this rival)
  if (round.total != null && didIWin(round) === true) {
    const myScores = withFriend.map(r => r.total).filter(x => x != null);
    if (myScores.length >= 3 && Math.min(...myScores) === round.total) {
      facts.push({ text: `${me}'s lowest ever vs ${fname}`, punch: 88 });
    }
  }

  // 7. Years of history
  if (sorted.length >= 2) {
    const firstDate = new Date(sorted[0].date);
    const yearsApart = (new Date(round.date) - firstDate) / (365.25 * 86400000);
    if (yearsApart >= 1) {
      const total = withFriend.length;
      facts.push({ text: `Round ${total} in ${yearsApart.toFixed(0)}+ years of rivalry`, punch: 50 + Math.min(20, Math.floor(yearsApart * 5)) });
    }
  }

  // Sort by punch
  return facts.sort((a, b) => b.punch - a.punch);
}

function pickBestFact(round, allRounds, friend, meName) {
  const facts = findFunStats(round, allRounds, friend, meName);
  return facts[0]?.text || null;
}

/* ---------- Scorecard OCR ---------- */
async function loadTesseract() {
  if (window.Tesseract) return window.Tesseract;
  return new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = 'https://unpkg.com/tesseract.js@5/dist/tesseract.min.js';
    s.onload = () => resolve(window.Tesseract);
    s.onerror = () => reject(new Error('Couldn\'t load OCR library'));
    document.head.appendChild(s);
  });
}

/** Parse scorecard OCR text and try to extract par, SI, and yardage rows.
 *  We look for rows of 9 or 18 numbers and classify them by value range. */
function parseScorecardText(text, expectedHoles = 18) {
  const lines = text.split(/\n/).map(l => l.trim()).filter(Boolean);

  // Extract sequences of numbers from each line
  const numericLines = lines.map(line => {
    const nums = line.match(/\d+/g)?.map(Number) || [];
    return { line, nums };
  });

  // Strategies: look for lines with 9 or 18 numbers (or close to it)
  function classify(nums) {
    const sum = nums.reduce((s,x) => s+x, 0);
    const avg = sum / nums.length;
    const max = Math.max(...nums);
    const min = Math.min(...nums);

    // Par: all 3-6
    if (nums.every(n => n >= 3 && n <= 6) && avg >= 3.3 && avg <= 5) return 'par';
    // SI: permutation of 1..N (or close to it), max ≈ N
    if (max <= expectedHoles && min >= 1 && new Set(nums).size === nums.length) return 'si';
    // Yardage/distance: many > 80
    if (avg > 80 && max < 800) return 'dist';
    return null;
  }

  let par = [], si = [], dist = [];
  for (const { nums } of numericLines) {
    // Sometimes the OCR concatenates rows. Look at exactly 9 or 18 numbers.
    const candidates = [];
    if (nums.length === expectedHoles) candidates.push(nums);
    if (nums.length === 9) candidates.push(nums);
    // Also try the "totals row" pattern: 9 + a sum + 9 + total. Drop sums.
    if (nums.length === expectedHoles + 2 || nums.length === expectedHoles + 1) {
      // try removing last 2 (out, total)
      candidates.push(nums.slice(0, expectedHoles));
    }
    for (const c of candidates) {
      const kind = classify(c);
      if (kind === 'par' && par.length === 0) par = c;
      if (kind === 'si' && si.length === 0) si = c;
      if (kind === 'dist' && dist.length === 0) dist = c;
    }
  }

  return { par, si, dist };
}

/* ============================================================
   PWA: service worker + install prompt + update flow
   ============================================================ */
let deferredInstall = null;
let waitingServiceWorker = null;

const PWA = {
  DISMISS_KEY: 'fairway.pwa.installDismissedAt',
  // Show banner again 14 days after dismissal
  DISMISS_TTL_MS: 14 * 24 * 60 * 60 * 1000,
};

function isStandalone() {
  return window.matchMedia('(display-mode: standalone)').matches
      || window.navigator.standalone === true;
}
function isIOS() {
  const ua = window.navigator.userAgent.toLowerCase();
  if (/iphone|ipad|ipod/.test(ua) && !window.MSStream) return true;
  return navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1;
}
function installDismissedRecently() {
  return sessionStorage.getItem('fairway.pwa.dismissed') === '1';
}
function isInstalledFlag() {
  try { return localStorage.getItem('fairway.pwa.installed') === '1'; } catch (e) { return false; }
}
function markInstalled() {
  try { localStorage.setItem('fairway.pwa.installed', '1'); } catch (e) {}
  hideInstallBanner();
}
function showInstallBanner() {
  if (isStandalone() || installDismissedRecently()) return;  // re-install: don't block on the persistent installed flag
  const el = document.getElementById('pwa-install-banner');
  if (el) el.classList.add('show');
}
function hideInstallBanner() {
  const el = document.getElementById('pwa-install-banner');
  if (el) el.classList.remove('show');
}
function dismissInstallPrompt() {
  sessionStorage.setItem('fairway.pwa.dismissed', '1');
  hideInstallBanner();
  closeIOSInstall();
}
function triggerInstallPrompt() {
  if (deferredInstall) {
    // Android/Chrome: ett trykk = native installasjon
    deferredInstall.prompt();
    deferredInstall.userChoice.then(choice => {
      if (choice && choice.outcome === 'accepted') { markInstalled(); }
      deferredInstall = null;
    });
    return;
  }
  if (isIOS()) { showInstallHelp(); return; }
  if (/Android|SamsungBrowser/i.test(navigator.userAgent)) {
    // Ingen install-prompt paa Android betyr at appen allerede er installert
    // (Chrome holder bare prompten tilbake for installerte/ikke-kvalifiserte apper).
    markInstalled();
    if (typeof showToast === 'function') showToast('Appen er allerede lagt til \u2713');
    return;
  }
  showInstallHelp();
}
