// Sign-in with email + password
window.doSignIn = async function () {
  const email = (document.getElementById('auth-email')?.value || '').trim();
  const password = document.getElementById('auth-password')?.value || '';
  const err = document.getElementById('auth-error');
  const btn = document.getElementById('auth-submit-btn');
  if (err) err.style.display = 'none';
  if (!email || !/.+@.+\..+/.test(email)) {
    if (err) { err.textContent = "Add a valid email"; err.style.display = ''; }
    document.getElementById('auth-email')?.focus();
    return;
  }
  if (!password || password.length < 6) {
    if (err) { err.textContent = "Password must be at least 6 characters"; err.style.display = ''; }
    document.getElementById('auth-password')?.focus();
    return;
  }
  if (!window.fairwayCloud?.signIn) {
    if (err) { err.textContent = "Cloud not ready — refresh and try again"; err.style.display = ''; }
    return;
  }
  if (btn) { btn.disabled = true; btn.textContent = "Signing in…"; }
  try {
    const { error } = await window.fairwayCloud.signIn(email, password);
    if (error) throw error;
    showToast("Signed in ✓");
    closeModal();
  } catch (e) {
    if (btn) { btn.disabled = false; btn.textContent = "Sign in"; }
    if (err) { err.textContent = e.message || "Couldn't sign in"; err.style.display = ''; }
  }
};

window.doSetPassword = async function () {
  const inp = document.getElementById('set-pw-input');
  const msg = document.getElementById('set-pw-msg');
  const pw = (inp && inp.value) || '';
  const show = (m, ok) => { if (msg) { msg.textContent = m; msg.style.display = ''; msg.style.color = ok ? 'var(--accent-bright)' : 'var(--tension)'; } };
  if (!pw || pw.length < 6) { show('Password must be at least 6 characters', false); if (inp) inp.focus(); return; }
  if (!window.fairwayCloud || !window.fairwayCloud.setPassword) { show('Cloud not ready — refresh and try again', false); return; }
  try {
    const { error } = await window.fairwayCloud.setPassword(pw);
    if (error) throw error;
    show('Password saved \u2713 — you can now sign in with email + password.', true);
    if (inp) inp.value = '';
  } catch (e) {
    show((e && e.message) || "Couldn't set password", false);
  }
};

/* ============ Password recovery: show "set new password" after a reset link ============ */
window.frTogglePw = function (id, link) {
  const el = document.getElementById(id);
  if (!el) return;
  if (el.type === 'password') { el.type = 'text'; if (link) link.textContent = 'Hide'; }
  else { el.type = 'password'; if (link) link.textContent = 'Show'; }
};
