window.doSaveNewPassword = async function () {
  const pw = (document.getElementById('np-pw')?.value) || '';
  const msg = document.getElementById('np-msg');
  const btn = document.getElementById('np-btn');
  const show = (m, ok) => { if (msg) { msg.textContent = m; msg.style.display = ''; msg.style.color = ok ? 'var(--accent-bright)' : 'var(--tension)'; } };
  if (pw.length < 6) { show('Password must be at least 6 characters', false); return; }
  if (!window.fairwayCloud || !window.fairwayCloud.setPassword) { show('Cloud not ready — refresh and try again', false); return; }
  if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }
  try {
    const { error } = await window.fairwayCloud.setPassword(pw);
    if (error) throw error;
    window._frInRecovery = false;
    try { history.replaceState(null, '', location.pathname); } catch (e) {}
    closeModal();
    showToast('Password updated \u2713');
  } catch (e) {
    if (btn) { btn.disabled = false; btn.textContent = 'Save password'; }
    show((e && e.message) || "Couldn't update password", false);
  }
};
let _frRecoveryHandled = false;
// Set synchronously from the URL so nothing else (profile setup, sync) interrupts the reset flow.
try { window._frInRecovery = /type=recovery/.test((location.hash || '') + ' ' + (location.search || '')); } catch (e) { window._frInRecovery = false; }
function frMaybeRecovery(ev) {
  if (_frRecoveryHandled) return;
  const h = (location.hash || '') + ' ' + (location.search || '');
  if (ev === 'PASSWORD_RECOVERY' || /type=recovery/.test(h)) {
    _frRecoveryHandled = true;
    window._frInRecovery = true;
    setTimeout(() => { try { openSetNewPasswordModal(); } catch (e) {} }, 400);
  }
}
if (window.fairwayCloud && window.fairwayCloud.onAuthChange) window.fairwayCloud.onAuthChange((s, p, ev) => frMaybeRecovery(ev));
window.addEventListener('load', function () { try { frMaybeRecovery(window.fairwayCloud && window.fairwayCloud.getAuthEvent && window.fairwayCloud.getAuthEvent()); } catch (e) {} });
try { frMaybeRecovery(window.fairwayCloud && window.fairwayCloud.getAuthEvent && window.fairwayCloud.getAuthEvent()); } catch (e) {}

