window.doSignup = async function () {
  const name = (document.getElementById('su-name')?.value || '').trim();
  const email = (document.getElementById('su-email')?.value || '').trim();
  const password = document.getElementById('su-password')?.value || '';
  const err = document.getElementById('su-error');
  const btn = document.getElementById('su-btn');
  const showErr = (m) => { if (err) { err.textContent = m; err.style.display = ''; } };
  if (err) err.style.display = 'none';
  if (!email || !/.+@.+\..+/.test(email)) { showErr('Add a valid email'); document.getElementById('su-email')?.focus(); return; }
  if (!password || password.length < 6) { showErr('Password must be at least 6 characters'); document.getElementById('su-password')?.focus(); return; }
  const password2 = document.getElementById('su-password2')?.value || '';
  if (password !== password2) { showErr('Passwords do not match'); document.getElementById('su-password2')?.focus(); return; }
  if (!name) { showErr('Add your name'); document.getElementById('su-name')?.focus(); return; }
  if (!window.fairwayCloud?.signUp) { showErr('Cloud not ready — refresh and try again'); return; }
  if (btn) { btn.disabled = true; btn.textContent = 'Creating…'; }
  try {
    const { data, error } = await window.fairwayCloud.signUp(email, password, name);
    if (error) throw error;
    try { const pr = activeProfile(); if (pr) { pr.name = name; saveState(); } } catch (e) {}
    if (data && data.session) {
      closeModal();
      showToast('Account created — welcome, ' + name + '!');
    } else {
      closeModal();
      openModal(`
        <div style="text-align:center; padding: 8px 0 4px">
          <div style="font-size: 48px; margin-bottom: 8px">📧</div>
          <h2 style="margin:0 0 8px">Confirm your email</h2>
          <p style="color: var(--muted); font-size: 13px; line-height: 1.55; max-width: 360px; margin: 0 auto 14px">
            We sent a confirmation link to <strong style="color: var(--gold-bright)">${email}</strong>.<br>
            Tap it to finish creating your account, then sign in with your password.
          </p>
          <button class="btn btn-gold" style="width:100%" onclick="closeModal()">Got it</button>
        </div>`);
    }
  } catch (e) {
    if (btn) { btn.disabled = false; btn.textContent = 'Create account'; }
    showErr((e && e.message) || "Couldn't create account");
  }
};

