window.doForgotPassword = async function () {
  const email = (document.getElementById('auth-email')?.value || '').trim();
  const err = document.getElementById('auth-error');
  const info = document.getElementById('auth-info');
  if (err) err.style.display = 'none';
  if (info) info.style.display = 'none';
  if (!email) {
    if (err) { err.textContent = "Enter your email first, then tap Forgot password"; err.style.display = ''; }
    document.getElementById('auth-email')?.focus();
    return;
  }
  if (!window.fairwayCloud?.resetPassword) {
    if (err) { err.textContent = "Cloud not ready"; err.style.display = ''; }
    return;
  }
  try {
    const { error } = await window.fairwayCloud.resetPassword(email);
    if (error) throw error;
    if (info) { info.textContent = `Reset link sent to ${email}. Check your inbox.`; info.style.display = ''; }
  } catch (e) {
    if (err) { err.textContent = "Couldn't send reset: " + (e.message || 'unknown'); err.style.display = ''; }
  }
};

window.switchAuthTab = function(mode) {
  window._authMode = mode;
  document.getElementById('auth-tab-login').classList.toggle('active', mode === 'login');
  document.getElementById('auth-tab-signup').classList.toggle('active', mode === 'signup');
  document.getElementById('auth-name-field').style.display = mode === 'signup' ? '' : 'none';
  document.getElementById('auth-submit').textContent = mode === 'signup' ? 'Create account' : 'Sign in';
  const fl = document.getElementById('auth-forgot-link');
  if (fl) fl.style.display = mode === 'signup' ? 'none' : '';
  const errEl = document.getElementById('auth-error');
  const infoEl = document.getElementById('auth-info');
  if (errEl) errEl.style.display = 'none';
  if (infoEl) infoEl.style.display = 'none';
};

window.doForgotPassword = async function() {
  const emailInput = document.getElementById('auth-email');
  const email = (emailInput?.value || '').trim();
  const err = document.getElementById('auth-error');
  const info = document.getElementById('auth-info');
  if (err) err.style.display = 'none';
  if (info) info.style.display = 'none';
  if (!email) {
    err.textContent = 'Enter your email first, then we send a reset link';
    err.style.display = '';
    emailInput?.focus();
    return;
  }
  if (!window.fairwayCloud?.resetPassword) {
    err.textContent = 'Cloud connection not ready';
    err.style.display = '';
    return;
  }
  try {
    const { error } = await window.fairwayCloud.resetPassword(email);
    if (error) throw error;
    info.textContent = 'A reset email was sent to ' + email + '. Check your inbox and spam folder.';
    info.style.display = '';
  } catch (e) {
    err.textContent = 'Could not send reset email: ' + (e.message || 'unknown error');
    err.style.display = '';
  }
};

async function doAuth() {
  const email = document.getElementById('auth-email').value.trim();
  const password = document.getElementById('auth-password').value;
  const name = document.getElementById('auth-name')?.value?.trim() || '';
  const err = document.getElementById('auth-error');
  err.style.display = 'none';

  if (!email || !password) { err.textContent = 'Fill in email and password'; err.style.display = ''; return; }
  if (password.length < 6) { err.textContent = 'Password must be at least 6 characters'; err.style.display = ''; return; }

  const submitBtn = document.getElementById('auth-submit');
  submitBtn.disabled = true;
  submitBtn.textContent = 'Please wait...';

  try {
    if (window._authMode === 'signup') {
      if (!name) { err.textContent = 'Enter your name'; err.style.display = ''; submitBtn.disabled = false; submitBtn.textContent = 'Create account'; return; }
      const { data, error } = await window.fairwayCloud.signUp(email, password, name);
      if (error) throw error;
      if (data?.user && !data.session) {
        showToast("Check your email to confirm your account", false);
      } else {
        showToast(`Welcome, ${name}!`);
      }
    } else {
      const { error } = await window.fairwayCloud.signIn(email, password);
      if (error) throw error;
      showToast("Signed in ✓");
    }
    closeModal();
  } catch (e) {
    err.textContent = e.message || 'Sign-in error';
    err.style.display = '';
    submitBtn.disabled = false;
    submitBtn.textContent = window._authMode === 'signup' ? 'Create account' : 'Sign in';
  }
}

/* =====================================================
   CLOUD SYNC - rounds, friends, rivalries, achievements
   ===================================================== */

let cloudSyncInProgress = false;

async function syncFromCloud() {
  if (cloudSyncInProgress || !window.fairwayCloud?.isLoggedIn()) return;
  cloudSyncInProgress = true;
  try {
    const p = activeProfile();
    if (!p) return;

    // Pull profile
    const { data: cloudProfile } = await window.fairwayCloud.fetchMyProfile();
    if (cloudProfile) {
      p.name = cloudProfile.name || p.name;
      p.homeClub = cloudProfile.home_club || p.homeClub || "";
      p.startedYear = cloudProfile.started_year || p.startedYear;
      p.targetHcp = cloudProfile.target_hcp || p.targetHcp;
      p.bio = cloudProfile.bio || p.bio || "";
      if (cloudProfile.manual_hcp != null) p.settings.manualHcp = cloudProfile.manual_hcp;
      if (cloudProfile.avatar_url && String(cloudProfile.avatar_url).startsWith('data:') && !(p.avatar && String(p.avatar).startsWith('data:'))) p.avatar = cloudProfile.avatar_url;
    }

    // Pull rounds, friends, rivalries in parallel
    const [roundsRes, friendsRes, rivalriesRes, achRes] = await Promise.all([
      window.fairwayCloud.fetchMyRounds(),
      window.fairwayCloud.fetchMyFriends(),
      window.fairwayCloud.fetchMyRivalries(),
      window.fairwayCloud.fetchMyAchievements(),
    ]);

    // MERGE strategy: never blindly overwrite. Keep local data, add cloud-only items,
    // prefer cloud version when IDs match. This protects against race conditions where
    // cloud doesn't yet have a recently-saved local item.
    function mergeById(local, cloud, mapper) {
      const byId = new Map();
      (local || []).forEach(item => byId.set(item.id, item));
      (cloud || []).forEach(c => { const mapped = mapper(c); byId.set(mapped.id, mapped); });
      return [...byId.values()];
    }

    if (!roundsRes.error && roundsRes.data) {
      p.rounds = mergeById(p.rounds, roundsRes.data, window.fairwayCloud.mapRoundCloudToLocal);
    }
    if (!friendsRes.error && friendsRes.data) {
      p.friends = mergeById(p.friends, friendsRes.data, window.fairwayCloud.mapFriendCloudToLocal);
    }
    if (!rivalriesRes.error && rivalriesRes.data) {
      p.rivalries = mergeById(p.rivalries, rivalriesRes.data, window.fairwayCloud.mapRivalryCloudToLocal);
    }
    if (!achRes.error && achRes.data) {
      const seen = new Set((p.achievementsSeen || []).map(a => a.id));
      (achRes.data || []).forEach(a => {
        if (!seen.has(a.trophy_id)) p.achievementsSeen.push({ id: a.trophy_id, earnedAt: a.earned_at });
      });
    }

    // Adopt any courses referenced by rounds that we don't have locally
    const localCourseIds = new Set(state.courses.map(c => c.id));
    const missingCourseIds = new Set();
    p.rounds.forEach(r => { if (r.courseId && !localCourseIds.has(r.courseId)) missingCourseIds.add(r.courseId); });
    if (missingCourseIds.size > 0) {
      const promises = [...missingCourseIds].map(id => window.fairwayCloud.fetchCourseById(id));
      const results = await Promise.all(promises);
      results.forEach(({ data }) => {
        if (data) adoptCloudCourse({
          id: data.id, name: data.name, country: data.country || "",
          city: data.city || "", holes: data.holes || 18, par: data.par || 72,
          tees: data.tees || [], holesData: data.holes_data || [],
          _fromCloud: true,
        });
      });
    }

    refreshProfileAliases();
    saveState();

    // Re-render whatever is currently visible
    const activeTab = document.querySelector('#tabs button.active')?.dataset.tab;
    if (activeTab) activateTab(activeTab);

    console.log(`[Cloud] Synced ${p.rounds.length} rounds, ${p.friends.length} friends, ${p.rivalries.length} rivalries, ${p.achievementsSeen.length} achievements`);

    // === SOCIAL v2: leagues, friendships, live rounds, proposals ===
    try {
      // Pull leagues and merge with local
      if (window.fairwayCloud.listMyLeagues) {
        const lgRes = await window.fairwayCloud.listMyLeagues();
        if (lgRes.data && lgRes.data.length) {
          const local = leaguesGet();
          for (const lg of lgRes.data) {
            const idx = local.findIndex(l => (l.cloudId && l.cloudId === lg.id) || l.code === lg.code);
            const membersRes = await window.fairwayCloud.listLeagueMembers(lg.id);
            const members = (membersRes.data || []).map(m => ({
              userId: m.user_id, name: m.name, role: m.role,
              joinedAt: m.joined_at || new Date().toISOString(), status: m.status || 'active'
            }));
            if (idx >= 0) {
              local[idx].cloudId = lg.id;
              local[idx].code = lg.code;
              local[idx].name = lg.name;
              local[idx].year = lg.year;
              local[idx].periodStart = lg.period_start || local[idx].periodStart;
              local[idx].periodEnd = lg.period_end || local[idx].periodEnd;
              local[idx].members = members.length ? members : local[idx].members;
            } else {
              local.push({
                id: lg.id, cloudId: lg.id, code: lg.code, name: lg.name, year: lg.year,
                ownerId: lg.owner_id, ownerName: '',
                createdAt: lg.created_at, periodStart: lg.period_start, periodEnd: lg.period_end,
                members,
              });
            }
          }
          leaguesSet(local);
        }
      }
      // Pull friendships (server-side friends) and merge
      if (window.fairwayCloud.listFriendships) {
        const fRes = await window.fairwayCloud.listFriendships();
        if (fRes.data && fRes.data.length) {
          const byName = new Map(p.friends.map(f => [(f.name||'').toLowerCase(), f]));
          for (const prof of fRes.data) {
            const key = (prof.name || '').toLowerCase();
            if (!byName.has(key)) {
              p.friends.push({
                id: prof.id, name: prof.name, _cloudUserId: prof.id, cloudId: prof.id,
                homeClub: prof.home_club, manualHcp: prof.manual_hcp,
              });
            } else {
              const f = byName.get(key);
              f._cloudUserId = prof.id;
              if (!f.cloudId) f.cloudId = prof.id;
              f.homeClub = f.homeClub || prof.home_club;
            }
          }
        }
      }
    } catch (e) { console.warn("[Cloud] social pull failed:", e); }

    // === REALTIME SUBSCRIPTIONS ===
    try { setupCloudRealtime(); } catch (e) { console.warn('realtime setup', e); }

    // === PUSH NOTIFICATIONS: auto-prompt once per session if not yet enabled ===
    try { maybeAutoEnablePush(); } catch (e) {}

    saveState();
  } catch (e) {
    console.warn("[Cloud] Sync failed:", e);
  } finally {
    cloudSyncInProgress = false;
  }
}

/* Set up Supabase Realtime subscriptions for live UI updates */
let _fglRealtimeSetup = false;
function setupCloudRealtime() {
  if (_fglRealtimeSetup || !window.fairwayCloud?.isLoggedIn?.()) return;
  _fglRealtimeSetup = true;
  // Friendships — re-sync friends list on any change
  window.fairwayCloud.subscribeFriendships?.(payload => {
    console.log('[Realtime] friendships', payload);
    setTimeout(() => syncFromCloud(), 400);
  });
  // Live rounds — show a drop-in when a friend starts/completes
  window.fairwayCloud.subscribeLiveRounds?.(payload => {
    try {
      const row = payload.new || payload.record;
      if (!row || row.user_id === window.fairwayCloud.getUser()?.id) return;
      const friendName = (state.friends || []).find(f => f._cloudUserId === row.user_id)?.name
                       || 'A friend';
      if (row.status === 'playing' && typeof caddieDropIn === 'function') {
        caddieDropIn(`<strong>${friendName}</strong> just teed off at <strong>${row.course_name || 'a course'}</strong>. Cheering them on.`);
      } else if (row.status === 'completed' && typeof caddieDropIn === 'function') {
        const par = row.par || 72;
        const rel = row.total != null ? row.total - par : null;
        const relStr = rel == null ? '' : (rel > 0 ? '+' + rel : rel === 0 ? 'E' : String(rel));
        caddieDropIn(`<strong>${friendName}</strong> just finished at <strong>${row.course_name || 'a course'}</strong>: <strong>${row.total}${relStr ? ' (' + relStr + ')' : ''}</strong>.`);
      }
    } catch (e) { console.warn('liverounds handler', e); }
  });
  // Proposals — toast on new pending one
  setTimeout(() => { try { updateApprovalsBadge(); } catch (e) {} }, 3000);
  window.fairwayCloud.subscribeProposals?.(payload => {
    try {
      try { updateApprovalsBadge(); } catch (e) {}
      const row = payload.new || payload.record;
      if (!row) return;
      // Proposer-side: my own proposal got resolved -> apply on my side too.
      const _myId = window.fairwayCloud.getUser()?.id;
      if (row.proposer_id === _myId && row.resolution === 'accepted') {
        const fr = (state.friends || []).find(f => f.cloudId === row.opponent_id);
        if (fr) {
          if (row.kind === 'round') { fr.baseWins = (fr.baseWins||0) + (row.proposer_score||0); fr.baseLosses = (fr.baseLosses||0) + (row.opponent_score||0); }
          else { fr.baseWins = row.proposer_score; fr.baseLosses = row.opponent_score; }
          try { saveState(); } catch (e) {}
          try { if (typeof showToast === 'function') showToast((fr.name||'Your rival') + ' approved the result'); } catch (e) {}
        }
        return;
      }
      if (row.opponent_id !== window.fairwayCloud.getUser()?.id) return;
      if (row.resolution !== 'pending') return;
      if (typeof showToast === 'function') showToast('New proposal — open Approvals to review');
      if (typeof caddieDropIn === 'function') {
        caddieDropIn(`You have a new <strong>standing-adjustment proposal</strong>. Check the <strong>Approvals</strong> tab to accept or reject.`);
      }
    } catch (e) { console.warn('proposals handler', e); }
  });
  // Notifications — show as in-app toast
  window.fairwayCloud.subscribeNotifications?.(notif => {
    try {
      if (typeof caddieDropIn === 'function') caddieDropIn(`<strong>${notif.title || 'Fairway'}</strong>${notif.body ? ' — ' + notif.body : ''}`);
      else if (typeof showToast === 'function') showToast(notif.title || 'New notification');
    } catch (e) {}
  });
  console.log('[Realtime] subscriptions active');
}

/* One-time prompt for push notifications, once per signed-in session */
let _pushPromptShown = false;
async function maybeAutoEnablePush() {
  return; // Push deferred — no prompting/registration until VAPID + Edge Function are set up (see FR-supabase-steg.md)
  if (_pushPromptShown) return;
  if (!('Notification' in window) || !('serviceWorker' in navigator) || !('PushManager' in window)) return;
  if (Notification.permission === 'granted') {
    // Already granted — silently subscribe
    try { await window.fairwayCloud.enablePush?.(); } catch (e) {}
    return;
  }
  if (Notification.permission === 'denied') return; // don't nag
  const dismissedAt = parseInt(localStorage.getItem('fgl_push_prompt_dismissed_at') || '0', 10);
  if (Date.now() - dismissedAt < 7 * 86400000) return; // wait a week before re-asking
  _pushPromptShown = true;
  setTimeout(() => {
    if (typeof caddieDropIn === 'function') {
      caddieDropIn(`Want to get notified when a friend starts a round or sends you a challenge? <button class="btn btn-gold btn-small" style="margin-top:6px" onclick="enablePushNow()">Turn on notifications</button> <button class="btn btn-ghost btn-small" style="margin-left:6px;margin-top:6px" onclick="dismissPushPrompt()">Not now</button>`);
    }
  }, 8000);
}
window.enablePushNow = async function () {
  try {
    const perm = await Notification.requestPermission();
    if (perm !== 'granted') {
      showToast('Notifications blocked — enable in browser settings', true);
      return;
    }
    if (window.fairwayCloud?.enablePush) {
      const res = await window.fairwayCloud.enablePush();
      if (res?.error) { showToast(res.error, true); return; }
      showToast('Notifications enabled ✓');
    }
  } catch (e) {
    showToast('Could not enable: ' + (e.message || 'unknown'), true);
  }
};
window.dismissPushPrompt = function () {
  localStorage.setItem('fgl_push_prompt_dismissed_at', String(Date.now()));
  showToast('OK — you can turn this on later in your profile');
};

