/* Cloud courses are queried on-demand from Supabase, NOT loaded into localStorage.
   The seed courses stay local for offline. Cloud is searched live when user types. */
const cloudCourseCache = new Map();  // id -> course (recently picked, kept in memory only)

async function searchCloudCourses(query, limit = 12) {
  if (!window.fairwayCloud || !query || query.length < 2) return [];  // cloud search allowed logged-out (capped RPC)
  try {
    const { data, error } = await window.fairwayCloud.fetchCourses({ search: query, limit });
    if (error || !data) return [];
    return data.map(c => ({
      id: c.id,
      name: c.name,
      country: c.country || "",
      city: c.city || "",
      holes: c.holes || 18,
      par: c.par || 72,
      tees: c.tees || [],
      holesData: c.holes_data || [],
      userContributed: c.user_contributed,
      _fromCloud: true,
    }));
  } catch (e) {
    console.warn("Cloud search failed:", e);
    return [];
  }
}

// When a cloud course is picked for a round, add it to local state so we have it for stats
function adoptCloudCourse(course) {
  const existing = state.courses.find(c => c.id === course.id);
  if (existing) return existing;
  state.courses.push(course);
  cloudCourseCache.set(course.id, course);
  saveState();
  return course;
}

