window.hcBulkParse = function () {
  const raw = (document.getElementById('hc-bulk')?.value || '').trim();
  if (!raw) return { rows: [], error: 'Paste at least one score' };
  const rows = [];
  raw.split(/\n+/).forEach(ln => {
    const parts = ln.split(/[,;\t]+/).map(s => s.trim()).filter(Boolean);
    if (parts.length < 3) return;
    const score = parseInt(parts[0]); const cr = parseFloat(parts[1]); const slope = parseInt(parts[2]);
    if (isNaN(score) || isNaN(cr) || isNaN(slope)) return;
    rows.push({ score, cr, slope, diff: (113 / slope) * (score - cr) });
  });
  return { rows };
};
window.hcBulkCompute = function (rows) {
  if (!rows.length) return null;
  // WHS: use the most recent 20 only (input order = chronological, newest first or last)
  const lastTwenty = rows.slice(0, 20);
  const diffs = lastTwenty.map(r => r.diff).sort((a, b) => a - b);
  const n = diffs.length;
  let best, adjustment = 0;
  if (n === 1) { best = diffs.slice(0, 1); adjustment = -2; }
  else if (n === 2) { best = diffs.slice(0, 1); adjustment = -2; }
  else if (n === 3) { best = diffs.slice(0, 1); adjustment = -2; }
  else if (n === 4) { best = diffs.slice(0, 1); adjustment = -1; }
  else if (n === 5) { best = diffs.slice(0, 1); adjustment = 0; }
  else if (n === 6) { best = diffs.slice(0, 2); adjustment = -1; }
  else if (n <= 8) { best = diffs.slice(0, 2); adjustment = 0; }
  else if (n <= 11) { best = diffs.slice(0, 3); adjustment = 0; }
  else if (n <= 14) { best = diffs.slice(0, 4); adjustment = 0; }
  else if (n <= 16) { best = diffs.slice(0, 5); adjustment = 0; }
  else if (n <= 18) { best = diffs.slice(0, 6); adjustment = 0; }
  else if (n === 19) { best = diffs.slice(0, 7); adjustment = 0; }
  else { best = diffs.slice(0, 8); adjustment = 0; }
  const avg = best.reduce((s, x) => s + x, 0) / best.length;
  return Math.round((avg + adjustment) * 10) / 10;
};
window.hcBulkPreview = function () {
  const { rows, error } = hcBulkParse();
  const res = document.getElementById('hc-bulk-result');
  if (!res) return;
  if (error) { res.style.color = 'var(--tension)'; res.textContent = error; return; }
  if (!rows.length) { res.style.color = 'var(--tension)'; res.textContent = "No valid rows. Format: score, CR, slope"; return; }
  const hcp = hcBulkCompute(rows);
  res.style.color = 'var(--gold-bright)';
  res.innerHTML = `<strong>Parsed ${rows.length} round${rows.length === 1 ? '' : 's'}.</strong>${rows.length > 20 ? ' (using your most recent 20)' : ''} WHS index = <strong>${hcp}</strong>`;
};
window.hcBulkApply = function () {
  const { rows } = hcBulkParse();
  if (!rows.length) { showToast('Add valid rows first', true); return; }
  const hcp = hcBulkCompute(rows);
  const p = activeProfile();
  if (!p) return;
  if (!p.settings) p.settings = {};
  p.settings.manualHcp = hcp;
  saveState();
  refreshProfileAliases?.();
  renderHeader?.();
  const fld = document.getElementById('p-manual-hcp');
  if (fld) fld.value = hcp;
  showToast(`Handicap set to ${hcp}`);
};

window.broadcastRoundLive = function (round) {
  // Local feed + (when signed in) Supabase live_rounds INSERT so friends see it via Realtime.
  try {
    const me = activeProfile()?.name || 'You';
    const courseName = round.courseId ? (getCourse(round.courseId)?.name || 'a course') : 'a course';
    const total = round.total;
    const par = round.courseId ? (getCourse(round.courseId)?.par || 72) : 72;
    const rel = total != null ? total - par : null;
    const relStr = rel == null ? '' : (rel > 0 ? '+' + rel : rel === 0 ? 'E' : String(rel));
    // Local feed
    const feed = JSON.parse(localStorage.getItem('fgl_live_feed') || '[]');
    feed.unshift({ at: new Date().toISOString(), by: me, course: courseName, total, rel: relStr, friends: round.friends || [] });
    if (feed.length > 50) feed.length = 50;
    localStorage.setItem('fgl_live_feed', JSON.stringify(feed));
    // Caddie cameo for confirmation
    if (typeof caddieDropIn === 'function' && (round.friends || []).length) {
      setTimeout(() => caddieDropIn(`Round saved! Your <strong>${(round.friends || []).length}</strong> friend${(round.friends || []).length === 1 ? '' : 's'} will see <strong>${total}${rel != null ? ' (' + relStr + ')' : ''}</strong> at ${courseName} when their app syncs.`), 1800);
    }
    // CLOUD: insert a live_round row then immediately mark completed (so friends get one push)
    if (window.fairwayCloud?.isLoggedIn?.() && window.fairwayCloud.startLiveRound) {
      const _existingLive = window.roundFormState?._liveRoundId;
      if (_existingLive && window.fairwayCloud.completeLiveRound) {
        // The round was already broadcast live during play — just complete that row.
        window.fairwayCloud.completeLiveRound(_existingLive, { total, differential: round.differential || null });
      } else {
        window.fairwayCloud.startLiveRound({
          courseId: round.courseId || null,
          courseName,
          par,
          friends: round.friends || [],
        }).then(res => {
          if (res?.data?.id) {
            window.fairwayCloud.completeLiveRound(res.data.id, { total, differential: round.differential || null });
          }
        }).catch(e => console.warn('cloud live round', e));
      }
    }
  } catch (e) { console.warn('broadcastRoundLive', e); }
};

/* Called when a round STARTS (entering the wizard or hole-by-hole mode).
   Pushes a live_round 'playing' row so friends get the heads-up. */
window.broadcastRoundStart = function (round) {
  try {
    if (!window.fairwayCloud?.isLoggedIn?.() || !window.fairwayCloud.startLiveRound) return;
    const courseName = round.courseId ? (getCourse(round.courseId)?.name || 'a course') : 'a course';
    const par = round.courseId ? (getCourse(round.courseId)?.par || 72) : 72;
    window.fairwayCloud.startLiveRound({
      courseId: round.courseId || null,
      courseName,
      par,
      friends: round.friends || [],
    }).then(res => {
      if (res?.data?.id) {
        round._liveRoundId = res.data.id;
        try { saveState(); } catch (e) {}
      }
    }).catch(e => console.warn('cloud live round start', e));
  } catch (e) { console.warn('broadcastRoundStart', e); }
};

window.showScoreSummary = function (round) {
  try { broadcastRoundLive(round); } catch (e) {}
  const course = round.courseId ? getCourse(round.courseId) : null;
  const tee = course?.tees?.find(t => t.name === round.teeName);
  const par = (tee && tee.par) || (course && course.par) || 72;
  const total = round.total;
  const rel = total != null ? total - par : null;
  const relStr = rel == null ? '—' : (rel > 0 ? '+' + rel : rel === 0 ? 'E' : String(rel));
  const diff = round.differential != null ? round.differential.toFixed(1) : '—';
  // Net (HC adjusted) — approximate using current handicap
  const p = activeProfile();
  const scoredRounds = (state.rounds || []).filter(r => r.differential != null);
  const hcp = p?.settings?.manualHcp != null ? p.settings.manualHcp : calcHcpIndex(scoredRounds);
  let ch = 0;
  if (hcp != null && tee) ch = Math.round(hcp * (tee.slope / 113) + (tee.cr - tee.par));
  const net = total != null && ch ? total - ch : null;
  const stbl = round.stableford;
  openModal(`
    <div class="rss-modal">
      <div class="section-eyebrow" style="text-align:center; color:#6fae87">✓ ROUND SAVED</div>
      <h2 class="rss-title">You shot <span class="rss-big">${total ?? '—'}</span></h2>
      <div class="rss-rel">${relStr} vs par ${par}</div>
      <div class="rss-grid">
        ${diff !== '—' ? `<div class="rss-stat"><div class="rss-val">${diff}</div><div class="rss-lab">Differential</div></div>` : ''}
        ${net != null ? `<div class="rss-stat"><div class="rss-val">${net}</div><div class="rss-lab">Net score</div></div>` : ''}
        ${ch ? `<div class="rss-stat"><div class="rss-val">${ch}</div><div class="rss-lab">Course HCP</div></div>` : ''}
        ${stbl ? `<div class="rss-stat"><div class="rss-val">${stbl}</div><div class="rss-lab">Stableford</div></div>` : ''}
      </div>
      ${round.playedTo && Object.keys(round.playedTo).length ? `<div class="rss-playedto"><div class="rss-pt-h">Played to ${round.withHcp ? '(net vs par)' : '(vs par)'}</div>${Object.keys(round.playedTo).map(id => { const v = round.playedTo[id]; const vs = v === 0 ? 'E' : (v > 0 ? '+' + v : String(v)); return `<div class="rss-pt-row"><span>${round.playerNames[id] || ''}</span><b>${vs}</b></div>`; }).join('')}</div>` : ''}
      ${course ? `<div class="rss-course">${course.name} · ${round.teeName || ''}</div>` : ''}
      ${(round.friends && round.friends.length) ? `<button class="btn btn-gold" style="width:100%; padding:14px; font-weight:800; margin-top:14px" onclick="frShareResult('${round.id}')"><svg viewBox="0 0 24 24" width="17" height="17" fill="none" stroke="#1a1408" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-3px;margin-right:7px"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.6" y1="13.5" x2="15.4" y2="17.5"/><line x1="15.4" y1="6.5" x2="8.6" y2="10.5"/></svg>Share the result</button>` : ''}
      <button class="btn ${(round.friends && round.friends.length) ? 'btn-ghost' : 'btn-gold'}" style="width:100%; padding:14px; font-weight:800; margin-top:10px" onclick="closeModal()">Done</button>
    </div>
  `);
};

/* ===================== Shareable result card (viral loop) ===================== */
function frResultText(round) {
  const rivals = (round.friends || []).map(fid => (frFindFriend(fid)?.name || 'Rival').split(' ')[0]);
  const rivalStr = rivals.join(' & ') || 'Rival';
  let headline, sub = '';
  let won = null;
  if (round.holePoints && (round.myPoints != null || round.oppPoints != null)) {
    won = (round.myPoints || 0) > (round.oppPoints || 0);
    const tie = (round.myPoints || 0) === (round.oppPoints || 0);
    if (tie) { headline = 'You tied ' + rivalStr; } else { headline = won ? 'You beat ' + rivalStr : rivalStr + ' beat you'; }
    sub = (round.myPoints || 0) + '\u2013' + (round.oppPoints || 0) + ' on holes';
  } else if (round.winner === 'me' || round.winner === 'opp' || round.winner === 'tie') {
    if (round.winner === 'tie') headline = 'You tied ' + rivalStr;
    else { won = round.winner === 'me'; headline = won ? 'You beat ' + rivalStr : rivalStr + ' beat you'; }
    if (round.total != null && round.opponentScore != null) sub = round.total + ' \u2013 ' + round.opponentScore;
  } else if (round.total != null && round.opponentScore != null) {
    won = round.total < round.opponentScore;
    headline = won ? 'You beat ' + rivalStr : (round.total > round.opponentScore ? rivalStr + ' beat you' : 'You tied ' + rivalStr);
    sub = round.total + ' \u2013 ' + round.opponentScore;
  } else { headline = 'You played ' + rivalStr; sub = round.total != null ? ('Round of ' + round.total) : ''; }
  let owes = '';
  if (round.stake) {
    const amt = round.stakeAmount ? (round.stakeAmount + ' ') : '';
    const unit = round.stake === 'money' ? '' : round.stake;
    if (won === true) owes = rivalStr + ' owes you \u00b7 ' + amt + unit;
    else if (won === false) owes = 'You owe ' + rivalStr + ' \u00b7 ' + amt + unit;
  }
  const course = round.courseId ? (getCourse(round.courseId)?.name || '') : (round.courseName || '');
  return { headline, sub, owes, course };
}
function frResultCardSVG(round) {
  const t = frResultText(round);
  const esc = x => String(x || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const W = 1080, H = 1080;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
    <defs>
      <linearGradient id="bg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#0a140e"/><stop offset="100%" stop-color="#030806"/></linearGradient>
      <linearGradient id="gold" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#f7ecc0"/><stop offset="55%" stop-color="#c9a961"/><stop offset="100%" stop-color="#8a7340"/></linearGradient>
    </defs>
    <rect width="${W}" height="${H}" fill="url(#bg)"/>
    <rect x="40" y="40" width="${W-80}" height="${H-80}" rx="28" fill="none" stroke="rgba(201,169,97,0.35)" stroke-width="2"/>
    <text x="${W/2}" y="170" text-anchor="middle" font-family="Georgia, serif" font-size="64" font-weight="700" fill="url(#gold)" letter-spacing="6">FR</text>
    <text x="${W/2}" y="225" text-anchor="middle" font-family="Georgia, serif" font-size="26" fill="#c9a961" letter-spacing="8">FAIRWAY RIVALRY</text>
    <text x="${W/2}" y="${t.headline.length>16?470:480}" text-anchor="middle" font-family="Georgia, serif" font-size="${t.headline.length>16?88:104}" font-weight="700" fill="#ffffff">${esc(t.headline)}</text>
    ${t.sub ? `<text x="${W/2}" y="585" text-anchor="middle" font-family="Georgia, serif" font-size="72" font-weight="700" fill="url(#gold)">${esc(t.sub)}</text>` : ''}
    ${t.course ? `<text x="${W/2}" y="680" text-anchor="middle" font-family="Georgia, serif" font-size="38" fill="#b9b2a0">${esc(t.course)}</text>` : ''}
    ${t.owes ? `<rect x="${W/2-330}" y="745" width="660" height="92" rx="46" fill="rgba(201,169,97,0.14)" stroke="rgba(201,169,97,0.4)" stroke-width="2"/><text x="${W/2}" y="805" text-anchor="middle" font-family="Georgia, serif" font-size="40" font-weight="700" fill="#e1c47e">${esc(t.owes)}</text>` : ''}
    <text x="${W/2}" y="985" text-anchor="middle" font-family="Georgia, serif" font-size="30" fill="#8a7340" letter-spacing="3">fairwayrivalry.com</text>
    <text x="${W/2}" y="1030" text-anchor="middle" font-family="Georgia, serif" font-size="24" fill="#6a6452" letter-spacing="2">Every rivalry starts with one round</text>
  </svg>`;
}
window.frShareResult = async function (roundId) {
  const round = (state.rounds || []).find(r => r.id === roundId); if (!round) return;
  const t = frResultText(round);
  const link = 'https://fairwayrivalry.com';
  const text = `${t.headline}${t.sub ? ' ' + t.sub : ''} \u2014 ${t.course || 'Fairway Rivalry'}${t.owes ? ' \u00b7 ' + t.owes : ''}`;
  try {
    const svg = frResultCardSVG(round);
    const blob = await frSvgToPng(svg, 1080, 1080);
    if (blob && navigator.canShare && navigator.canShare({ files: [new File([blob], 'fairway-result.png', { type: 'image/png' })] })) {
      await navigator.share({ files: [new File([blob], 'fairway-result.png', { type: 'image/png' })], text, url: link });
      return;
    }
    if (blob) { const u = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = u; a.download = 'fairway-result.png'; a.click(); setTimeout(() => URL.revokeObjectURL(u), 4000); showToast('Result card saved \u2014 share it anywhere'); return; }
  } catch (e) {}
  try { if (navigator.share) { await navigator.share({ text, url: link }); return; } } catch (e) {}
  try { prompt('Copy & share:', text + ' ' + link); } catch (e) {}
};
function frSvgToPng(svg, w, h) {
  return new Promise(resolve => {
    try {
      const img = new Image();
      const blob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      img.onload = () => { try { const c = document.createElement('canvas'); c.width = w; c.height = h; const ctx = c.getContext('2d'); ctx.drawImage(img, 0, 0, w, h); URL.revokeObjectURL(url); c.toBlob(b => resolve(b), 'image/png'); } catch (e) { resolve(null); } };
      img.onerror = () => { URL.revokeObjectURL(url); resolve(null); };
      img.src = url;
    } catch (e) { resolve(null); }
  });
}

