// ===================== CADDIE — periodic floating tips throughout the app =====================
const CADDIE_DROPIN_FACTS = [
  // About the user — built from data
  (d) => d.totalRounds >= 1 ? `Did you know? Your last round was ${d.lastDays} days ago. ${d.lastDiff != null ? "Differential " + d.lastDiff.toFixed(1) + "." : ""}` : null,
  (d) => d.bestEver != null ? `Your career best differential is <strong>${d.bestEver.toFixed(1)}</strong>. Remember the day you set it.` : null,
  (d) => d.handicap != null ? `Your handicap index sits at <strong>${d.handicap}</strong>. WHS-style, your best 8 of the last 20.` : null,
  (d) => d.bestCourse ? `You play your best on <strong>${d.bestCourse}</strong> — average diff ${d.bestCourseAvg.toFixed(1)}.` : null,
  (d) => d.recentForm != null ? `Your last 5 rounds average ${d.recentForm.toFixed(1)} differential. ${d.recentForm < (d.bestEver || 99) + 2 ? "You're firing." : "Form will turn."}` : null,
  // General app tips
  () => `Caddie tip: Aim center of every green. Pros only hit 65% of greens. You're not hitting flagsticks.`,
  () => `Quick stat: <strong>60% of all shots</strong> are inside 100 yards. Flip your practice ratio.`,
  () => `Reminder: lag putts to a 1m circle. Three-putts cost more strokes than wild drives.`,
  () => `Mental tip: every shot starts with the routine. Skip it, the brain takes over with bad ideas.`,
  () => `Bogey is a great score from trouble. Don't compound mistakes chasing the hero shot.`,
  () => `Most strokes hide between 40–100m. Sharpen one wedge yardage at a time.`,
  () => `Did you know? The 7-iron is your benchmark club. Know your stock carry within 5m and approaches get a lot easier.`,
  // Course facts (would be richer with course data — placeholder for now)
  () => `Course wisdom: front 9 plays harder when fresh. Don't fight it — settle in.`,
  // Funny / encouraging
  () => `Hot take: nobody remembers your bad shots except you. Move on.`,
  () => `The 19th hole hits different after a smart round.`,
];

function caddieFactData() {
  try {
    const rounds = (state.rounds || []).filter(r => r.gameKind === 'golf' || !r.gameKind).map(buildRoundComputed).filter(r => r.differential != null);
    if (!rounds.length) return { totalRounds: 0 };
    rounds.sort((a, b) => new Date(b.date) - new Date(a.date));
    const last = rounds[0];
    const lastDays = Math.floor((Date.now() - new Date(last.date)) / 86400000);
    const lastDiff = last.differential;
    const bestEver = rounds.reduce((m, r) => r.differential < m ? r.differential : m, 99);
    const handicap = calcHcpIndex(rounds);
    // Best course
    const courseGroups = {};
    rounds.forEach(r => { const c = getCourse(r.courseId); if (!c) return; (courseGroups[c.name] = courseGroups[c.name] || []).push(r.differential); });
    let bestCourse = null, bestCourseAvg = 99;
    Object.entries(courseGroups).forEach(([n, ds]) => { const avg = ds.reduce((s, x) => s + x, 0) / ds.length; if (avg < bestCourseAvg) { bestCourseAvg = avg; bestCourse = n; } });
    const last5 = rounds.slice(0, 5);
    const recentForm = last5.length ? last5.reduce((s, r) => s + r.differential, 0) / last5.length : null;
    return { totalRounds: rounds.length, lastDays, lastDiff, bestEver, handicap, bestCourse, bestCourseAvg, recentForm };
  } catch (e) { return { totalRounds: 0 }; }
}

window.caddieDropIn = function (manualText) {
  if (localStorage.getItem('fgl_caddie_hidden') === '1') return;
  if (localStorage.getItem('fgl_caddie_muted') === '1') return;  // respect notification toggle (#73)
  if (document.getElementById('caddie-dropin')) return; // already showing one
  let txt = manualText;
  if (!txt) {
    const d = caddieFactData();
    const candidates = CADDIE_DROPIN_FACTS.map(fn => fn(d)).filter(Boolean);
    if (!candidates.length) return;
    txt = candidates[Math.floor(Math.random() * candidates.length)];
  }
  const el = document.createElement('div');
  el.id = 'caddie-dropin';
  el.className = 'cd-drop';
  el.innerHTML = `
    <div class="cd-drop-av">
      <svg viewBox="0 0 64 64" style="width:28px;height:28px"><defs><linearGradient id="cdDropG" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#1a1408"/><stop offset="100%" stop-color="#3d2f12"/></linearGradient></defs><g fill="none" stroke="url(#cdDropG)" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="24" cy="16" r="6"/><path d="M 22 22 L 22 42 L 28 56"/><path d="M 26 22 L 32 30 L 30 38 L 36 56"/><rect x="34" y="20" width="14" height="26" rx="3"/><line x1="40" y1="16" x2="40" y2="20"/><line x1="44" y1="14" x2="44" y2="20"/></g></svg>
    </div>
    <div class="cd-drop-body">
      <div class="cd-drop-name">The Caddie</div>
      <div class="cd-drop-text">${txt}</div>
    </div>
    <button class="cd-drop-close" onclick="this.parentElement.remove()" aria-label="Dismiss">✕</button>
  `;
  document.body.appendChild(el);
  // Auto-dismiss after 12 seconds
  setTimeout(() => { if (el.parentElement) el.remove(); }, 12000);
};

// Schedule periodic Caddie drop-ins — once every 4-6 minutes while the app is open
(function () {
  let lastDrop = 0;
  function maybeDrop() {
    if (Date.now() - lastDrop < 240000) return; // min 4 min apart
    if (Math.random() > 0.3) return; // 30% chance each check
    lastDrop = Date.now();
    caddieDropIn();
  }
  setInterval(maybeDrop, 90000); // check every 90s
  // First drop-in shortly after app load if we have data
  setTimeout(() => {
    const d = caddieFactData();
    if (d.totalRounds > 0) { lastDrop = Date.now(); caddieDropIn(); }
  }, 8000);
})();

// Helper: trigger from match mode / per-hole context
window.caddieDropInOnHole = function (holeNum, par, courseName) {
  if (localStorage.getItem('fgl_caddie_hidden') === '1') return;
  const lines = [
    `Hole ${holeNum} — ${par === 3 ? "par 3, two-putt and run" : par === 5 ? "lay up to your favorite wedge, three full shots wins" : "center of the green, never short-side"}.`,
    `Pressure point: hole ${holeNum}. Trust your number.`,
    `Old caddie line: "Don't think. Aim. Swing."`
  ];
  caddieDropIn(lines[Math.floor(Math.random() * lines.length)]);
};

/* ===================== PROFILE & ACCOUNT — simple, secure ===================== */
window.saveProfileChanges = function () {
  const p = activeProfile();
  if (!p) return;
  const name = (document.getElementById('p-name')?.value || '').trim();
  const home = (document.getElementById('p-home-club')?.value || '').trim();
  const mh = document.getElementById('p-manual-hcp')?.value;
  if (!name) { showToast('Name missing', true); return; }
  p.name = name;
  p.homeClub = home;
  if (!p.settings) p.settings = {};
  p.settings.manualHcp = (mh === '' || mh == null) ? null : parseFloat(mh);
  saveState();
  refreshProfileAliases?.();
  renderHeader?.();
  showToast('Profile saved');
  // Sync to cloud if signed in
  if (window.fairwayCloud?.isLoggedIn?.() && window.fairwayCloud?.updateProfile) {
    window.fairwayCloud.updateProfile({ name, home_club: home, manual_hcp: p.settings.manualHcp }).catch(()=>{});
  }
};

function renderAccountInfo() {
  const el = document.getElementById('pp-account-info');
  if (!el) return;
  const cloud = window.fairwayCloud;
  if (!cloud) { el.innerHTML = '<div class="pp-status local"><strong>Local only</strong> · changes stay on this device. Sign in to sync.</div>'; return; }
  if (!cloud.isLoggedIn?.()) {
    el.innerHTML = '<div class="pp-status local"><strong>Local only</strong> · changes stay on this device. Sign in to sync rounds, rivalries and the FGL table across devices.</div>';
    const btn = document.getElementById('pp-signin-btn'); if (btn) btn.textContent = 'Sign in';
    return;
  }
  const user = cloud.getUser?.() || {};
  const prof = cloud.getProfile?.() || {};
  const lastSignIn = user.last_sign_in_at ? new Date(user.last_sign_in_at) : null;
  const created = user.created_at ? new Date(user.created_at) : null;
  const pushSupported = ('Notification' in window) && ('serviceWorker' in navigator) && ('PushManager' in window);
  const pushPerm = pushSupported ? Notification.permission : 'unsupported';
  const pushLabel = pushPerm === 'granted' ? 'Notifications on'
                  : pushPerm === 'denied' ? 'Blocked in browser'
                  : pushPerm === 'default' ? 'Turn on'
                  : 'Not supported';
  const pushAction = `<span style="font-size:11px; color:var(--muted-2)">Coming soon</span>`;
  el.innerHTML = `
    <div class="pp-status synced">
      <div class="pp-status-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="width:18px;height:18px"><path d="M 5 12 L 10 17 L 19 8"/></svg></div>
      <div>
        <div><strong>Signed in & synced</strong></div>
        <div class="pp-status-d">${user.email || prof.name || ''}</div>
        ${lastSignIn ? `<div class="pp-status-d">Last sign-in: ${lastSignIn.toLocaleDateString()} ${lastSignIn.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</div>` : ''}
        ${created ? `<div class="pp-status-d">Member since: ${created.toLocaleDateString()}</div>` : ''}
      </div>
    </div>
    <div style="display:flex; align-items:center; justify-content:space-between; gap:10px; padding:12px 14px; margin-top:10px; background:var(--panel-2); border:1px solid var(--border); border-radius:10px">
      <div>
        <div style="font-size:13px; font-weight:600">Push notifications</div>
        <div style="font-size:11px; color:var(--muted-2); margin-top:2px">Friend starts a round, sends a challenge, or accepts a proposal</div>
      </div>
      <div>${pushAction}</div>
    </div>`;
  const btn = document.getElementById('pp-signin-btn'); if (btn) btn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="width:16px;height:16px;vertical-align:-3px;margin-right:6px"><path d="M 12 3 L 12 14 M 9 11 L 12 14 L 15 11 M 5 19 L 19 19"/></svg>Sign out';
}

window.exportMyData = function () {
  try {
    const p = activeProfile() || {};
    const payload = {
      exportedAt: new Date().toISOString(),
      profile: { name: p.name, homeClub: p.homeClub, manualHcp: p.settings?.manualHcp, createdAt: p.createdAt },
      rounds: p.rounds || [],
      friends: p.friends || [],
      rivalries: p.rivalries || [],
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `fgl-data-${(p.name || 'me').toLowerCase().replace(/\s+/g,'-')}-${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(a.href), 1000);
    showToast('Data exported ✓');
  } catch (e) { showToast('Export failed: ' + (e.message || 'unknown'), true); }
};

window.confirmDeleteProfile = function () {
  const p = activeProfile();
  if (!p) return;
  openModal(`
    <div style="text-align:center; padding:8px 0 4px">
      <h2 style="margin:0 0 8px; color:#c97a7a">Delete profile?</h2>
      <p style="color:var(--muted); font-size:13px; line-height:1.55; max-width:340px; margin:0 auto 14px">This clears <strong>${(p.name || 'this profile')}</strong> and all its data from this device. ${window.fairwayCloud?.isLoggedIn?.() ? 'Your cloud account stays — you can sign out separately.' : ''}</p>
      <p style="font-size:12px; color:var(--muted-2); margin-bottom:14px">Type <strong>delete</strong> to confirm.</p>
      <input id="del-confirm" type="text" placeholder="delete" style="width:100%; background:var(--panel-2); border:1px solid var(--border); border-radius:10px; padding:10px; text-align:center; color:var(--text); font-family:inherit; margin-bottom:14px">
      <div style="display:flex; gap:8px; justify-content:center">
        <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
        <button class="btn" style="background:#c97a7a; color:#1a0606; border:none" onclick="doDeleteProfile()">Delete profile</button>
      </div>
    </div>
  `);
  setTimeout(() => document.getElementById('del-confirm')?.focus(), 50);
};
window.doDeleteProfile = function () {
  const v = (document.getElementById('del-confirm')?.value || '').trim().toLowerCase();
  if (v !== 'delete') { showToast('Type "delete" to confirm', true); return; }
  if (Object.keys(state.profiles || {}).length <= 1) {
    // Reset to a fresh default profile
    const fresh = defaultProfile?.() || { id: uid(), name: 'Player', rounds: [], friends: [], rivalries: [], settings: {} };
    state.profiles = { [fresh.id]: fresh };
    state.activeProfileId = fresh.id;
  } else {
    delete state.profiles[state.activeProfileId];
    state.activeProfileId = Object.keys(state.profiles)[0];
  }
  refreshProfileAliases?.();
  saveState();
  closeModal();
  showToast('Profile deleted');
  renderHeader?.();
  activateTab('dashboard');
};

/* Initial profile-setup wizard — shown after first sign-in to complete the basics */
window.maybeShowProfileSetup = function () {
  if (window._frInRecovery) return;   // don't replace the "set new password" recovery modal
  const p = activeProfile();
  if (!p) return;
  const needsSetup = (!p.name || p.name === 'Player' || p.name === 'You' || p.name === 'Profile') || !p.homeClub;
  const key = 'fgl_setup_done_' + p.id;
  if (!needsSetup || localStorage.getItem(key)) return;
  // Build a list of course names for suggest
  const coursesList = (state.courses || []).map(c => c.name).slice(0, 30);
  const datalist = coursesList.map(n => `<option value="${n.replace(/"/g,'&quot;')}">`).join('');
  openModal(`
    <div style="text-align:center; padding:4px 0 0">
      <div class="section-eyebrow" style="margin-bottom:6px">ONE QUICK STEP</div>
      <h2 style="margin:2px 0 8px">Set up your profile</h2>
      <p style="color:var(--muted); font-size:13px; max-width:340px; margin:0 auto 16px">Just three things, then we'll get out of your way.</p>
    </div>
    <label class="field" style="margin-bottom:10px"><span>Your name</span>
      <input id="ws-name" type="text" placeholder="Mathias" value="${p.name && p.name !== 'Player' ? p.name : ''}" autofocus>
    </label>
    <label class="field" style="margin-bottom:10px"><span>Home club <span style="color:var(--muted-2); font-weight:400">— optional, prefills new rounds</span></span>
      <input id="ws-home" type="text" placeholder="Oslo Golfklubb" list="ws-courses" value="${p.homeClub || ''}">
      <datalist id="ws-courses">${datalist}</datalist>
    </label>
    <label class="field" style="margin-bottom:14px"><span>Handicap index <span style="color:var(--muted-2); font-weight:400">— your current index; we keep an unofficial WHS-style index updated as you log rounds</span></span>
      <input id="ws-hcp" type="number" step="0.1" placeholder="12.4" value="${p.settings?.manualHcp ?? ''}">
    </label>
    <button class="btn btn-gold" style="width:100%; padding:14px; font-weight:700" onclick="saveProfileSetup()">Save & start playing</button>
  `);
};
window.saveProfileSetup = function () {
  const p = activeProfile();
  if (!p) return closeModal();
  const name = (document.getElementById('ws-name')?.value || '').trim();
  const home = (document.getElementById('ws-home')?.value || '').trim();
  const mh = document.getElementById('ws-hcp')?.value;
  if (!name) { showToast('Add your name', true); document.getElementById('ws-name')?.focus(); return; }
  p.name = name;
  p.homeClub = home;
  if (!p.settings) p.settings = {};
  p.settings.manualHcp = (mh === '' || mh == null) ? null : parseFloat(mh);
  saveState();
  refreshProfileAliases?.();
  localStorage.setItem('fgl_setup_done_' + p.id, '1');
  closeModal();
  renderHeader?.();
  showToast(`Welcome, ${name}.`);
};

// Show welcome wizard on first sign-in if user has no profile data yet
  // (handled by maybeShowProfileSetup which runs after auth change)
  // Wire setup to fire after auth change to signed-in
if (window.fairwayCloud?.onAuthChange) {
  window.fairwayCloud.onAuthChange((session) => {
    if (session && !window._frInRecovery) setTimeout(() => { try { maybeShowProfileSetup(); } catch(e){} }, 400);
  });
}


